INSERT INTO vocab_examples (id, vocabulary_id, word, sentence_en, sentence_zh) VALUES
  ('e128faaa-ce9d-4c79-8f0d-3612b7a7ea55-ex1', 'e128faaa-ce9d-4c79-8f0d-3612b7a7ea55', 'eventually', 'Keep trying, and you will eventually succeed.', '坚持下去，你最终会成功的。'),
  ('e128faaa-ce9d-4c79-8f0d-3612b7a7ea55-ex2', 'e128faaa-ce9d-4c79-8f0d-3612b7a7ea55', 'eventually', 'The litigation was eventually resolved through a confidential settlement.', '这场诉讼最终通过保密和解得以解决。'),
  ('927f6f0f-07de-4011-a459-6bb7ec9aaa27-ex1', '927f6f0f-07de-4011-a459-6bb7ec9aaa27', 'forest', 'We went hiking in the forest.', '我们去森林里远足了。'),
  ('927f6f0f-07de-4011-a459-6bb7ec9aaa27-ex2', '927f6f0f-07de-4011-a459-6bb7ec9aaa27', 'forest', 'Satellite monitoring documents the accelerating loss of primary forest cover.', '卫星监测记录了原始森林覆盖正在加速消失。'),
  ('0d69e03f-677a-44ba-b872-c817c4fb5338-ex1', '0d69e03f-677a-44ba-b872-c817c4fb5338', 'video', 'She posted a funny video online.', '她在网上发布了一段有趣的视频。'),
  ('0d69e03f-677a-44ba-b872-c817c4fb5338-ex2', '0d69e03f-677a-44ba-b872-c817c4fb5338', 'video', 'The authenticated video footage proved decisive in corroborating the witness accounts.', '经鉴定的视频片段在印证证人陈述方面起到了决定性作用。'),
  ('b4d0e6bd-ca61-4071-b7aa-a058b385c798-ex1', 'b4d0e6bd-ca61-4071-b7aa-a058b385c798', 'global', 'English is a global language.', '英语是一门全球性语言。'),
  ('b4d0e6bd-ca61-4071-b7aa-a058b385c798-ex2', 'b4d0e6bd-ca61-4071-b7aa-a058b385c798', 'global', 'Global coordination remains indispensable for addressing transboundary environmental harms.', '应对跨境环境损害，全球协调仍然不可或缺。'),
  ('06f57deb-d3f6-49f2-a95d-05a298c35dff-ex1', '06f57deb-d3f6-49f2-a95d-05a298c35dff', 'Senate', 'The Senate will vote on the bill today.', '参议院今天将对该法案进行表决。'),
  ('06f57deb-d3f6-49f2-a95d-05a298c35dff-ex2', '06f57deb-d3f6-49f2-a95d-05a298c35dff', 'Senate', 'The Senate exercises its advice-and-consent prerogative over judicial nominations.', '参议院对司法提名行使其建议与同意的特权。'),
  ('5895a490-9f99-4dfe-afbe-a81f52bc54e2-ex1', '5895a490-9f99-4dfe-afbe-a81f52bc54e2', 'reform', 'The school needs reform in many areas.', '这所学校在很多方面需要改革。'),
  ('5895a490-9f99-4dfe-afbe-a81f52bc54e2-ex2', '5895a490-9f99-4dfe-afbe-a81f52bc54e2', 'reform', 'Structural reform of the pension system can no longer be responsibly deferred.', '养老金体系的结构性改革已不能再负责任地拖延下去。'),
  ('0638dcd4-4395-4547-bfbb-21d438bc3c8e-ex1', '0638dcd4-4395-4547-bfbb-21d438bc3c8e', 'access', 'Do you have access to the internet?', '你能上网吗？'),
  ('0638dcd4-4395-4547-bfbb-21d438bc3c8e-ex2', '0638dcd4-4395-4547-bfbb-21d438bc3c8e', 'access', 'The directive guarantees equitable access to essential services regardless of income.', '该指令保障不分收入水平公平获得基本服务。'),
  ('c0b31fe8-fc6f-4a39-abdb-8ecf43d1877d-ex1', 'c0b31fe8-fc6f-4a39-abdb-8ecf43d1877d', 'restaurant', 'We tried a new restaurant last night.', '我们昨晚去了一家新餐厅。'),
  ('c0b31fe8-fc6f-4a39-abdb-8ecf43d1877d-ex2', 'c0b31fe8-fc6f-4a39-abdb-8ecf43d1877d', 'restaurant', 'The restaurant group entered administration after sustained losses across its portfolio.', '这家餐饮集团因旗下业务持续亏损而进入破产管理程序。'),
  ('d8653556-bd72-4632-b414-2979648ccbda-ex1', 'd8653556-bd72-4632-b414-2979648ccbda', 'judge', 'Don''t judge a book by its cover.', '不要以貌取人。'),
  ('d8653556-bd72-4632-b414-2979648ccbda-ex2', 'd8653556-bd72-4632-b414-2979648ccbda', 'judge', 'The presiding judge excluded the testimony on grounds of demonstrable bias.', '主审法官以存在明显偏见为由排除了该证词。'),
  ('05bb8cad-40ce-4b07-a1d6-952c8caf932c-ex1', '05bb8cad-40ce-4b07-a1d6-952c8caf932c', 'publish', 'She will publish her first book next year.', '她明年将出版自己的第一本书。'),
  ('05bb8cad-40ce-4b07-a1d6-952c8caf932c-ex2', '05bb8cad-40ce-4b07-a1d6-952c8caf932c', 'publish', 'The agency is statutorily obliged to publish the findings of every formal investigation.', '该机构负有公布每项正式调查结果的法定义务。'),
  ('f37c958e-8991-4962-a60b-784af4155d50-ex1', 'f37c958e-8991-4962-a60b-784af4155d50', 'relation', 'The two events have no relation to each other.', '这两件事彼此没有关系。'),
  ('f37c958e-8991-4962-a60b-784af4155d50-ex2', 'f37c958e-8991-4962-a60b-784af4155d50', 'relation', 'Diplomatic relations were restored following two decades of formal estrangement.', '在二十年的正式疏远之后，两国恢复了外交关系。'),
  ('30e13d8c-6bc5-421c-9b3d-bf6215686ea5-ex1', '30e13d8c-6bc5-421c-9b3d-bf6215686ea5', 'release', 'The band will release a new album soon.', '乐队很快会发行新专辑。'),
  ('30e13d8c-6bc5-421c-9b3d-bf6215686ea5-ex2', '30e13d8c-6bc5-421c-9b3d-bf6215686ea5', 'release', 'The court ordered the release of documents previously withheld on security grounds.', '法院下令公开此前以安全为由扣留的文件。'),
  ('da95f598-dd56-4292-a143-0307b5fcb75b-ex1', 'da95f598-dd56-4292-a143-0307b5fcb75b', 'bird', 'A bird is singing outside my window.', '一只鸟在我窗外鸣叫。'),
  ('da95f598-dd56-4292-a143-0307b5fcb75b-ex2', 'da95f598-dd56-4292-a143-0307b5fcb75b', 'bird', 'Migratory bird populations have declined sharply as wetland habitats disappear.', '随着湿地栖息地消失，候鸟数量急剧下降。'),
  ('4d65c9c0-9225-4798-9bcf-3f4204c45ccb-ex1', '4d65c9c0-9225-4798-9bcf-3f4204c45ccb', 'opinion', 'In my opinion, the movie was great.', '在我看来，这部电影很棒。'),
  ('4d65c9c0-9225-4798-9bcf-3f4204c45ccb-ex2', '4d65c9c0-9225-4798-9bcf-3f4204c45ccb', 'opinion', 'The court''s majority opinion articulates a narrower construction of the statute.', '法院的多数意见对该法规作出了更狭义的解释。'),
  ('969ca627-5e62-45eb-91e0-82df1d8a4924-ex1', '969ca627-5e62-45eb-91e0-82df1d8a4924', 'credit', 'I paid for the TV on credit.', '我分期付款买了这台电视。'),
  ('969ca627-5e62-45eb-91e0-82df1d8a4924-ex2', '969ca627-5e62-45eb-91e0-82df1d8a4924', 'credit', 'Tightening credit conditions have constrained investment across the small-business sector.', '信贷条件收紧抑制了整个小企业部门的投资。'),
  ('cee73416-4333-4ae9-8fc6-86e83651005b-ex1', 'cee73416-4333-4ae9-8fc6-86e83651005b', 'critical', 'The patient is in critical condition.', '病人情况危急。'),
  ('cee73416-4333-4ae9-8fc6-86e83651005b-ex2', 'cee73416-4333-4ae9-8fc6-86e83651005b', 'critical', 'Independent journalism performs a critical function in democratic accountability.', '独立新闻业在民主问责中发挥着关键作用。'),
  ('c1363b9b-12b2-4513-9a9d-0523103cecb2-ex1', 'c1363b9b-12b2-4513-9a9d-0523103cecb2', 'corner', 'The cafe is on the corner of the street.', '咖啡馆在街角。'),
  ('c1363b9b-12b2-4513-9a9d-0523103cecb2-ex2', 'c1363b9b-12b2-4513-9a9d-0523103cecb2', 'corner', 'The settlement reached every corner of the affected market, including overseas claimants.', '和解覆盖了受影响市场的每个角落，包括海外索赔人。'),
  ('06046acf-27e9-4b9e-865f-5818a47d9b04-ex1', '06046acf-27e9-4b9e-865f-5818a47d9b04', 'concerned', 'I am concerned about your health.', '我担心你的健康。'),
  ('06046acf-27e9-4b9e-865f-5818a47d9b04-ex2', '06046acf-27e9-4b9e-865f-5818a47d9b04', 'concerned', 'All concerned parties were afforded an opportunity to submit written representations.', '所有相关方都获得了提交书面陈述的机会。'),
  ('8f9080b3-cc0a-41cd-aed1-98256bf2adb4-ex1', '8f9080b3-cc0a-41cd-aed1-98256bf2adb4', 'recall', 'I can''t recall his name.', '我想不起他的名字了。'),
  ('8f9080b3-cc0a-41cd-aed1-98256bf2adb4-ex2', '8f9080b3-cc0a-41cd-aed1-98256bf2adb4', 'recall', 'The manufacturer issued a global recall after regulators documented the defect.', '在监管机构证实该缺陷后，制造商发布了全球召回。'),
  ('07067914-1438-45ab-8561-d897a593024e-ex1', '07067914-1438-45ab-8561-d897a593024e', 'version', 'This is the latest version of the app.', '这是该应用的最新版本。'),
  ('07067914-1438-45ab-8561-d897a593024e-ex2', '07067914-1438-45ab-8561-d897a593024e', 'version', 'The ratified version differs materially from the draft circulated during consultation.', '批准的版本与磋商期间分发的草案存在重大差异。'),
  ('43fa6184-801b-47f3-9803-5b44f9d83bd0-ex1', '43fa6184-801b-47f3-9803-5b44f9d83bd0', 'stare', 'It is rude to stare at people.', '盯着别人看是不礼貌的。'),
  ('43fa6184-801b-47f3-9803-5b44f9d83bd0-ex2', '43fa6184-801b-47f3-9803-5b44f9d83bd0', 'stare', 'The negotiators could only stare at the figures that rendered their position untenable.', '谈判代表只能呆望着那些使其立场难以为继的数字。'),
  ('d209d341-46a6-450a-a0a5-4bdf316e6ce1-ex1', 'd209d341-46a6-450a-a0a5-4bdf316e6ce1', 'safety', 'Always wear a helmet for safety.', '为了安全，请始终佩戴头盔。'),
  ('d209d341-46a6-450a-a0a5-4bdf316e6ce1-ex2', 'd209d341-46a6-450a-a0a5-4bdf316e6ce1', 'safety', 'The inquiry attributed the disaster to a sustained erosion of the safety culture.', '调查将这场灾难归因于安全文化的持续滑坡。'),
  ('59451192-a3ed-4668-8788-2e66d6e8fa0b-ex1', '59451192-a3ed-4668-8788-2e66d6e8fa0b', 'effective', 'This medicine is very effective.', '这种药非常有效。'),
  ('59451192-a3ed-4668-8788-2e66d6e8fa0b-ex2', '59451192-a3ed-4668-8788-2e66d6e8fa0b', 'effective', 'The amendments become effective upon publication in the official gazette.', '修正案自官方公报刊布之日起生效。'),
  ('5a0d32c0-1d16-40d9-9bc3-ea758e5ce243-ex1', '5a0d32c0-1d16-40d9-9bc3-ea758e5ce243', 'neighborhood', 'We live in a quiet neighborhood.', '我们住在一个安静的社区。'),
  ('5a0d32c0-1d16-40d9-9bc3-ea758e5ce243-ex2', '5a0d32c0-1d16-40d9-9bc3-ea758e5ce243', 'neighborhood', 'The redevelopment displaced long-standing residents from the historic neighborhood.', '重建工程使老居民迁离了这片历史街区。'),
  ('95cf3940-ffaa-49d1-9972-f1cacdc2d683-ex1', '95cf3940-ffaa-49d1-9972-f1cacdc2d683', 'original', 'The original painting is in the museum.', '原画收藏在博物馆里。'),
  ('95cf3940-ffaa-49d1-9972-f1cacdc2d683-ex2', '95cf3940-ffaa-49d1-9972-f1cacdc2d683', 'original', 'The court reinstated the original award, finding the modification procedurally defective.', '法院认定修改在程序上有缺陷，恢复了原裁决。'),
  ('17ff5802-5a1c-40b6-82aa-dee6fb44564d-ex1', '17ff5802-5a1c-40b6-82aa-dee6fb44564d', 'troop', 'The troops returned home last month.', '部队上个月回国了。'),
  ('17ff5802-5a1c-40b6-82aa-dee6fb44564d-ex2', '17ff5802-5a1c-40b6-82aa-dee6fb44564d', 'troop', 'The resolution authorizes the deployment of additional troops under a strictly defined mandate.', '该决议授权在严格界定的授权范围内增派部队。'),
  ('c0f986c4-e520-40a0-8e01-ede3f21a5ff9-ex1', 'c0f986c4-e520-40a0-8e01-ede3f21a5ff9', 'income', 'His monthly income covers the rent.', '他的月收入够付房租。'),
  ('c0f986c4-e520-40a0-8e01-ede3f21a5ff9-ex2', 'c0f986c4-e520-40a0-8e01-ede3f21a5ff9', 'income', 'The reform shifts the tax burden progressively toward higher income brackets.', '这项改革使税负累进地向高收入阶层转移。'),
  ('787465fc-d20c-413e-a867-83970c818c20-ex1', '787465fc-d20c-413e-a867-83970c818c20', 'directly', 'The bus goes directly to the airport.', '这班公交车直达机场。'),
  ('787465fc-d20c-413e-a867-83970c818c20-ex2', '787465fc-d20c-413e-a867-83970c818c20', 'directly', 'The regulation applies directly in member states without further implementing legislation.', '该条例无需进一步的实施立法即在成员国直接适用。'),
  ('b5b1a91f-e701-4966-b522-1fdcb27210bc-ex1', 'b5b1a91f-e701-4966-b522-1fdcb27210bc', 'hurt', 'My feet hurt after the long walk.', '走了很长的路，我的脚很疼。'),
  ('b5b1a91f-e701-4966-b522-1fdcb27210bc-ex2', 'b5b1a91f-e701-4966-b522-1fdcb27210bc', 'hurt', 'The disclosure requirements were diluted in ways that ultimately hurt retail investors.', '披露要求被稀释，最终损害了散户投资者的利益。'),
  ('20f2265e-1e73-4424-a670-8e11a21e657a-ex1', '20f2265e-1e73-4424-a670-8e11a21e657a', 'species', 'The panda is an endangered species.', '熊猫是濒危物种。'),
  ('20f2265e-1e73-4424-a670-8e11a21e657a-ex2', '20f2265e-1e73-4424-a670-8e11a21e657a', 'species', 'The convention restricts trade in species threatened with extinction.', '该公约限制濒临灭绝物种的贸易。'),
  ('bd1fe4da-93c8-44da-bd46-9f35a4d00966-ex1', 'bd1fe4da-93c8-44da-bd46-9f35a4d00966', 'immediately', 'Call me immediately when you arrive.', '你一到就立刻给我打电话。'),
  ('bd1fe4da-93c8-44da-bd46-9f35a4d00966-ex2', 'bd1fe4da-93c8-44da-bd46-9f35a4d00966', 'immediately', 'The suspension takes effect immediately and remains in force pending appeal.', '停职令立即生效，并在上诉期间持续有效。'),
  ('d6344592-7aa7-4444-9c82-d59da34753e2-ex1', 'd6344592-7aa7-4444-9c82-d59da34753e2', 'track', 'The train left the track.', '火车脱轨了。'),
  ('d6344592-7aa7-4444-9c82-d59da34753e2-ex2', 'd6344592-7aa7-4444-9c82-d59da34753e2', 'track', 'The registry was established to track beneficial ownership across corporate structures.', '该登记系统的建立旨在追踪公司架构中的实际受益所有权。'),
  ('fe660b50-f06d-434b-b46d-303efe30949c-ex1', 'fe660b50-f06d-434b-b46d-303efe30949c', 'basic', 'I am learning basic cooking skills.', '我在学习基本的烹饪技能。'),
  ('fe660b50-f06d-434b-b46d-303efe30949c-ex2', 'fe660b50-f06d-434b-b46d-303efe30949c', 'basic', 'The charter guarantees basic procedural rights that no emergency measure may suspend.', '宪章保障的基本程序权利不得因任何紧急措施而中止。'),
  ('8fa7ac6c-7295-4476-93c0-cae9a2257007-ex1', '8fa7ac6c-7295-4476-93c0-cae9a2257007', 'strike', 'The workers went on strike for higher pay.', '工人们为争取加薪举行了罢工。'),
  ('8fa7ac6c-7295-4476-93c0-cae9a2257007-ex2', '8fa7ac6c-7295-4476-93c0-cae9a2257007', 'strike', 'The tribunal must strike a balance between transparency and legitimate confidentiality.', '法庭必须在透明度与正当保密之间取得平衡。'),
  ('b7522736-2af2-4b1c-9d9e-d1d8a5cbb709-ex1', 'b7522736-2af2-4b1c-9d9e-d1d8a5cbb709', 'sky', 'The sky is full of stars tonight.', '今晚满天繁星。'),
  ('b7522736-2af2-4b1c-9d9e-d1d8a5cbb709-ex2', 'b7522736-2af2-4b1c-9d9e-d1d8a5cbb709', 'sky', 'Housing costs have risen sky high in metropolitan areas with constrained supply.', '在供应受限的大都市地区，住房成本已涨至天价。'),
  ('ac9835cc-effe-4612-9da5-9d6694c5823e-ex1', 'ac9835cc-effe-4612-9da5-9d6694c5823e', 'freedom', 'The children enjoy the freedom of summer vacation.', '孩子们享受着暑假的自由。'),
  ('ac9835cc-effe-4612-9da5-9d6694c5823e-ex2', 'ac9835cc-effe-4612-9da5-9d6694c5823e', 'freedom', 'The covenant safeguards freedom of expression subject to narrowly construed limitations.', '该公约保障言论自由，仅受严格限定的例外约束。'),
  ('72bf55cf-ff3d-4fd7-b901-06c8e7598837-ex1', '72bf55cf-ff3d-4fd7-b901-06c8e7598837', 'absolutely', 'You are absolutely right.', '你完全正确。'),
  ('72bf55cf-ff3d-4fd7-b901-06c8e7598837-ex2', '72bf55cf-ff3d-4fd7-b901-06c8e7598837', 'absolutely', 'The privilege against self-incrimination is absolutely protected under the constitution.', '不自证其罪的特权受到宪法的绝对保护。'),
  ('b70120f5-12d1-4379-9d6d-7174ca2d228d-ex1', 'b70120f5-12d1-4379-9d6d-7174ca2d228d', 'plane', 'Our plane leaves at noon.', '我们的飞机中午起飞。'),
  ('b70120f5-12d1-4379-9d6d-7174ca2d228d-ex2', 'b70120f5-12d1-4379-9d6d-7174ca2d228d', 'plane', 'The dispute has shifted onto an entirely different plane involving sovereign immunity.', '这场争端已转移到一个涉及主权豁免的全新层面。'),
  ('edd70e6f-f6b0-4c3f-8c50-cf4674688076-ex1', 'edd70e6f-f6b0-4c3f-8c50-cf4674688076', 'nobody', 'Nobody knows the answer.', '没有人知道答案。'),
  ('edd70e6f-f6b0-4c3f-8c50-cf4674688076-ex2', 'edd70e6f-f6b0-4c3f-8c50-cf4674688076', 'nobody', 'Nobody within the organization escaped scrutiny during the forensic audit.', '在法证审计期间，组织内无人能逃过审查。'),
  ('449bbdf8-e7ca-4e4a-b5a9-9f92f80f3452-ex1', '449bbdf8-e7ca-4e4a-b5a9-9f92f80f3452', 'achieve', 'She worked hard to achieve her goal.', '她努力工作以实现目标。'),
  ('449bbdf8-e7ca-4e4a-b5a9-9f92f80f3452-ex2', '449bbdf8-e7ca-4e4a-b5a9-9f92f80f3452', 'achieve', 'The program failed to achieve its stated objectives despite substantial expenditure.', '尽管投入巨大，该项目仍未实现其既定目标。'),
  ('9715008d-5d5d-4be8-a1e1-f2904f05284e-ex1', '9715008d-5d5d-4be8-a1e1-f2904f05284e', 'object', 'What is that strange object in the sky?', '天上那个奇怪的物体是什么？'),
  ('9715008d-5d5d-4be8-a1e1-f2904f05284e-ex2', '9715008d-5d5d-4be8-a1e1-f2904f05284e', 'object', 'Counsel rose to object to the introduction of evidence obtained without warrant.', '律师起身反对采纳未经搜查令取得的证据。'),
  ('feb17fd9-0d5d-4cdc-a15b-57a8f0f6cb1d-ex1', 'feb17fd9-0d5d-4cdc-a15b-57a8f0f6cb1d', 'attitude', 'She has a positive attitude toward life.', '她对生活持积极态度。'),
