  ('9a164cc1-8fab-42d1-81da-3ee8e37f2b04-ex1', '9a164cc1-8fab-42d1-81da-3ee8e37f2b04', 'powerful', 'The car has a powerful engine.', '这辆车的发动机动力强劲。'),
