  ('fd9b4f25-8183-4b7a-af9b-a97b0b9a9a4d-ex1', 'fd9b4f25-8183-4b7a-af9b-a97b0b9a9a4d', 'encourage', 'My parents encourage me to read more.', '父母鼓励我多读书。'),
