  ('8d74052c-f149-463f-ba58-83fa1d652fd7-ex1', '8d74052c-f149-463f-ba58-83fa1d652fd7', 'AM', 'The flight leaves at 7 AM.', '航班早上七点起飞。'),
  ('8d74052c-f149-463f-ba58-83fa1d652fd7-ex2', '8d74052c-f149-463f-ba58-83fa1d652fd7', 'AM', 'Trading opened at 9 AM to unprecedented volatility across all major indices.', '上午九点开盘时，各大指数均出现前所未有的波动。'),
  ('30e325d8-c3b3-487a-807c-30ef0910cc58-ex1', '30e325d8-c3b3-487a-807c-30ef0910cc58', 'weekend', 'What are your plans for the weekend?', '你周末有什么安排？'),
  ('30e325d8-c3b3-487a-807c-30ef0910cc58-ex2', '30e325d8-c3b3-487a-807c-30ef0910cc58', 'weekend', 'Negotiators worked through the weekend to finalize the terms before markets opened.', '谈判人员周末连续工作，赶在开市前敲定条款。'),
  ('4f3e0915-a92c-4819-8332-4cd41b1ea567-ex1', '4f3e0915-a92c-4819-8332-4cd41b1ea567', 'dozen', 'I bought a dozen eggs.', '我买了一打鸡蛋。'),
  ('4f3e0915-a92c-4819-8332-4cd41b1ea567-ex2', '4f3e0915-a92c-4819-8332-4cd41b1ea567', 'dozen', 'More than a dozen jurisdictions have enacted substantially equivalent legislation.', '已有十多个司法管辖区颁布了实质等效的立法。'),
  ('3575df5c-bfe8-48e0-8525-a292b01f36fb-ex1', '3575df5c-bfe8-48e0-8525-a292b01f36fb', 'possibility', 'There is a possibility of rain tomorrow.', '明天有可能下雨。'),
  ('3575df5c-bfe8-48e0-8525-a292b01f36fb-ex2', '3575df5c-bfe8-48e0-8525-a292b01f36fb', 'possibility', 'The committee refused to exclude the possibility of further enforcement measures.', '委员会拒绝排除采取进一步执法措施的可能性。'),
  ('f405b50f-5cb4-4239-9fdc-e9e4d97ee653-ex1', 'f405b50f-5cb4-4239-9fdc-e9e4d97ee653', 'insurance', 'Do you have travel insurance?', '你买旅行保险了吗？'),
  ('f405b50f-5cb4-4239-9fdc-e9e4d97ee653-ex2', 'f405b50f-5cb4-4239-9fdc-e9e4d97ee653', 'insurance', 'The insurance consortium disputed liability for losses attributable to the excluded perils.', '保险联合体对除外风险造成的损失拒绝承担赔付责任。'),
  ('fab570a7-f601-4245-9f1a-0cd15ba23445-ex1', 'fab570a7-f601-4245-9f1a-0cd15ba23445', 'department', 'She works in the sales department.', '她在销售部门工作。'),
  ('fab570a7-f601-4245-9f1a-0cd15ba23445-ex2', 'fab570a7-f601-4245-9f1a-0cd15ba23445', 'department', 'The department exceeded its statutory authority in promulgating the contested rule.', '该部门颁布争议规则的行为超出了其法定权限。'),
  ('51f2cf08-df85-411e-9b2a-7e28b997c51b-ex1', '51f2cf08-df85-411e-9b2a-7e28b997c51b', 'battle', 'The two teams fought a close battle.', '两支队伍打得难解难分。'),
  ('51f2cf08-df85-411e-9b2a-7e28b997c51b-ex2', '51f2cf08-df85-411e-9b2a-7e28b997c51b', 'battle', 'The legal battle over the estate spanned three jurisdictions and two decades.', '围绕这笔遗产的法律战横跨三个司法管辖区，持续了二十年。'),
  ('f9877bf1-ce18-44d5-982f-f3f5b2567af1-ex1', 'f9877bf1-ce18-44d5-982f-f3f5b2567af1', 'beginning', 'The beginning of the movie is slow.', '电影的开头节奏很慢。'),
  ('f9877bf1-ce18-44d5-982f-f3f5b2567af1-ex2', 'f9877bf1-ce18-44d5-982f-f3f5b2567af1', 'beginning', 'The reforms mark the beginning of a fundamental reordering of the regulatory landscape.', '这些改革标志着监管格局根本性重塑的开端。'),
  ('303f9a06-8263-45c9-987c-0074672279e2-ex1', '303f9a06-8263-45c9-987c-0074672279e2', 'date', 'What is the date today?', '今天几号？'),
  ('303f9a06-8263-45c9-987c-0074672279e2-ex2', '303f9a06-8263-45c9-987c-0074672279e2', 'date', 'The effective date of the regulation was deferred to permit orderly transition.', '为保障有序过渡，该法规的生效日期被推迟。'),
  ('8c8dbcfe-9be9-4314-8c82-5f316f74597d-ex1', '8c8dbcfe-9be9-4314-8c82-5f316f74597d', 'generally', 'I generally get up at seven.', '我一般七点起床。'),
  ('8c8dbcfe-9be9-4314-8c82-5f316f74597d-ex2', '8c8dbcfe-9be9-4314-8c82-5f316f74597d', 'generally', 'Courts have generally construed the exemption narrowly to preserve the statute''s purpose.', '法院通常对该豁免作狭义解释，以维护法规的立法目的。'),
  ('68d38bce-4e39-4c8b-884e-965cda18640a-ex1', '68d38bce-4e39-4c8b-884e-965cda18640a', 'African', 'We listened to African music at the festival.', '我们在音乐节上听了非洲音乐。'),
  ('68d38bce-4e39-4c8b-884e-965cda18640a-ex2', '68d38bce-4e39-4c8b-884e-965cda18640a', 'African', 'Several African states jointly proposed reforms to the global financing architecture.', '几个非洲国家联合提出了改革全球融资架构的方案。'),
  ('1d968d38-71be-4160-a9f7-0466d215fd08-ex1', '1d968d38-71be-4160-a9f7-0466d215fd08', 'sorry', 'I am sorry for being late.', '很抱歉我迟到了。'),
  ('1d968d38-71be-4160-a9f7-0466d215fd08-ex2', '1d968d38-71be-4160-a9f7-0466d215fd08', 'sorry', 'The chairman expressed himself sorry for failures that occurred under his stewardship.', '主席对其任内发生的失误表示歉意。'),
  ('9ced6792-e01e-4628-b6f4-2d0f922a9d4f-ex1', '9ced6792-e01e-4628-b6f4-2d0f922a9d4f', 'crisis', 'The company is going through a crisis.', '公司正在经历一场危机。'),
  ('9ced6792-e01e-4628-b6f4-2d0f922a9d4f-ex2', '9ced6792-e01e-4628-b6f4-2d0f922a9d4f', 'crisis', 'The crisis exposed the inadequacy of resolution frameworks for systemically important institutions.', '这场危机暴露了系统重要性机构处置框架的不足。'),
  ('e8d2cd0c-0fb0-4699-aebc-b1a641fba081-ex1', 'e8d2cd0c-0fb0-4699-aebc-b1a641fba081', 'complete', 'Did you complete your homework?', '你完成作业了吗？'),
  ('e8d2cd0c-0fb0-4699-aebc-b1a641fba081-ex2', 'e8d2cd0c-0fb0-4699-aebc-b1a641fba081', 'complete', 'The acquisition cannot complete until every condition precedent has been satisfied.', '在所有先决条件满足之前，收购无法完成交割。'),
  ('8c86dd8d-f295-46fa-ad8c-15f66e95fbfd-ex1', '8c86dd8d-f295-46fa-ad8c-15f66e95fbfd', 'fan', 'Turn on the fan; it is hot in here.', '开下风扇，这里太热了。'),
  ('8c86dd8d-f295-46fa-ad8c-15f66e95fbfd-ex2', '8c86dd8d-f295-46fa-ad8c-15f66e95fbfd', 'fan', 'The franchise cultivated a global fan base through sustained digital engagement.', '该品牌通过持续的数字互动培育了全球粉丝群体。'),
  ('65cdcb57-b405-4b12-9294-ed40db5afd31-ex1', '65cdcb57-b405-4b12-9294-ed40db5afd31', 'stick', 'The dog loves to chase the stick.', '这只狗喜欢追树枝。'),
  ('65cdcb57-b405-4b12-9294-ed40db5afd31-ex2', '65cdcb57-b405-4b12-9294-ed40db5afd31', 'stick', 'The board resolved to stick to the agreed timetable despite mounting external pressure.', '尽管外部压力不断加大，董事会仍决定坚持既定时间表。'),
  ('5ab8ebd3-7df4-4262-a3fe-b7909970bb67-ex1', '5ab8ebd3-7df4-4262-a3fe-b7909970bb67', 'define', 'Can you define this word?', '你能给这个词下个定义吗？'),
  ('5ab8ebd3-7df4-4262-a3fe-b7909970bb67-ex2', '5ab8ebd3-7df4-4262-a3fe-b7909970bb67', 'define', 'The statute fails to define the operative terms with sufficient precision.', '该法规未能足够精确地界定关键术语。'),
  ('a9de4d44-15d2-409a-b070-bc2937031477-ex1', 'a9de4d44-15d2-409a-b070-bc2937031477', 'easily', 'She easily won the race.', '她轻松赢得了比赛。'),
  ('a9de4d44-15d2-409a-b070-bc2937031477-ex2', 'a9de4d44-15d2-409a-b070-bc2937031477', 'easily', 'Sophisticated structures can easily obscure the ultimate beneficiaries of transactions.', '复杂的架构很容易掩盖交易的最终受益人。'),
  ('43eb8155-6256-4a6b-98bc-44fb25d3ec76-ex1', '43eb8155-6256-4a6b-98bc-44fb25d3ec76', 'hole', 'There is a hole in my sock.', '我的袜子上有个洞。'),
  ('43eb8155-6256-4a6b-98bc-44fb25d3ec76-ex2', '43eb8155-6256-4a6b-98bc-44fb25d3ec76', 'hole', 'The amendment closes a regulatory hole long exploited by offshore intermediaries.', '该修正案堵上了长期被离岸中介利用的监管漏洞。'),
  ('74fe1787-d04e-488f-b677-8a4ae81219fb-ex1', '74fe1787-d04e-488f-b677-8a4ae81219fb', 'element', 'Surprise is an important element of the story.', '悬念是这个故事的重要元素。'),
  ('74fe1787-d04e-488f-b677-8a4ae81219fb-ex2', '74fe1787-d04e-488f-b677-8a4ae81219fb', 'element', 'Intent constitutes an essential element of the offense as statutorily defined.', '按照法定定义，故意是该罪行的必要构成要件。'),
  ('7aac87d1-f69f-4d32-be7b-f744f99b35bf-ex1', '7aac87d1-f69f-4d32-be7b-f744f99b35bf', 'vision', 'He wears glasses to correct his vision.', '他戴眼镜矫正视力。'),
  ('7aac87d1-f69f-4d32-be7b-f744f99b35bf-ex2', '7aac87d1-f69f-4d32-be7b-f744f99b35bf', 'vision', 'The charter articulates a vision of regional integration grounded in shared institutions.', '宪章阐明了以共同制度为基础的区域一体化愿景。'),
  ('ac5e0752-024f-408b-bcbe-47fd7ef5066a-ex1', 'ac5e0752-024f-408b-bcbe-47fd7ef5066a', 'status', 'What is the status of my order?', '我的订单状态怎么样了？'),
  ('ac5e0752-024f-408b-bcbe-47fd7ef5066a-ex2', 'ac5e0752-024f-408b-bcbe-47fd7ef5066a', 'status', 'The tribunal will determine the legal status of the contested maritime features.', '法庭将认定争议海洋地物的法律地位。'),
  ('ab276e34-d89a-4a5a-969f-4e1a47427e2a-ex1', 'ab276e34-d89a-4a5a-969f-4e1a47427e2a', 'normal', 'Things are back to normal now.', '现在一切恢复正常了。'),
  ('ab276e34-d89a-4a5a-969f-4e1a47427e2a-ex2', 'ab276e34-d89a-4a5a-969f-4e1a47427e2a', 'normal', 'The indicators have returned to ranges considered normal by historical standards.', '各项指标已回到按历史标准衡量属于正常的区间。'),
  ('faa2b866-71fb-4aab-8c94-39a25e5ea277-ex1', 'faa2b866-71fb-4aab-8c94-39a25e5ea277', 'Chinese', 'We had Chinese food for dinner.', '我们晚饭吃了中餐。'),
  ('faa2b866-71fb-4aab-8c94-39a25e5ea277-ex2', 'faa2b866-71fb-4aab-8c94-39a25e5ea277', 'Chinese', 'Chinese manufacturers have ascended the value chain into advanced precision industries.', '中国制造商已沿价值链攀升至先进精密产业。'),
  ('e3cbeb5c-e6d4-4fb2-ba41-ff9d0a02aaf8-ex1', 'e3cbeb5c-e6d4-4fb2-ba41-ff9d0a02aaf8', 'ship', 'The ship sails at dawn.', '船在黎明时启航。'),
  ('e3cbeb5c-e6d4-4fb2-ba41-ff9d0a02aaf8-ex2', 'e3cbeb5c-e6d4-4fb2-ba41-ff9d0a02aaf8', 'ship', 'The convention obliges flag states to ensure that every ship meets prescribed safety standards.', '该公约要求船旗国确保每艘船舶符合规定的安全标准。'),
  ('9d429f68-10ff-459e-b31c-712346df1084-ex1', '9d429f68-10ff-459e-b31c-712346df1084', 'solution', 'We found a simple solution to the problem.', '我们找到了解决这个问题的简单办法。'),
  ('9d429f68-10ff-459e-b31c-712346df1084-ex2', '9d429f68-10ff-459e-b31c-712346df1084', 'solution', 'Any durable solution must address the structural causes rather than the symptoms.', '任何持久的解决方案都必须针对结构性根源，而非表面症状。'),
  ('e70c4937-019e-4451-a1e3-cb102c1c4f40-ex1', 'e70c4937-019e-4451-a1e3-cb102c1c4f40', 'stone', 'The path is made of stone.', '这条小路是石头铺的。'),
  ('e70c4937-019e-4451-a1e3-cb102c1c4f40-ex2', 'e70c4937-019e-4451-a1e3-cb102c1c4f40', 'stone', 'The ruling leaves no stone unturned in dismantling the contested regulatory edifice.', '这一裁决不遗余力地拆解了备受争议的监管体系。'),
  ('b5be9f47-9a91-4c9f-92c7-b05b1c9300e7-ex1', 'b5be9f47-9a91-4c9f-92c7-b05b1c9300e7', 'slowly', 'Please speak more slowly.', '请说慢一点。'),
  ('b5be9f47-9a91-4c9f-92c7-b05b1c9300e7-ex2', 'b5be9f47-9a91-4c9f-92c7-b05b1c9300e7', 'slowly', 'Institutional reform proceeds slowly, constrained by entrenched interests at every turn.', '机构改革进展缓慢，处处受到既得利益的掣肘。'),
  ('93b66f3b-7efd-475c-b0e5-12922e19f371-ex1', '93b66f3b-7efd-475c-b0e5-12922e19f371', 'scale', 'Weigh the flour on the scale.', '用秤称一下面粉。'),
  ('93b66f3b-7efd-475c-b0e5-12922e19f371-ex2', '93b66f3b-7efd-475c-b0e5-12922e19f371', 'scale', 'Fraud on this scale could not have occurred without sustained internal collusion.', '如此规模的舞弊若无持续的内部串通是不可能发生的。'),
  ('14511ed2-dc6e-4225-af6a-85e79f1208a0-ex1', '14511ed2-dc6e-4225-af6a-85e79f1208a0', 'university', 'She studies physics at the university.', '她在大学学习物理。'),
  ('14511ed2-dc6e-4225-af6a-85e79f1208a0-ex2', '14511ed2-dc6e-4225-af6a-85e79f1208a0', 'university', 'The university established an independent chair endowed for research integrity.', '这所大学设立了一个专为科研诚信而设的独立教席。'),
  ('4dccef27-5ecb-4b17-9401-2052dd254516-ex1', '4dccef27-5ecb-4b17-9401-2052dd254516', 'introduce', 'Let me introduce my friend Tom.', '让我介绍一下我的朋友汤姆。'),
  ('4dccef27-5ecb-4b17-9401-2052dd254516-ex2', '4dccef27-5ecb-4b17-9401-2052dd254516', 'introduce', 'The government plans to introduce legislation mandating algorithmic transparency.', '政府计划提出强制算法透明的立法。'),
  ('d91c2fae-7116-4ac6-9733-1006454ccbb4-ex1', 'd91c2fae-7116-4ac6-9733-1006454ccbb4', 'driver', 'The bus driver waited for us.', '公交车司机等了我们。'),
  ('d91c2fae-7116-4ac6-9733-1006454ccbb4-ex2', 'd91c2fae-7116-4ac6-9733-1006454ccbb4', 'driver', 'Demographic change has become the principal driver of long-term fiscal pressure.', '人口结构变化已成为长期财政压力的主要驱动因素。'),
  ('dc673b9f-f4fa-4ae1-a013-5c152bf3f422-ex1', 'dc673b9f-f4fa-4ae1-a013-5c152bf3f422', 'attempt', 'This is my first attempt at baking bread.', '这是我第一次尝试烤面包。'),
  ('dc673b9f-f4fa-4ae1-a013-5c152bf3f422-ex2', 'dc673b9f-f4fa-4ae1-a013-5c152bf3f422', 'attempt', 'The takeover attempt collapsed when regulators signaled their intention to intervene.', '当监管机构表明干预意图后，这次收购企图宣告失败。'),
  ('e62107bf-fe9d-461b-9968-668ed75b1c93-ex1', 'e62107bf-fe9d-461b-9968-668ed75b1c93', 'park', 'We had a picnic in the park.', '我们在公园野餐了。'),
  ('e62107bf-fe9d-461b-9968-668ed75b1c93-ex2', 'e62107bf-fe9d-461b-9968-668ed75b1c93', 'park', 'The industrial park was rezoned following protracted environmental litigation.', '经过旷日持久的环境诉讼，这个工业园区被重新规划。'),
  ('817629e2-e002-43eb-af89-bef5cd4aabde-ex1', '817629e2-e002-43eb-af89-bef5cd4aabde', 'spot', 'This is a great spot for fishing.', '这是个钓鱼的好地方。'),
  ('817629e2-e002-43eb-af89-bef5cd4aabde-ex2', '817629e2-e002-43eb-af89-bef5cd4aabde', 'spot', 'The audit was designed to spot irregularities before they matured into systemic risks.', '这项审计旨在赶在违规演变为系统性风险之前将其发现。'),
  ('13f78281-9702-4868-945c-720c631fa694-ex1', '13f78281-9702-4868-945c-720c631fa694', 'lack', 'The plant died from lack of water.', '这株植物因缺水而枯死。'),
  ('13f78281-9702-4868-945c-720c631fa694-ex2', '13f78281-9702-4868-945c-720c631fa694', 'lack', 'The prosecution foundered on a lack of admissible documentary evidence.', '由于缺乏可采纳的书面证据，控方的指控未能成立。'),
  ('d91a1006-c465-43af-8f9d-086c8fce944f-ex1', 'd91a1006-c465-43af-8f9d-086c8fce944f', 'ice', 'Would you like ice in your drink?', '你的饮料要加冰吗？'),
  ('d91a1006-c465-43af-8f9d-086c8fce944f-ex2', 'd91a1006-c465-43af-8f9d-086c8fce944f', 'ice', 'Accelerating ice loss from polar sheets is redrawing projections of sea-level rise.', '极地冰盖的加速消融正在改写海平面上升的预测。'),
  ('299d1295-34b5-4578-8d29-b25fe5691ada-ex1', '299d1295-34b5-4578-8d29-b25fe5691ada', 'boat', 'We rented a boat on the lake.', '我们在湖上租了一条船。'),
  ('299d1295-34b5-4578-8d29-b25fe5691ada-ex2', '299d1295-34b5-4578-8d29-b25fe5691ada', 'boat', 'Interception of migrant boats raises unresolved questions under maritime law.', '拦截移民船只引发了海洋法上悬而未决的问题。'),
  ('c3b92bf6-c2a3-4fdd-937b-99c0c9ecde68-ex1', 'c3b92bf6-c2a3-4fdd-937b-99c0c9ecde68', 'drink', 'Drink more water in summer.', '夏天要多喝水。'),
  ('c3b92bf6-c2a3-4fdd-937b-99c0c9ecde68-ex2', 'c3b92bf6-c2a3-4fdd-937b-99c0c9ecde68', 'drink', 'The directive restricts the marketing of sugary drinks to minors.', '该指令限制向未成年人营销含糖饮料。'),
  ('22dde0b5-11ea-4bd5-9c4f-9db28d870aaf-ex1', '22dde0b5-11ea-4bd5-9c4f-9db28d870aaf', 'sun', 'The sun is shining brightly today.', '今天阳光灿烂。'),
  ('22dde0b5-11ea-4bd5-9c4f-9db28d870aaf-ex2', '22dde0b5-11ea-4bd5-9c4f-9db28d870aaf', 'sun', 'Utility-scale solar arrays convert the sun''s radiation at steadily improving efficiencies.', '大型太阳能电站正以不断提高的效率转化太阳辐射。'),
  ('556a33ff-aafb-4477-a58d-e0fe709d8838-ex1', '556a33ff-aafb-4477-a58d-e0fe709d8838', 'distance', 'The school is within walking distance.', '学校步行就能到。'),
  ('556a33ff-aafb-4477-a58d-e0fe709d8838-ex2', '556a33ff-aafb-4477-a58d-e0fe709d8838', 'distance', 'The agency sought to distance itself from the conclusions of its own commissioned report.', '该机构试图与自己委托撰写的报告结论保持距离。'),
  ('cb27a8ab-d252-4232-9aff-e2d37077ac5a-ex1', 'cb27a8ab-d252-4232-9aff-e2d37077ac5a', 'wood', 'The table is made of wood.', '这张桌子是木制的。'),
  ('cb27a8ab-d252-4232-9aff-e2d37077ac5a-ex2', 'cb27a8ab-d252-4232-9aff-e2d37077ac5a', 'wood', 'Certified sustainable wood now commands a substantial premium in export markets.', '经认证的可持续木材如今在出口市场享有可观的溢价。'),
  ('139f6c5a-f19a-429a-8cc9-5e139e93da9b-ex1', '139f6c5a-f19a-429a-8cc9-5e139e93da9b', 'handle', 'The handle of the cup is broken.', '杯子的把手断了。'),
  ('139f6c5a-f19a-429a-8cc9-5e139e93da9b-ex2', '139f6c5a-f19a-429a-8cc9-5e139e93da9b', 'handle', 'The tribunal lacks capacity to handle the volume of claims now pending before it.', '该法庭已无力处理目前积压的大量索赔案件。'),
  ('a2f73869-0cf5-47a2-b339-8bd1b8253f65-ex1', 'a2f73869-0cf5-47a2-b339-8bd1b8253f65', 'truck', 'The truck delivered our new furniture.', '卡车送来了我们的新家具。'),
  ('a2f73869-0cf5-47a2-b339-8bd1b8253f65-ex2', 'a2f73869-0cf5-47a2-b339-8bd1b8253f65', 'truck', 'Autonomous truck corridors are being piloted along designated interstate routes.', '自动驾驶卡车专用通道正在指定的州际线路上试点。'),
  ('58ce9420-2b8d-4a51-89ef-bc9c0ee307d7-ex1', '58ce9420-2b8d-4a51-89ef-bc9c0ee307d7', 'mountain', 'We climbed the mountain last summer.', '我们去年夏天爬了那座山。'),
  ('58ce9420-2b8d-4a51-89ef-bc9c0ee307d7-ex2', '58ce9420-2b8d-4a51-89ef-bc9c0ee307d7', 'mountain', 'The agency confronts a mountain of unprocessed claims inherited from its predecessor.', '该机构面临着从前身机构遗留下来的堆积如山的未处理索赔。'),
  ('f7c40912-4edd-485f-b032-2605c6765c90-ex1', 'f7c40912-4edd-485f-b032-2605c6765c90', 'survey', 'Please fill out this short survey.', '请填写这份简短的问卷。'),
  ('f7c40912-4edd-485f-b032-2605c6765c90-ex2', 'f7c40912-4edd-485f-b032-2605c6765c90', 'survey', 'The longitudinal survey tracks household welfare across successive policy regimes.', '这项纵向调查追踪了历次政策周期下的家庭福利状况。'),
  ('8b05597e-bffd-4ec0-ba96-879849207597-ex1', '8b05597e-bffd-4ec0-ba96-879849207597', 'supposed', 'You are supposed to be in bed.', '你这会儿应该在睡觉。'),
  ('8b05597e-bffd-4ec0-ba96-879849207597-ex2', '8b05597e-bffd-4ec0-ba96-879849207597', 'supposed', 'The safeguards that were supposed to prevent such failures proved entirely illusory.', '本应防止此类失误的保障措施被证明完全形同虚设。'),
  ('d970a7be-4c0d-4506-81b3-b009e074d5fd-ex1', 'd970a7be-4c0d-4506-81b3-b009e074d5fd', 'tradition', 'It is our family tradition to cook together.', '一起做饭是我们家的传统。'),
  ('d970a7be-4c0d-4506-81b3-b009e074d5fd-ex2', 'd970a7be-4c0d-4506-81b3-b009e074d5fd', 'tradition', 'The court drew upon a long tradition of construing penal statutes narrowly.', '法院遵循了对刑事法规作狭义解释的悠久传统。'),
  ('7a3f7fd0-cd66-49bf-8ed2-e263258c1169-ex1', '7a3f7fd0-cd66-49bf-8ed2-e263258c1169', 'winter', 'We go skiing every winter.', '我们每年冬天去滑雪。'),
  ('7a3f7fd0-cd66-49bf-8ed2-e263258c1169-ex2', '7a3f7fd0-cd66-49bf-8ed2-e263258c1169', 'winter', 'Energy regulators warned of supply constraints heading into the coming winter.', '能源监管机构警告，即将到来的冬季将面临供应紧张。'),
  ('85cfdbc5-5bca-40a6-9ebc-90ff222dfb4f-ex1', '85cfdbc5-5bca-40a6-9ebc-90ff222dfb4f', 'village', 'My grandparents live in a small village.', '我的祖父母住在一个小村庄里。'),
  ('85cfdbc5-5bca-40a6-9ebc-90ff222dfb4f-ex2', '85cfdbc5-5bca-40a6-9ebc-90ff222dfb4f', 'village', 'Electrification reached the last unconnected villages under the rural infrastructure program.', '在农村基础设施计划下，最后一批未通电的村庄实现了通电。'),
  ('1ba400fb-efc4-4a3d-bf9b-45717aca61df-ex1', '1ba400fb-efc4-4a3d-bf9b-45717aca61df', 'Soviet', 'He grew up in the Soviet era.', '他在苏联时代长大。'),
  ('1ba400fb-efc4-4a3d-bf9b-45717aca61df-ex2', '1ba400fb-efc4-4a3d-bf9b-45717aca61df', 'Soviet', 'Declassified Soviet archives have transformed scholarly understanding of the period.', '解密的苏联档案彻底改变了学界对那个时期的认识。'),
  ('26c9efee-fe93-419d-a5ff-96b0739a7511-ex1', '26c9efee-fe93-419d-a5ff-96b0739a7511', 'refuse', 'She refused my offer of help.', '她拒绝了我的帮助。'),
  ('26c9efee-fe93-419d-a5ff-96b0739a7511-ex2', '26c9efee-fe93-419d-a5ff-96b0739a7511', 'refuse', 'The witness may not refuse to testify absent a recognized claim of privilege.', '除非存在公认的特权主张，证人不得拒绝作证。'),
  ('728dfb2c-960a-4e38-b978-010a906c33d3-ex1', '728dfb2c-960a-4e38-b978-010a906c33d3', 'sales', 'Sales increased during the holiday.', '假期期间销售额增长了。'),
  ('728dfb2c-960a-4e38-b978-010a906c33d3-ex2', '728dfb2c-960a-4e38-b978-010a906c33d3', 'sales', 'The prospectus materially overstated projected sales across the core product lines.', '招股书严重夸大了核心产品线的预期销售额。'),
  ('3c483788-84c7-47b3-bb1f-d0db3dbcdcb3-ex1', '3c483788-84c7-47b3-bb1f-d0db3dbcdcb3', 'roll', 'Roll the dough into a ball.', '把面团揉成球状。'),
  ('3c483788-84c7-47b3-bb1f-d0db3dbcdcb3-ex2', '3c483788-84c7-47b3-bb1f-d0db3dbcdcb3', 'roll', 'The administration moved to roll back regulations enacted by its predecessor.', '本届政府着手撤销前任颁布的监管法规。'),
  ('c933ccb2-1f0b-4b3b-af8e-1575df50a4a4-ex1', 'c933ccb2-1f0b-4b3b-af8e-1575df50a4a4', 'communication', 'Good communication is important in a team.', '良好的沟通在团队中很重要。'),
  ('c933ccb2-1f0b-4b3b-af8e-1575df50a4a4-ex2', 'c933ccb2-1f0b-4b3b-af8e-1575df50a4a4', 'communication', 'Privileged communications between counsel and client are shielded from compelled disclosure.', '律师与客户之间的特权通信受到保护，免于强制披露。'),
  ('fe7f8cfd-2f04-4913-9bd0-ef6b3405d582-ex1', 'fe7f8cfd-2f04-4913-9bd0-ef6b3405d582', 'screen', 'My phone screen is cracked.', '我的手机屏幕裂了。'),
  ('fe7f8cfd-2f04-4913-9bd0-ef6b3405d582-ex2', 'fe7f8cfd-2f04-4913-9bd0-ef6b3405d582', 'screen', 'The agency will screen all inbound investment in designated strategic sectors.', '该机构将审查所有进入指定战略行业的投资。'),
  ('6967ff20-707d-4746-947e-fcfb26cbecde-ex1', '6967ff20-707d-4746-947e-fcfb26cbecde', 'gain', 'No pain, no gain.', '不劳无获。'),
  ('6967ff20-707d-4746-947e-fcfb26cbecde-ex2', '6967ff20-707d-4746-947e-fcfb26cbecde', 'gain', 'Realized capital gains are taxed at rates that vary with the holding period.', '已实现的资本利得按持有期限的不同适用差别税率。'),
  ('411a6b52-7e22-4802-9fae-87cf3b37d7c8-ex1', '411a6b52-7e22-4802-9fae-87cf3b37d7c8', 'resident', 'The residents complained about the noise.', '居民们投诉噪音问题。'),
  ('411a6b52-7e22-4802-9fae-87cf3b37d7c8-ex2', '411a6b52-7e22-4802-9fae-87cf3b37d7c8', 'resident', 'Every affected resident is entitled to relocation assistance at fair market value.', '每位受影响的居民都有权按公平市价获得搬迁补助。'),
  ('2f8ff2b4-444b-4545-aa20-2ef4bc960a75-ex1', '2f8ff2b4-444b-4545-aa20-2ef4bc960a75', 'hide', 'The kids love to play hide and seek.', '孩子们喜欢玩捉迷藏。'),
  ('2f8ff2b4-444b-4545-aa20-2ef4bc960a75-ex2', '2f8ff2b4-444b-4545-aa20-2ef4bc960a75', 'hide', 'Layered corporate structures were deployed to hide the ultimate beneficial owners.', '层层嵌套的公司架构被用来隐藏最终受益所有人。'),
  ('91b9b011-f56d-4280-89b3-9198f94396b8-ex1', '91b9b011-f56d-4280-89b3-9198f94396b8', 'gold', 'She wears a gold necklace.', '她戴着一条金项链。'),
  ('91b9b011-f56d-4280-89b3-9198f94396b8-ex2', '91b9b011-f56d-4280-89b3-9198f94396b8', 'gold', 'Central banks accumulated gold reserves as a hedge against currency volatility.', '各国央行增持黄金储备，以对冲货币波动风险。'),
  ('4c53f42d-295a-4a79-a1e7-6a9b0500b1b7-ex1', '4c53f42d-295a-4a79-a1e7-6a9b0500b1b7', 'club', 'I joined the school chess club.', '我加入了学校的国际象棋俱乐部。'),
  ('4c53f42d-295a-4a79-a1e7-6a9b0500b1b7-ex2', '4c53f42d-295a-4a79-a1e7-6a9b0500b1b7', 'club', 'The club''s governance was overhauled after findings of financial mismanagement.', '在财务管理不善的问题被查实后，该俱乐部的治理结构进行了彻底改革。'),
  ('830853ff-fdf5-4ff9-9849-cfee66fa85f0-ex1', '830853ff-fdf5-4ff9-9849-cfee66fa85f0', 'farm', 'My uncle has a small farm.', '我叔叔有一个小农场。'),
  ('830853ff-fdf5-4ff9-9849-cfee66fa85f0-ex2', '830853ff-fdf5-4ff9-9849-cfee66fa85f0', 'farm', 'Consolidation has concentrated farm ownership in progressively fewer corporate hands.', '兼并使农场所有权日益集中在少数企业手中。'),
  ('9905fe98-02b6-4370-ae3a-d4ee38736fce-ex1', '9905fe98-02b6-4370-ae3a-d4ee38736fce', 'potential', 'She has great potential as a singer.', '她很有歌唱天赋。'),
  ('9905fe98-02b6-4370-ae3a-d4ee38736fce-ex2', '9905fe98-02b6-4370-ae3a-d4ee38736fce', 'potential', 'The assessment identifies potential conflicts of interest requiring prospective disclosure.', '评估指出了需要事先披露的潜在利益冲突。'),
  ('e5b26900-03fb-4f46-b0d0-6bb3e2b8c707-ex1', 'e5b26900-03fb-4f46-b0d0-6bb3e2b8c707', 'European', 'We visited several European cities.', '我们游览了几座欧洲城市。'),
  ('e5b26900-03fb-4f46-b0d0-6bb3e2b8c707-ex2', 'e5b26900-03fb-4f46-b0d0-6bb3e2b8c707', 'European', 'European regulators have led the global convergence toward stricter data protection.', '欧洲监管机构引领了全球向更严格数据保护标准的趋同。'),
  ('b3d63ae0-b3ad-45eb-848f-f7f7947f1c61-ex1', 'b3d63ae0-b3ad-45eb-848f-f7f7947f1c61', 'presence', 'Your presence at the party made it special.', '你的到场让聚会变得特别。'),
  ('b3d63ae0-b3ad-45eb-848f-f7f7947f1c61-ex2', 'b3d63ae0-b3ad-45eb-848f-f7f7947f1c61', 'presence', 'The sustained military presence requires periodic reauthorization by the legislature.', '持续的军事存在需要立法机构定期重新授权。'),
  ('3e2b1340-648b-42bb-a0e3-e0a6249df09d-ex1', '3e2b1340-648b-42bb-a0e3-e0a6249df09d', 'independent', 'She is very independent for her age.', '就她的年龄来说，她非常独立。'),
  ('3e2b1340-648b-42bb-a0e3-e0a6249df09d-ex2', '3e2b1340-648b-42bb-a0e3-e0a6249df09d', 'independent', 'An independent monitor was appointed to oversee compliance with the consent decree.', '一名独立监督员受命监督和解令的执行情况。'),
  ('8723cd89-5ec2-4385-bf38-333840a36da2-ex1', '8723cd89-5ec2-4385-bf38-333840a36da2', 'district', 'We live in the school district.', '我们住在这个学区里。'),
  ('8723cd89-5ec2-4385-bf38-333840a36da2-ex2', '8723cd89-5ec2-4385-bf38-333840a36da2', 'district', 'The district court retained jurisdiction to enforce the terms of the settlement.', '地区法院保留了执行和解条款的管辖权。'),
  ('0230da94-ff32-471f-8c8b-bc6985303f30-ex1', '0230da94-ff32-471f-8c8b-bc6985303f30', 'shape', 'The cake is in the shape of a heart.', '蛋糕是心形的。'),
  ('0230da94-ff32-471f-8c8b-bc6985303f30-ex2', '0230da94-ff32-471f-8c8b-bc6985303f30', 'shape', 'Demographic forces will shape fiscal policy for decades to come.', '人口因素将在未来数十年塑造财政政策。'),
  ('8fc8a209-c002-4173-94fc-088a8cf610a2-ex1', '8fc8a209-c002-4173-94fc-088a8cf610a2', 'reader', 'She is an avid reader of mystery novels.', '她是悬疑小说的忠实读者。'),
  ('8fc8a209-c002-4173-94fc-088a8cf610a2-ex2', '8fc8a209-c002-4173-94fc-088a8cf610a2', 'reader', 'The disclosure must convey material risks comprehensibly to the ordinary reader.', '披露文件必须以普通读者能够理解的方式传达重大风险。'),
  ('73141435-62ef-488f-b48c-54529ce377f0-ex1', '73141435-62ef-488f-b48c-54529ce377f0', 'Ms', 'Ms Chen will see you now.', '陈女士现在可以见你了。'),
  ('73141435-62ef-488f-b48c-54529ce377f0-ex2', '73141435-62ef-488f-b48c-54529ce377f0', 'Ms', 'Ms Alvarez assumed the chair of the oversight committee upon her predecessor''s resignation.', '前任辞职后，阿尔瓦雷斯女士接任监督委员会主席。'),
  ('5c1f84af-342a-4671-8095-b21f96c24f8c-ex1', '5c1f84af-342a-4671-8095-b21f96c24f8c', 'contract', 'I signed a one-year contract.', '我签了一份一年期合同。'),
  ('5c1f84af-342a-4671-8095-b21f96c24f8c-ex2', '5c1f84af-342a-4671-8095-b21f96c24f8c', 'contract', 'The contract allocates consequential losses according to each party''s degree of fault.', '合同按各方过错程度分配间接损失。'),
  ('13a97aa2-b471-4dd9-afaf-c94acb6d21bd-ex1', '13a97aa2-b471-4dd9-afaf-c94acb6d21bd', 'crowd', 'A large crowd gathered in the square.', '广场上聚集了一大群人。'),
  ('13a97aa2-b471-4dd9-afaf-c94acb6d21bd-ex2', '13a97aa2-b471-4dd9-afaf-c94acb6d21bd', 'crowd', 'Officers were instructed to disperse the crowd using only proportionate means.', '警员奉命只能使用相称的手段疏散人群。'),
  ('710e1af2-1074-44dc-90d1-aa289a6ecce6-ex1', '710e1af2-1074-44dc-90d1-aa289a6ecce6', 'Christian', 'She comes from a Christian family.', '她来自一个基督教家庭。'),
  ('710e1af2-1074-44dc-90d1-aa289a6ecce6-ex2', '710e1af2-1074-44dc-90d1-aa289a6ecce6', 'Christian', 'The manuscript illuminates early Christian communities in the eastern Mediterranean.', '这份手稿揭示了地中海东部早期基督教社群的面貌。'),
  ('e6dc9b06-a34a-4ba4-b563-9001c95722ec-ex1', 'e6dc9b06-a34a-4ba4-b563-9001c95722ec', 'express', 'It is hard to express my thanks in words.', '我的感激之情难以言表。'),
  ('e6dc9b06-a34a-4ba4-b563-9001c95722ec-ex2', 'e6dc9b06-a34a-4ba4-b563-9001c95722ec', 'express', 'The statute requires express written consent before personal data may be transferred.', '该法规要求在转移个人数据前必须获得明示的书面同意。'),
  ('8f234ef0-2d1e-4b51-92a0-71fc528f73c0-ex1', '8f234ef0-2d1e-4b51-92a0-71fc528f73c0', 'apartment', 'They rent a small apartment downtown.', '他们在市中心租了一套小公寓。'),
  ('8f234ef0-2d1e-4b51-92a0-71fc528f73c0-ex2', '8f234ef0-2d1e-4b51-92a0-71fc528f73c0', 'apartment', 'The ordinance caps annual rent increases for regulated apartment units.', '该条例对受管制公寓单元的年租金涨幅设定了上限。'),
  ('d506e14b-f399-4b81-a3a4-7ce45f69d0e9-ex1', 'd506e14b-f399-4b81-a3a4-7ce45f69d0e9', 'willing', 'I am willing to help you move.', '我愿意帮你搬家。'),
  ('d506e14b-f399-4b81-a3a4-7ce45f69d0e9-ex2', 'd506e14b-f399-4b81-a3a4-7ce45f69d0e9', 'willing', 'Few institutions proved willing to absorb the regulatory risk the transaction entailed.', '事实证明，几乎没有机构愿意承担这笔交易所附带的监管风险。'),
  ('7132c9e0-d1ae-43f4-a154-6b11d4dd5a76-ex1', '7132c9e0-d1ae-43f4-a154-6b11d4dd5a76', 'strength', 'He doesn''t have the strength to lift it.', '他没有力气举起它。'),
  ('7132c9e0-d1ae-43f4-a154-6b11d4dd5a76-ex2', '7132c9e0-d1ae-43f4-a154-6b11d4dd5a76', 'strength', 'The currency''s persistent strength has eroded the competitiveness of export industries.', '本币持续走强削弱了出口产业的竞争力。'),
  ('d17c71dc-0c78-4140-9ac9-0b40de5c24b4-ex1', 'd17c71dc-0c78-4140-9ac9-0b40de5c24b4', 'previous', 'I liked the previous version better.', '我更喜欢之前的版本。'),
  ('d17c71dc-0c78-4140-9ac9-0b40de5c24b4-ex2', 'd17c71dc-0c78-4140-9ac9-0b40de5c24b4', 'previous', 'The ruling expressly overrules the previous line of authority on this question.', '该裁决明确推翻了此前关于这一问题的先例。'),
  ('27665dc3-12f7-4075-9f79-e443a9e10ed6-ex1', '27665dc3-12f7-4075-9f79-e443a9e10ed6', 'band', 'The band played until midnight.', '乐队一直演奏到午夜。'),
  ('27665dc3-12f7-4075-9f79-e443a9e10ed6-ex2', '27665dc3-12f7-4075-9f79-e443a9e10ed6', 'band', 'Income within the lowest band is exempted entirely from the new levy.', '最低档收入完全免征新税。'),
  ('de7afd8c-f88e-421c-953e-e591a529d654-ex1', 'de7afd8c-f88e-421c-953e-e591a529d654', 'obviously', 'Obviously, he forgot our meeting.', '很显然，他忘了我们的会面。'),
  ('de7afd8c-f88e-421c-953e-e591a529d654-ex2', 'de7afd8c-f88e-421c-953e-e591a529d654', 'obviously', 'The disclosed figures were obviously irreconcilable with the audited statements.', '披露的数字与经审计的报表明显无法对应。'),
  ('305371fd-7d10-4a4c-a420-216b1ee9b9d7-ex1', '305371fd-7d10-4a4c-a420-216b1ee9b9d7', 'horse', 'She rides her horse every morning.', '她每天早上骑马。'),
  ('305371fd-7d10-4a4c-a420-216b1ee9b9d7-ex2', '305371fd-7d10-4a4c-a420-216b1ee9b9d7', 'horse', 'The province''s horse breeding industry secured protected geographical designation.', '该省的马匹养殖业获得了地理标志保护认证。'),
  ('3da0a86c-d13c-40c5-b1fc-294716ccade3-ex1', '3da0a86c-d13c-40c5-b1fc-294716ccade3', 'interested', 'Are you interested in music?', '你对音乐感兴趣吗？'),
  ('3da0a86c-d13c-40c5-b1fc-294716ccade3-ex2', '3da0a86c-d13c-40c5-b1fc-294716ccade3', 'interested', 'All interested parties may submit observations within the prescribed consultation period.', '所有利害关系方均可在规定的磋商期内提交意见。'),
  ('3fa2a20f-3e05-47ed-87b7-989ff3bf521e-ex1', '3fa2a20f-3e05-47ed-87b7-989ff3bf521e', 'target', 'He hit the target on his first try.', '他第一次尝试就命中了目标。'),
  ('3fa2a20f-3e05-47ed-87b7-989ff3bf521e-ex2', '3fa2a20f-3e05-47ed-87b7-989ff3bf521e', 'target', 'The framework sets binding intermediate targets subject to independent verification.', '该框架设定了须经独立核查的有约束力的阶段性目标。'),
  ('97abcefa-acc5-4e87-9765-2536f4383a1c-ex1', '97abcefa-acc5-4e87-9765-2536f4383a1c', 'prison', 'He spent two years in prison.', '他在监狱里待了两年。'),
  ('97abcefa-acc5-4e87-9765-2536f4383a1c-ex2', '97abcefa-acc5-4e87-9765-2536f4383a1c', 'prison', 'The commission documented chronic overcrowding across the prison estate.', '委员会记录了监狱系统普遍存在的长期过度拥挤问题。'),
  ('a5fbd91c-fbd9-4272-ad7b-3f35302014f4-ex1', 'a5fbd91c-fbd9-4272-ad7b-3f35302014f4', 'ride', 'Can you give me a ride to school?', '你能载我去学校吗？'),
  ('a5fbd91c-fbd9-4272-ad7b-3f35302014f4-ex2', 'a5fbd91c-fbd9-4272-ad7b-3f35302014f4', 'ride', 'Investors chose to ride out the volatility rather than crystallize their losses.', '投资者选择扛过波动，而不是将损失变现。'),
  ('e110b775-9507-4cf5-8157-639bfbf76863-ex1', 'e110b775-9507-4cf5-8157-639bfbf76863', 'guard', 'A guard stands at the gate.', '大门口站着一名警卫。'),
  ('e110b775-9507-4cf5-8157-639bfbf76863-ex2', 'e110b775-9507-4cf5-8157-639bfbf76863', 'guard', 'Constitutional safeguards guard against the arbitrary exercise of emergency powers.', '宪法保障机制防范紧急权力的恣意行使。'),
  ('18e97829-be84-43a5-b9d2-a843675eabf6-ex1', '18e97829-be84-43a5-b9d2-a843675eabf6', 'terms', 'We are on good terms with our neighbors.', '我们和邻居关系很好。'),
  ('18e97829-be84-43a5-b9d2-a843675eabf6-ex2', '18e97829-be84-43a5-b9d2-a843675eabf6', 'terms', 'The revised terms subordinate existing creditors to the new financing facility.', '修订后的条款使现有债权人的受偿顺位低于新融资安排。'),
  ('f9fed05a-e8f0-4d48-8933-11a433203f29-ex1', 'f9fed05a-e8f0-4d48-8933-11a433203f29', 'demand', 'This product is in high demand.', '这种产品需求量很大。'),
  ('f9fed05a-e8f0-4d48-8933-11a433203f29-ex2', 'f9fed05a-e8f0-4d48-8933-11a433203f29', 'demand', 'The union''s demands include binding arbitration for all unresolved grievances.', '工会的诉求包括对所有未解决的申诉实行有约束力的仲裁。'),
  ('9928231b-2274-416b-888a-c79d23d8aef6-ex1', '9928231b-2274-416b-888a-c79d23d8aef6', 'reporter', 'The reporter asked many questions.', '记者问了很多问题。'),
  ('9928231b-2274-416b-888a-c79d23d8aef6-ex2', '9928231b-2274-416b-888a-c79d23d8aef6', 'reporter', 'The reporter invoked statutory protection to shield the identity of her sources.', '这名记者援引法定保护条款，为消息来源的身份保密。'),
  ('e16e821c-5dc5-4993-8654-5070c16d147a-ex1', 'e16e821c-5dc5-4993-8654-5070c16d147a', 'deliver', 'They deliver pizza until midnight.', '他们送披萨到午夜。'),
  ('e16e821c-5dc5-4993-8654-5070c16d147a-ex2', 'e16e821c-5dc5-4993-8654-5070c16d147a', 'deliver', 'The administration failed to deliver the reforms promised during the campaign.', '本届政府未能兑现竞选期间承诺的改革。'),
  ('f64eebc3-f0db-4685-88cc-c164da75dd73-ex1', 'f64eebc3-f0db-4685-88cc-c164da75dd73', 'text', 'Send me a text when you arrive.', '你到了给我发条短信。'),
  ('f64eebc3-f0db-4685-88cc-c164da75dd73-ex2', 'f64eebc3-f0db-4685-88cc-c164da75dd73', 'text', 'The authentic text of the treaty prevails in the event of divergence among translations.', '如各译本之间出现分歧，以条约的作准文本为准。'),
  ('22c19ad5-b5b4-4201-af33-973e3b2efac9-ex1', '22c19ad5-b5b4-4201-af33-973e3b2efac9', 'tool', 'A hammer is a useful tool.', '锤子是一种有用的工具。'),
  ('22c19ad5-b5b4-4201-af33-973e3b2efac9-ex2', '22c19ad5-b5b4-4201-af33-973e3b2efac9', 'tool', 'Sanctions remain the principal tool for enforcing compliance short of armed measures.', '在武力手段之外，制裁仍是强制履约的主要工具。'),
  ('84aa98a6-2092-4a44-8b41-80c70a59ec53-ex1', '84aa98a6-2092-4a44-8b41-80c70a59ec53', 'wild', 'We saw wild deer in the forest.', '我们在森林里看到了野鹿。'),
  ('84aa98a6-2092-4a44-8b41-80c70a59ec53-ex2', '84aa98a6-2092-4a44-8b41-80c70a59ec53', 'wild', 'The reintroduction program has restored viable wild populations across the reserve.', '重引入计划已在保护区内恢复了可持续的野生种群。'),
  ('fdd072e5-4d34-4cc6-87a3-539f8d6b8953-ex1', 'fdd072e5-4d34-4cc6-87a3-539f8d6b8953', 'vehicle', 'Park your vehicle in the designated area.', '请将车辆停放在指定区域。'),
  ('fdd072e5-4d34-4cc6-87a3-539f8d6b8953-ex2', 'fdd072e5-4d34-4cc6-87a3-539f8d6b8953', 'vehicle', 'Special purpose vehicles were used to keep the liabilities off the consolidated balance sheet.', '特殊目的实体被用来将负债排除在合并资产负债表之外。'),
  ('1a3e9a63-1f79-4345-95b2-a69e93dc7626-ex1', '1a3e9a63-1f79-4345-95b2-a69e93dc7626', 'observe', 'We observed the birds through binoculars.', '我们用望远镜观察鸟类。'),
  ('1a3e9a63-1f79-4345-95b2-a69e93dc7626-ex2', '1a3e9a63-1f79-4345-95b2-a69e93dc7626', 'observe', 'All parties must observe the ceasefire pending the deployment of monitors.', '在观察员部署到位之前，各方必须遵守停火协议。'),
  ('4f47ba9f-aaf5-4e8a-97d1-3abae03cbce4-ex1', '4f47ba9f-aaf5-4e8a-97d1-3abae03cbce4', 'flight', 'Our flight leaves at six in the morning.', '我们的航班早上六点起飞。'),
  ('4f47ba9f-aaf5-4e8a-97d1-3abae03cbce4-ex2', '4f47ba9f-aaf5-4e8a-97d1-3abae03cbce4', 'flight', 'Capital flight accelerated as confidence in the currency peg deteriorated.', '随着对汇率挂钩制度的信心恶化，资本外逃加速。'),
  ('30e39710-a6c5-4354-8b7d-5d57368c973b-ex1', '30e39710-a6c5-4354-8b7d-5d57368c973b', 'facility', 'The hotel has a gym facility.', '这家酒店配有健身设施。'),
  ('30e39710-a6c5-4354-8b7d-5d57368c973b-ex2', '30e39710-a6c5-4354-8b7d-5d57368c973b', 'facility', 'The storage facility operates under continuous international monitoring.', '该储存设施处于持续的国际监督之下。'),
  ('664331a9-2121-4b4e-98b6-1e825bdf0298-ex1', '664331a9-2121-4b4e-98b6-1e825bdf0298', 'understanding', 'Thank you for your understanding.', '感谢你的理解。'),
  ('664331a9-2121-4b4e-98b6-1e825bdf0298-ex2', '664331a9-2121-4b4e-98b6-1e825bdf0298', 'understanding', 'The memorandum of understanding precedes a legally binding definitive agreement.', '谅解备忘录先于具有法律约束力的正式协议签署。'),
  ('8f6c5521-1528-4ef9-9100-953871b208e4-ex1', '8f6c5521-1528-4ef9-9100-953871b208e4', 'average', 'The average temperature here is mild.', '这里的平均气温很温和。'),
  ('8f6c5521-1528-4ef9-9100-953871b208e4-ex2', '8f6c5521-1528-4ef9-9100-953871b208e4', 'average', 'Real wages for the average household have stagnated despite aggregate growth.', '尽管总量在增长，普通家庭的实际工资却停滞不前。'),
  ('beb888b6-62f5-49ec-9a2c-283470bf822f-ex1', 'beb888b6-62f5-49ec-9a2c-283470bf822f', 'emerge', 'The sun emerged from behind the clouds.', '太阳从云层后露了出来。'),
  ('beb888b6-62f5-49ec-9a2c-283470bf822f-ex2', 'beb888b6-62f5-49ec-9a2c-283470bf822f', 'emerge', 'A consensus began to emerge around phased implementation with independent review.', '围绕分阶段实施并辅以独立审查，共识开始形成。'),
  ('6ebbf69f-9b00-4251-9b54-d1afc550098e-ex1', '6ebbf69f-9b00-4251-9b54-d1afc550098e', 'advantage', 'Being tall is an advantage in basketball.', '个子高在篮球运动中是个优势。'),
  ('6ebbf69f-9b00-4251-9b54-d1afc550098e-ex2', '6ebbf69f-9b00-4251-9b54-d1afc550098e', 'advantage', 'The subsidy confers a competitive advantage that rival jurisdictions deem unlawful.', '这项补贴带来的竞争优势被竞争对手辖区认定为违法。'),
  ('479cd352-1f06-4613-b3b1-74a7d651dcaf-ex1', '479cd352-1f06-4613-b3b1-74a7d651dcaf', 'quick', 'Let''s have a quick lunch.', '我们快速吃个午饭吧。'),
  ('479cd352-1f06-4613-b3b1-74a7d651dcaf-ex2', '479cd352-1f06-4613-b3b1-74a7d651dcaf', 'quick', 'The tribunal cautioned against quick conclusions drawn from incomplete records.', '法庭告诫不要根据不完整的记录仓促下结论。'),
  ('fce929b7-d640-4674-b508-82951ef7d4a6-ex1', 'fce929b7-d640-4674-b508-82951ef7d4a6', 'leadership', 'The team improved under her leadership.', '在她的领导下，团队进步了。'),
  ('fce929b7-d640-4674-b508-82951ef7d4a6-ex2', 'fce929b7-d640-4674-b508-82951ef7d4a6', 'leadership', 'The succession crisis exposed deep fractures within the party leadership.', '接班危机暴露了党内领导层的深刻裂痕。'),
  ('87aae99c-8b91-4cff-8ca4-4f5a4d8176d0-ex1', '87aae99c-8b91-4cff-8ca4-4f5a4d8176d0', 'earn', 'How much do you earn a month?', '你一个月挣多少钱？'),
  ('87aae99c-8b91-4cff-8ca4-4f5a4d8176d0-ex2', '87aae99c-8b91-4cff-8ca4-4f5a4d8176d0', 'earn', 'Institutions must earn public trust through demonstrable accountability, not assertion.', '机构必须通过切实可见的问责赢得公众信任，而非空口宣称。'),
  ('0c0ec22c-d656-4189-8cee-72b60b5d9def-ex1', '0c0ec22c-d656-4189-8cee-72b60b5d9def', 'pound', 'The apples cost two dollars a pound.', '苹果两美元一磅。'),
  ('0c0ec22c-d656-4189-8cee-72b60b5d9def-ex2', '0c0ec22c-d656-4189-8cee-72b60b5d9def', 'pound', 'The pound depreciated sharply as markets digested the fiscal announcement.', '随着市场消化这份财政声明，英镑大幅贬值。'),
  ('12294f1b-86c9-400a-918a-57a2d532bd80-ex1', '12294f1b-86c9-400a-918a-57a2d532bd80', 'basis', 'We meet on a weekly basis.', '我们每周见一次面。'),
  ('12294f1b-86c9-400a-918a-57a2d532bd80-ex2', '12294f1b-86c9-400a-918a-57a2d532bd80', 'basis', 'The court found no statutory basis for the agency''s expansive interpretation.', '法院认定，该机构的扩张性解释缺乏法律依据。'),
  ('673a603e-d6e5-4755-a6c7-2e391cb763a8-ex1', '673a603e-d6e5-4755-a6c7-2e391cb763a8', 'bright', 'The room is bright and airy.', '这个房间明亮通风。'),
  ('673a603e-d6e5-4755-a6c7-2e391cb763a8-ex2', '673a603e-d6e5-4755-a6c7-2e391cb763a8', 'bright', 'Despite the downturn, analysts see bright prospects for the renewable sector.', '尽管经济低迷，分析人士仍看好可再生能源行业的前景。'),
  ('9ab6149c-b41a-4846-8ce6-685de71b8331-ex1', '9ab6149c-b41a-4846-8ce6-685de71b8331', 'operate', 'Do you know how to operate this machine?', '你知道怎么操作这台机器吗？'),
  ('9ab6149c-b41a-4846-8ce6-685de71b8331-ex2', '9ab6149c-b41a-4846-8ce6-685de71b8331', 'operate', 'Foreign carriers may operate domestic routes only under reciprocal arrangements.', '外国承运人只有在对等安排下才能经营国内航线。'),
  ('486b82be-d2b9-409e-b0da-16ed02610ade-ex1', '486b82be-d2b9-409e-b0da-16ed02610ade', 'guest', 'We have guests coming for dinner.', '我们有客人来吃晚饭。'),
  ('486b82be-d2b9-409e-b0da-16ed02610ade-ex2', '486b82be-d2b9-409e-b0da-16ed02610ade', 'guest', 'The summit''s guest list reflected a deliberate recalibration of diplomatic priorities.', '峰会的嘉宾名单反映出外交优先事项的刻意调整。'),
  ('a1507791-4afb-4ef6-ba8b-2d1614a22af2-ex1', 'a1507791-4afb-4ef6-ba8b-2d1614a22af2', 'sample', 'Would you like a free sample?', '你想要免费试用装吗？'),
  ('a1507791-4afb-4ef6-ba8b-2d1614a22af2-ex2', 'a1507791-4afb-4ef6-ba8b-2d1614a22af2', 'sample', 'The laboratory analyzed each sample under blinded conditions to preclude bias.', '实验室在盲测条件下分析每份样本，以排除偏倚。'),
  ('be80a420-9f96-429c-9c1f-4ccc3d76ac6e-ex1', 'be80a420-9f96-429c-9c1f-4ccc3d76ac6e', 'contribute', 'Everyone contributed money for the gift.', '每个人都为这份礼物出了钱。'),
  ('be80a420-9f96-429c-9c1f-4ccc3d76ac6e-ex2', 'be80a420-9f96-429c-9c1f-4ccc3d76ac6e', 'contribute', 'Multiple converging factors contributed to the eventual collapse of the institution.', '多重因素的叠加促成了该机构最终的倒闭。'),
  ('b17ee877-8d1c-4d06-ae12-35514c3445ed-ex1', 'b17ee877-8d1c-4d06-ae12-35514c3445ed', 'tiny', 'The kitten is so tiny!', '这只小猫真小！'),
  ('b17ee877-8d1c-4d06-ae12-35514c3445ed-ex2', 'b17ee877-8d1c-4d06-ae12-35514c3445ed', 'tiny', 'A tiny fraction of claimants ultimately received the full compensation promised.', '最终拿到全额承诺赔偿的索赔人寥寥无几。'),
  ('ec92ed2e-ebef-4e4b-9bc2-85581c82f2a4-ex1', 'ec92ed2e-ebef-4e4b-9bc2-85581c82f2a4', 'block', 'The school is two blocks away.', '学校离这里两个街区。'),
  ('ec92ed2e-ebef-4e4b-9bc2-85581c82f2a4-ex2', 'ec92ed2e-ebef-4e4b-9bc2-85581c82f2a4', 'block', 'Minority shareholders moved to block the merger through injunctive proceedings.', '小股东通过禁令程序试图阻止这次合并。'),
  ('6358b48a-12c2-44f4-b644-ee46a0c74222-ex1', '6358b48a-12c2-44f4-b644-ee46a0c74222', 'protection', 'Wear sunscreen for protection from the sun.', '涂防晒霜以防晒伤。'),
  ('6358b48a-12c2-44f4-b644-ee46a0c74222-ex2', '6358b48a-12c2-44f4-b644-ee46a0c74222', 'protection', 'The directive harmonizes consumer protection standards across member jurisdictions.', '该指令统一了成员辖区的消费者保护标准。'),
  ('9d4e0ad7-52be-46b4-92bb-a00408063043-ex1', '9d4e0ad7-52be-46b4-92bb-a00408063043', 'settle', 'Let''s settle this argument calmly.', '我们心平气和地解决这场争论吧。'),
  ('9d4e0ad7-52be-46b4-92bb-a00408063043-ex2', '9d4e0ad7-52be-46b4-92bb-a00408063043', 'settle', 'The parties elected to settle on confidential terms before trial commenced.', '双方选择在庭审开始前以保密条款达成和解。'),
  ('29bbfe68-0614-4894-9905-477620d4f6f0-ex1', '29bbfe68-0614-4894-9905-477620d4f6f0', 'feed', 'Don''t forget to feed the cat.', '别忘了喂猫。'),
  ('29bbfe68-0614-4894-9905-477620d4f6f0-ex2', '29bbfe68-0614-4894-9905-477620d4f6f0', 'feed', 'The subsidies effectively feed the very overcapacity that regulators seek to curb.', '这些补贴实际上助长了监管机构力图遏制的产能过剩。'),
  ('94bb5a9b-1d63-4aeb-a858-718309fa83a9-ex1', '94bb5a9b-1d63-4aeb-a858-718309fa83a9', 'collect', 'She collects stamps as a hobby.', '她的爱好是集邮。'),
  ('94bb5a9b-1d63-4aeb-a858-718309fa83a9-ex2', '94bb5a9b-1d63-4aeb-a858-718309fa83a9', 'collect', 'The agency may collect personal data only for specified and legitimate purposes.', '该机构只能为特定的正当目的收集个人数据。'),
  ('8be2683e-89d8-4557-a404-cf0bf0c63b5c-ex1', '8be2683e-89d8-4557-a404-cf0bf0c63b5c', 'additional', 'Do you need additional time?', '你需要额外的时间吗？'),
  ('8be2683e-89d8-4557-a404-cf0bf0c63b5c-ex2', '8be2683e-89d8-4557-a404-cf0bf0c63b5c', 'additional', 'The lenders demanded additional collateral as a condition of extending the facility.', '贷款方要求追加担保作为续贷的条件。'),
  ('2ae67075-699d-43cf-8c2b-b212235d2026-ex1', '2ae67075-699d-43cf-8c2b-b212235d2026', 'highly', 'She is a highly skilled surgeon.', '她是一位技术高超的外科医生。'),
  ('2ae67075-699d-43cf-8c2b-b212235d2026-ex2', '2ae67075-699d-43cf-8c2b-b212235d2026', 'highly', 'The committee regarded the unaudited projections as highly unreliable.', '委员会认为这些未经审计的预测极不可靠。'),
  ('b1556c61-277a-43bd-bb7e-6e629890c6cd-ex1', 'b1556c61-277a-43bd-bb7e-6e629890c6cd', 'identity', 'The police confirmed the man''s identity.', '警方确认了那名男子的身份。'),
  ('b1556c61-277a-43bd-bb7e-6e629890c6cd-ex2', 'b1556c61-277a-43bd-bb7e-6e629890c6cd', 'identity', 'The statute criminalizes identity theft committed through digital impersonation.', '该法规将通过数字冒充实施的身份盗窃定为犯罪。'),
  ('6c72e00f-ada1-4d0d-b60f-4fed151676a1-ex1', '6c72e00f-ada1-4d0d-b60f-4fed151676a1', 'title', 'What is the title of the book?', '这本书的书名是什么？'),
  ('6c72e00f-ada1-4d0d-b60f-4fed151676a1-ex2', '6c72e00f-ada1-4d0d-b60f-4fed151676a1', 'title', 'Clear title to the land could not be established from the fragmentary records.', '凭借零散的记录无法确立这块土地的清晰产权。'),
  ('93d100f4-b3f4-497f-a6cd-e43813dc9603-ex1', '93d100f4-b3f4-497f-a6cd-e43813dc9603', 'mostly', 'The audience was mostly students.', '观众大多是学生。'),
  ('93d100f4-b3f4-497f-a6cd-e43813dc9603-ex2', '93d100f4-b3f4-497f-a6cd-e43813dc9603', 'mostly', 'The fund''s losses were mostly attributable to concentrated currency exposures.', '该基金的亏损主要归因于集中的货币风险敞口。'),
  ('53ee0e67-0d58-4795-9071-edd1a1f6b65d-ex1', '53ee0e67-0d58-4795-9071-edd1a1f6b65d', 'lesson', 'I have a piano lesson today.', '我今天有钢琴课。'),
  ('53ee0e67-0d58-4795-9071-edd1a1f6b65d-ex2', '53ee0e67-0d58-4795-9071-edd1a1f6b65d', 'lesson', 'The principal lesson of the crisis concerns the dangers of correlated risk-taking.', '这场危机的主要教训在于关联性冒险行为的危害。'),
  ('ac2aebf0-eafd-47be-bad2-17c9d0a44577-ex1', 'ac2aebf0-eafd-47be-bad2-17c9d0a44577', 'faith', 'Have faith in yourself.', '要对自己有信心。'),
  ('ac2aebf0-eafd-47be-bad2-17c9d0a44577-ex2', 'ac2aebf0-eafd-47be-bad2-17c9d0a44577', 'faith', 'Both parties are obliged to perform the contract in good faith.', '双方均有义务本着诚信原则履行合同。'),
  ('6d356e58-2db1-490e-a257-3970187b90e8-ex1', '6d356e58-2db1-490e-a257-3970187b90e8', 'river', 'We swam in the river all afternoon.', '我们整个下午都在河里游泳。'),
  ('6d356e58-2db1-490e-a257-3970187b90e8-ex2', '6d356e58-2db1-490e-a257-3970187b90e8', 'river', 'The transboundary river is governed by an allocation treaty now under renegotiation.', '这条跨境河流受一项正在重新谈判的水量分配条约管辖。')
INSERT INTO vocab_examples (id, vocabulary_id, word, sentence_en, sentence_zh) VALUES
  ('71736175-5d5f-47c4-ae6f-7e9183ce9a80-ex1', '71736175-5d5f-47c4-ae6f-7e9183ce9a80', 'promote', 'The company promoted her to manager.', '公司提拔她当了经理。'),
  ('71736175-5d5f-47c4-ae6f-7e9183ce9a80-ex2', '71736175-5d5f-47c4-ae6f-7e9183ce9a80', 'promote', 'The campaign seeks to promote vaccination uptake among hesitant communities.', '该宣传活动旨在提高犹豫群体的疫苗接种率。'),
  ('b0c210eb-55e4-4dbc-9fed-9b4f6718eee0-ex1', 'b0c210eb-55e4-4dbc-9fed-9b4f6718eee0', 'living', 'What do you do for a living?', '你做什么工作谋生？'),
  ('b0c210eb-55e4-4dbc-9fed-9b4f6718eee0-ex2', 'b0c210eb-55e4-4dbc-9fed-9b4f6718eee0', 'living', 'Millions earn their living within informal economies untouched by labor protections.', '数以百万计的人在不受劳动保护覆盖的非正规经济中谋生。'),
  ('89d93c6a-d63c-46db-9256-481ce5645583-ex1', '89d93c6a-d63c-46db-9256-481ce5645583', 'count', 'Count the apples in the basket.', '数一数篮子里的苹果。'),
