  ('36501fe6-31c3-4efc-87ae-afc7d7841f12-ex2', '36501fe6-31c3-4efc-87ae-afc7d7841f12', 'ignore', 'Management chose to ignore repeated internal warnings of impending failure.', '管理层选择无视内部对即将发生故障的多次警告。'),
  ('8fb6eef6-af9e-4106-8d5c-f5cd083e84ad-ex1', '8fb6eef6-af9e-4106-8d5c-f5cd083e84ad', 'egg', 'I had a boiled egg for breakfast.', '我早餐吃了一个煮鸡蛋。'),
  ('8fb6eef6-af9e-4106-8d5c-f5cd083e84ad-ex2', '8fb6eef6-af9e-4106-8d5c-f5cd083e84ad', 'egg', 'Traceability requirements now extend to every egg sold through retail channels.', '可追溯性要求现已覆盖零售渠道销售的每一枚鸡蛋。'),
  ('b6ef9d43-7b94-473d-85f1-e3e326cfec92-ex1', 'b6ef9d43-7b94-473d-85f1-e3e326cfec92', 'belief', 'It is my belief that honesty matters most.', '我相信诚实最重要。'),
  ('b6ef9d43-7b94-473d-85f1-e3e326cfec92-ex2', 'b6ef9d43-7b94-473d-85f1-e3e326cfec92', 'belief', 'The constitution protects freedom of belief against state interference.', '宪法保护信仰自由不受国家干预。'),
  ('ab1fd07e-9e9d-4a47-9f60-6eb81e1fc8ac-ex1', 'ab1fd07e-9e9d-4a47-9f60-6eb81e1fc8ac', 'demonstrate', 'Let me demonstrate how the machine works.', '让我演示一下这台机器的工作原理。'),
  ('ab1fd07e-9e9d-4a47-9f60-6eb81e1fc8ac-ex2', 'ab1fd07e-9e9d-4a47-9f60-6eb81e1fc8ac', 'demonstrate', 'Applicants must demonstrate compliance with every criterion before certification issues.', '申请人必须证明符合每项标准，认证方可签发。'),
  ('de44a188-8445-499e-82ca-0d3fe1699687-ex1', 'de44a188-8445-499e-82ca-0d3fe1699687', 'anybody', 'Is anybody there?', '有人吗？'),
  ('de44a188-8445-499e-82ca-0d3fe1699687-ex2', 'de44a188-8445-499e-82ca-0d3fe1699687', 'anybody', 'The amnesty extends to anybody who voluntarily discloses violations within ninety days.', '凡在九十天内主动披露违规行为者，均可获得特赦。'),
  ('e4816dbd-8e3e-42bf-ad88-4db3786c3851-ex1', 'e4816dbd-8e3e-42bf-ad88-4db3786c3851', 'murder', 'The police are investigating the murder.', '警方正在调查这起谋杀案。'),
  ('e4816dbd-8e3e-42bf-ad88-4db3786c3851-ex2', 'e4816dbd-8e3e-42bf-ad88-4db3786c3851', 'murder', 'The tribunal convicted the commander of murder as a crime against humanity.', '法庭判定该指挥官犯有作为危害人类罪的谋杀罪。'),
  ('0f53bc04-589c-4051-88a1-dfb9228bce56-ex1', '0f53bc04-589c-4051-88a1-dfb9228bce56', 'gift', 'This watch was a gift from my father.', '这块手表是父亲送我的礼物。'),
  ('0f53bc04-589c-4051-88a1-dfb9228bce56-ex2', '0f53bc04-589c-4051-88a1-dfb9228bce56', 'gift', 'Officials must declare any gift exceeding the value prescribed by the ethics code.', '官员必须申报任何超过道德准则规定价值的馈赠。'),
  ('c66849e1-5bfb-4151-9969-840cfae2b6b1-ex1', 'c66849e1-5bfb-4151-9969-840cfae2b6b1', 'religion', 'We learned about world religions in school.', '我们在学校学习了世界各大宗教。'),
  ('c66849e1-5bfb-4151-9969-840cfae2b6b1-ex2', 'c66849e1-5bfb-4151-9969-840cfae2b6b1', 'religion', 'The charter forbids discrimination on grounds of religion in public employment.', '宪章禁止在公共就业中基于宗教的歧视。'),
  ('9749fee7-11ce-4432-b032-7e203b7d80e2-ex1', '9749fee7-11ce-4432-b032-7e203b7d80e2', 'review', 'The movie got great reviews.', '这部电影获得了很好的评价。'),
  ('9749fee7-11ce-4432-b032-7e203b7d80e2-ex2', '9749fee7-11ce-4432-b032-7e203b7d80e2', 'review', 'The decision is subject to judicial review on grounds of procedural impropriety.', '该决定可基于程序不当的理由接受司法审查。'),
  ('8cec900d-5ae3-4e51-b3a0-99dfc2e271d3-ex1', '8cec900d-5ae3-4e51-b3a0-99dfc2e271d3', 'editor', 'She works as an editor at a publishing house.', '她在一家出版社做编辑。'),
  ('8cec900d-5ae3-4e51-b3a0-99dfc2e271d3-ex2', '8cec900d-5ae3-4e51-b3a0-99dfc2e271d3', 'editor', 'The editor defended the publication as squarely within the public interest.', '主编辩称这次报道完全符合公共利益。'),
  ('0f02e291-8371-4d33-ad00-0dfd28afcc1b-ex1', '0f02e291-8371-4d33-ad00-0dfd28afcc1b', 'engage', 'The teacher knows how to engage her students.', '这位老师知道如何吸引学生的注意力。'),
  ('0f02e291-8371-4d33-ad00-0dfd28afcc1b-ex2', '0f02e291-8371-4d33-ad00-0dfd28afcc1b', 'engage', 'The parties agreed to engage in structured mediation before resorting to litigation.', '双方同意在诉诸诉讼之前先进行有组织的调解。'),
  ('b20f0485-a0a4-4a2b-81be-e41c10edc348-ex1', 'b20f0485-a0a4-4a2b-81be-e41c10edc348', 'coffee', 'I can''t start my day without coffee.', '不喝咖啡我一天都没法开始。'),
  ('b20f0485-a0a4-4a2b-81be-e41c10edc348-ex2', 'b20f0485-a0a4-4a2b-81be-e41c10edc348', 'coffee', 'Volatile coffee prices have destabilized the incomes of millions of smallholders.', '咖啡价格的剧烈波动动摇了数百万小农户的收入。'),
  ('c28f57dd-d688-47e0-a597-ec7f7929be22-ex1', 'c28f57dd-d688-47e0-a597-ec7f7929be22', 'document', 'Please sign this document.', '请在这份文件上签字。'),
  ('c28f57dd-d688-47e0-a597-ec7f7929be22-ex2', 'c28f57dd-d688-47e0-a597-ec7f7929be22', 'document', 'The subpoenaed documents revealed contemporaneous knowledge of the defect.', '被传调的文件显示，当时就已知晓该缺陷。'),
  ('d9babae2-c042-4bb5-8527-8088333773ea-ex1', 'd9babae2-c042-4bb5-8527-8088333773ea', 'speed', 'Reduce your speed in the school zone.', '在学校区域要减速。'),
  ('d9babae2-c042-4bb5-8527-8088333773ea-ex2', 'd9babae2-c042-4bb5-8527-8088333773ea', 'speed', 'The speed of contagion outpaced the regulators'' capacity to respond.', '风险蔓延的速度超出了监管机构的应对能力。'),
  ('ac915710-d182-4e6b-b22b-228ab34cb5cf-ex1', 'ac915710-d182-4e6b-b22b-228ab34cb5cf', 'cross', 'Look both ways before you cross the street.', '过马路前要左右看。'),
  ('ac915710-d182-4e6b-b22b-228ab34cb5cf-ex2', 'ac915710-d182-4e6b-b22b-228ab34cb5cf', 'cross', 'The case raises issues that cross traditional boundaries between tort and contract.', '该案提出的问题跨越了侵权法与合同法的传统界限。'),
  ('633728d8-c638-4a50-b91a-28ba00659903-ex1', '633728d8-c638-4a50-b91a-28ba00659903', 'influence', 'Her teacher had a big influence on her.', '她的老师对她影响很大。'),
  ('633728d8-c638-4a50-b91a-28ba00659903-ex2', '633728d8-c638-4a50-b91a-28ba00659903', 'influence', 'The statute criminalizes the exercise of improper influence over public procurement.', '该法规将对公共采购施加不当影响的行为定为犯罪。'),
  ('098897f4-19d3-4572-9b17-3a98dd44912e-ex1', '098897f4-19d3-4572-9b17-3a98dd44912e', 'anyway', 'It was raining, but we went out anyway.', '虽然下着雨，我们还是出门了。'),
  ('098897f4-19d3-4572-9b17-3a98dd44912e-ex2', '098897f4-19d3-4572-9b17-3a98dd44912e', 'anyway', 'The objection was procedurally barred; the tribunal nonetheless addressed it anyway.', '该异议本已因程序问题被排除，但法庭仍对其作了处理。'),
  ('3448fd88-1456-445c-acde-790850955565-ex1', '3448fd88-1456-445c-acde-790850955565', 'threaten', 'The dark clouds threaten rain.', '乌云预示着要下雨。'),
  ('3448fd88-1456-445c-acde-790850955565-ex2', '3448fd88-1456-445c-acde-790850955565', 'threaten', 'Rising sea levels threaten the habitability of low-lying island states.', '海平面上升威胁着低洼岛国的宜居性。'),
  ('b058b260-bbe7-4346-8b72-92dcc6b8dedb-ex1', 'b058b260-bbe7-4346-8b72-92dcc6b8dedb', 'commit', 'I can''t commit to a date yet.', '我还不能确定具体日期。'),
  ('b058b260-bbe7-4346-8b72-92dcc6b8dedb-ex2', 'b058b260-bbe7-4346-8b72-92dcc6b8dedb', 'commit', 'Signatories commit themselves to binding arbitration of all unresolved disputes.', '签署方承诺将所有未决争端提交有约束力的仲裁。'),
  ('3e0ac66d-1058-43f5-913f-8421408ab07c-ex1', '3e0ac66d-1058-43f5-913f-8421408ab07c', 'female', 'The female bird builds the nest.', '雌鸟负责筑巢。'),
  ('3e0ac66d-1058-43f5-913f-8421408ab07c-ex2', '3e0ac66d-1058-43f5-913f-8421408ab07c', 'female', 'The directive mandates minimum female representation on listed-company boards.', '该指令规定上市公司董事会中女性比例的最低要求。'),
  ('475b80c0-34e8-41fa-9fca-1285e5a1bdd8-ex1', '475b80c0-34e8-41fa-9fca-1285e5a1bdd8', 'youth', 'He spent his youth in the countryside.', '他的青年时代是在乡村度过的。'),
  ('475b80c0-34e8-41fa-9fca-1285e5a1bdd8-ex2', '475b80c0-34e8-41fa-9fca-1285e5a1bdd8', 'youth', 'Persistent youth unemployment poses a structural challenge to social cohesion.', '持续的青年失业对社会凝聚力构成结构性挑战。'),
  ('21fcca85-ff1f-475b-8180-9eb9ede8b0f3-ex1', '21fcca85-ff1f-475b-8180-9eb9ede8b0f3', 'wave', 'The waves are perfect for surfing today.', '今天的海浪非常适合冲浪。'),
  ('21fcca85-ff1f-475b-8180-9eb9ede8b0f3-ex2', '21fcca85-ff1f-475b-8180-9eb9ede8b0f3', 'wave', 'A wave of consolidations has transformed the competitive structure of the industry.', '一波兼并潮改变了该行业的竞争结构。'),
  ('5e0f2695-7f75-4bc1-9d39-03ce892d07d8-ex1', '5e0f2695-7f75-4bc1-9d39-03ce892d07d8', 'afraid', 'Don''t be afraid of the dark.', '不要怕黑。'),
  ('5e0f2695-7f75-4bc1-9d39-03ce892d07d8-ex2', '5e0f2695-7f75-4bc1-9d39-03ce892d07d8', 'afraid', 'Witnesses were afraid to testify absent enforceable guarantees of protection.', '在缺乏可执行的保护保证的情况下，证人不敢作证。'),
  ('bd9ce6ea-f1e3-460a-aecb-c8f7050ad87c-ex1', 'bd9ce6ea-f1e3-460a-aecb-c8f7050ad87c', 'quarter', 'The meeting starts at a quarter past nine.', '会议九点一刻开始。'),
  ('bd9ce6ea-f1e3-460a-aecb-c8f7050ad87c-ex2', 'bd9ce6ea-f1e3-460a-aecb-c8f7050ad87c', 'quarter', 'Revenue declined for the third consecutive quarter despite aggressive cost reductions.', '尽管大力削减成本，营收仍连续第三个季度下滑。'),
  ('a333ede6-9074-44fd-9498-4c82765b609d-ex1', 'a333ede6-9074-44fd-9498-4c82765b609d', 'background', 'Tell me about your background.', '跟我说说你的经历背景。'),
  ('a333ede6-9074-44fd-9498-4c82765b609d-ex2', 'a333ede6-9074-44fd-9498-4c82765b609d', 'background', 'Mandatory background checks apply to every position involving fiduciary responsibility.', '凡涉及受托责任的职位均须接受强制背景审查。'),
  ('ab07f50a-9fd9-4df1-87ef-8f4ed6b5e3e7-ex1', 'ab07f50a-9fd9-4df1-87ef-8f4ed6b5e3e7', 'native', 'She is a native speaker of Spanish.', '她的母语是西班牙语。'),
  ('ab07f50a-9fd9-4df1-87ef-8f4ed6b5e3e7-ex2', 'ab07f50a-9fd9-4df1-87ef-8f4ed6b5e3e7', 'native', 'The settlement recognizes native title over territories held under customary tenure.', '和解方案承认原住民对习惯保有地的所有权。'),
  ('25de2568-1d0a-46d7-a707-e526e1497453-ex1', '25de2568-1d0a-46d7-a707-e526e1497453', 'broad', 'The river is broad and calm here.', '这里的河面宽阔平静。'),
  ('25de2568-1d0a-46d7-a707-e526e1497453-ex2', '25de2568-1d0a-46d7-a707-e526e1497453', 'broad', 'The statute grants regulators broad discretion bounded only by proportionality review.', '该法规授予监管机构广泛的裁量权，仅受相称性审查约束。'),
  ('eefb12a7-6234-4140-821b-1f9b2bd6c714-ex1', 'eefb12a7-6234-4140-821b-1f9b2bd6c714', 'wonderful', 'We had a wonderful time at the beach.', '我们在海滩度过了美好的时光。'),
  ('eefb12a7-6234-4140-821b-1f9b2bd6c714-ex2', 'eefb12a7-6234-4140-821b-1f9b2bd6c714', 'wonderful', 'The restoration is a wonderful demonstration of what sustained patronage can achieve.', '这次修复出色地展示了持续资助所能取得的成就。'),
  ('1e21e1b7-c42d-4438-a824-b4f76a1ec3c8-ex1', '1e21e1b7-c42d-4438-a824-b4f76a1ec3c8', 'deny', 'He denied breaking the window.', '他否认打破了窗户。'),
  ('1e21e1b7-c42d-4438-a824-b4f76a1ec3c8-ex2', '1e21e1b7-c42d-4438-a824-b4f76a1ec3c8', 'deny', 'The state may not deny due process even amid declared emergencies.', '即使在宣布紧急状态期间，国家也不得剥夺正当程序权利。'),
  ('e125318a-8fe7-46bd-bd40-e531689ac10c-ex1', 'e125318a-8fe7-46bd-bd40-e531689ac10c', 'apparently', 'Apparently, the store is closed today.', '看来这家店今天关门了。'),
  ('e125318a-8fe7-46bd-bd40-e531689ac10c-ex2', 'e125318a-8fe7-46bd-bd40-e531689ac10c', 'apparently', 'The funds were apparently routed through intermediaries to obscure their origin.', '这些资金显然经由中介机构周转，以掩盖其来源。'),
  ('8d68be60-3ba8-4475-90ee-cbef78147474-ex1', '8d68be60-3ba8-4475-90ee-cbef78147474', 'slightly', 'The price is slightly higher this year.', '今年价格略高一些。'),
  ('8d68be60-3ba8-4475-90ee-cbef78147474-ex2', '8d68be60-3ba8-4475-90ee-cbef78147474', 'slightly', 'The revised projections deviate only slightly from the consensus forecast.', '修订后的预测与市场一致预期仅有细微偏差。'),
  ('3f091b15-a7a1-4e3e-b6bc-39728b3b8812-ex1', '3f091b15-a7a1-4e3e-b6bc-39728b3b8812', 'reaction', 'What was her reaction to the news?', '她对这个消息有什么反应？'),
  ('3f091b15-a7a1-4e3e-b6bc-39728b3b8812-ex2', '3f091b15-a7a1-4e3e-b6bc-39728b3b8812', 'reaction', 'The market reaction suggested investors had anticipated a far harsher ruling.', '市场反应表明，投资者原本预期裁决会严厉得多。'),
  ('e097e3ef-0a42-4c59-8c38-f4fde67e1a96-ex1', 'e097e3ef-0a42-4c59-8c38-f4fde67e1a96', 'twice', 'I exercise twice a week.', '我每周锻炼两次。'),
  ('e097e3ef-0a42-4c59-8c38-f4fde67e1a96-ex2', 'e097e3ef-0a42-4c59-8c38-f4fde67e1a96', 'twice', 'The legislation was vetoed twice before a compromise text finally secured passage.', '该立法两度遭否决，折中文本最终才获得通过。'),
  ('b2d5d9b7-2158-4a7a-850d-c9d4cb051dd0-ex1', 'b2d5d9b7-2158-4a7a-850d-c9d4cb051dd0', 'suit', 'He wore a dark suit to the interview.', '他穿着深色西装去面试。'),
  ('b2d5d9b7-2158-4a7a-850d-c9d4cb051dd0-ex2', 'b2d5d9b7-2158-4a7a-850d-c9d4cb051dd0', 'suit', 'The class action suit consolidated claims from plaintiffs across nine states.', '这起集体诉讼合并了来自九个州原告的索赔。'),
  ('9b328c2e-b039-4677-aa4c-4a8b39d05782-ex1', '9b328c2e-b039-4677-aa4c-4a8b39d05782', 'perspective', 'Travel gives you a new perspective.', '旅行能给你带来新的视角。'),
  ('9b328c2e-b039-4677-aa4c-4a8b39d05782-ex2', '9b328c2e-b039-4677-aa4c-4a8b39d05782', 'perspective', 'From a regulatory perspective, the arrangement raises unresolved questions of accountability.', '从监管角度看，这一安排留下了尚未解决的问责问题。'),
  ('c67ae017-3280-42bd-bc9e-725c818def6c-ex1', 'c67ae017-3280-42bd-bc9e-725c818def6c', 'growing', 'There is growing interest in electric cars.', '人们对电动汽车的兴趣日益浓厚。'),
  ('c67ae017-3280-42bd-bc9e-725c818def6c-ex2', 'c67ae017-3280-42bd-bc9e-725c818def6c', 'growing', 'Growing fiscal imbalances constrain the government''s capacity for countercyclical response.', '不断扩大的财政失衡制约着政府逆周期调节的能力。'),
  ('6a483e07-b5d4-4a91-bfaa-5525d8975dd5-ex1', '6a483e07-b5d4-4a91-bfaa-5525d8975dd5', 'blow', 'Blow out the candles and make a wish!', '吹灭蜡烛许个愿吧！'),
  ('6a483e07-b5d4-4a91-bfaa-5525d8975dd5-ex2', '6a483e07-b5d4-4a91-bfaa-5525d8975dd5', 'blow', 'The ruling dealt a severe blow to the agency''s expansive enforcement strategy.', '这一裁决沉重打击了该机构的扩张性执法策略。'),
  ('f877f149-e3ad-4088-a25b-8973ea9f210c-ex1', 'f877f149-e3ad-4088-a25b-8973ea9f210c', 'construction', 'The new bridge is under construction.', '新桥正在建设中。'),
  ('f877f149-e3ad-4088-a25b-8973ea9f210c-ex2', 'f877f149-e3ad-4088-a25b-8973ea9f210c', 'construction', 'The court adopted a narrow construction of the exemption to preserve legislative intent.', '法院对该豁免条款作了狭义解释，以维护立法意图。'),
  ('93a00551-98b4-4ee4-82fa-2cc79125897e-ex1', '93a00551-98b4-4ee4-82fa-2cc79125897e', 'intelligence', 'The dog shows remarkable intelligence.', '这只狗表现出非凡的智力。'),
  ('93a00551-98b4-4ee4-82fa-2cc79125897e-ex2', '93a00551-98b4-4ee4-82fa-2cc79125897e', 'intelligence', 'The committee oversees the intelligence services through classified briefings.', '该委员会通过机密简报对情报部门实施监督。'),
  ('e83c459e-4d22-4205-99d7-20765bca2c6a-ex1', 'e83c459e-4d22-4205-99d7-20765bca2c6a', 'destroy', 'The fire destroyed the old barn.', '大火烧毁了那座旧谷仓。'),
  ('e83c459e-4d22-4205-99d7-20765bca2c6a-ex2', 'e83c459e-4d22-4205-99d7-20765bca2c6a', 'destroy', 'Spoliation rules prohibit parties from destroying evidence relevant to anticipated litigation.', '证据保全规则禁止当事人销毁与预期诉讼相关的证据。'),
  ('07a1568e-ab58-4515-87ef-bfc10279d932-ex1', '07a1568e-ab58-4515-87ef-bfc10279d932', 'cook', 'My dad is a great cook.', '我爸爸做饭很棒。'),
  ('07a1568e-ab58-4515-87ef-bfc10279d932-ex2', '07a1568e-ab58-4515-87ef-bfc10279d932', 'cook', 'The audit revealed attempts to cook the books through fictitious revenue entries.', '审计揭露了通过虚构收入条目做假账的企图。'),
  ('ca97b11f-eb72-47ce-8e09-c5ecfa29e89d-ex1', 'ca97b11f-eb72-47ce-8e09-c5ecfa29e89d', 'connection', 'The internet connection is slow today.', '今天网速很慢。'),
  ('ca97b11f-eb72-47ce-8e09-c5ecfa29e89d-ex2', 'ca97b11f-eb72-47ce-8e09-c5ecfa29e89d', 'connection', 'Prosecutors established a direct connection between the shell entities and the laundered funds.', '检方证实了空壳实体与被洗资金之间的直接关联。'),
  ('f0580f45-6278-46ff-89ac-0ac479ce908f-ex1', 'f0580f45-6278-46ff-89ac-0ac479ce908f', 'burn', 'Be careful not to burn the toast.', '小心别把吐司烤糊了。'),
  ('f0580f45-6278-46ff-89ac-0ac479ce908f-ex2', 'f0580f45-6278-46ff-89ac-0ac479ce908f', 'burn', 'The plant was authorized to burn refuse-derived fuel under strict emission limits.', '该工厂获准在严格排放限制下燃烧垃圾衍生燃料。'),
  ('4e3a7e31-8694-4298-b8a4-85f8b9add391-ex1', '4e3a7e31-8694-4298-b8a4-85f8b9add391', 'shoe', 'My shoes got wet in the rain.', '我的鞋被雨淋湿了。'),
  ('4e3a7e31-8694-4298-b8a4-85f8b9add391-ex2', '4e3a7e31-8694-4298-b8a4-85f8b9add391', 'shoe', 'The tariff dispute over imported shoes escalated into a broader trade confrontation.', '围绕进口鞋类的关税争端升级为更广泛的贸易对抗。'),
  ('803b3889-9977-40ae-bfad-014ca3afa4ba-ex1', '803b3889-9977-40ae-bfad-014ca3afa4ba', 'grade', 'She got a good grade on the test.', '她考试得了好成绩。'),
  ('803b3889-9977-40ae-bfad-014ca3afa4ba-ex2', '803b3889-9977-40ae-bfad-014ca3afa4ba', 'grade', 'The bonds were downgraded below investment grade following the restatement.', '财报重述后，这些债券被下调至投资级以下。'),
  ('3665b290-86b9-4438-9811-6abcc6351691-ex1', '3665b290-86b9-4438-9811-6abcc6351691', 'context', 'You need to understand the context first.', '你需要先了解背景情况。'),
  ('3665b290-86b9-4438-9811-6abcc6351691-ex2', '3665b290-86b9-4438-9811-6abcc6351691', 'context', 'The remarks, read in their proper context, support no inference of intent.', '在恰当的语境中解读，这些言论不能推断出任何故意。'),
  ('943dbe4d-5daf-4169-a9fa-5e7e183109d6-ex1', '943dbe4d-5daf-4169-a9fa-5e7e183109d6', 'committee', 'The committee meets every Monday.', '委员会每周一开会。'),
  ('943dbe4d-5daf-4169-a9fa-5e7e183109d6-ex2', '943dbe4d-5daf-4169-a9fa-5e7e183109d6', 'committee', 'The committee subpoenaed records spanning a decade of disputed transactions.', '委员会传调了十年间争议交易的记录。'),
  ('4928ba1d-ff95-4eae-af0a-e363c2158ce7-ex1', '4928ba1d-ff95-4eae-af0a-e363c2158ce7', 'hey', 'Hey, wait for me!', '嘿，等等我！'),
  ('4928ba1d-ff95-4eae-af0a-e363c2158ce7-ex2', '4928ba1d-ff95-4eae-af0a-e363c2158ce7', 'hey', '"Hey," the chairman interjected, "the record must reflect every objection raised today."', '“嘿，”主席插话道，“今天提出的每项异议都必须记录在案。”'),
  ('19878a11-212f-424c-abd3-4c4b9aa2712c-ex1', '19878a11-212f-424c-abd3-4c4b9aa2712c', 'mistake', 'I made a mistake on the test.', '我考试时犯了一个错误。'),
  ('19878a11-212f-424c-abd3-4c4b9aa2712c-ex2', '19878a11-212f-424c-abd3-4c4b9aa2712c', 'mistake', 'The tribunal held that a unilateral mistake does not vitiate an otherwise valid contract.', '法庭认定，单方错误不影响本属有效合同的效力。'),
  ('ef19a366-a2f9-40f5-82e8-2e4dcf74cc5b-ex1', 'ef19a366-a2f9-40f5-82e8-2e4dcf74cc5b', 'location', 'The restaurant moved to a new location.', '那家餐厅搬到了新地址。'),
  ('ef19a366-a2f9-40f5-82e8-2e4dcf74cc5b-ex2', 'ef19a366-a2f9-40f5-82e8-2e4dcf74cc5b', 'location', 'The facility''s location within a seismic zone necessitated enhanced structural standards.', '该设施位于地震带内，因此需要更高的结构标准。'),
  ('77683408-0158-40c7-af07-be0f843d2e3a-ex1', '77683408-0158-40c7-af07-be0f843d2e3a', 'clothes', 'I need to buy some new clothes.', '我需要买些新衣服。'),
  ('77683408-0158-40c7-af07-be0f843d2e3a-ex2', '77683408-0158-40c7-af07-be0f843d2e3a', 'clothes', 'The seized shipment contained counterfeit clothes bearing protected trademarks.', '查获的货物中有假冒受保护商标的服装。'),
  ('7fc81b7a-811e-4cf4-8f05-d15408e62b91-ex1', '7fc81b7a-811e-4cf4-8f05-d15408e62b91', 'Indian', 'We had Indian food for lunch.', '我们午饭吃了印度菜。'),
  ('7fc81b7a-811e-4cf4-8f05-d15408e62b91-ex2', '7fc81b7a-811e-4cf4-8f05-d15408e62b91', 'Indian', 'Indian negotiators secured significant concessions on agricultural market access.', '印度谈判代表在农产品市场准入方面争取到了重大让步。'),
  ('ff3e9715-f48e-4373-996c-ef58a77ad69a-ex1', 'ff3e9715-f48e-4373-996c-ef58a77ad69a', 'quiet', 'Please keep quiet in the library.', '在图书馆请保持安静。'),
  ('ff3e9715-f48e-4373-996c-ef58a77ad69a-ex2', 'ff3e9715-f48e-4373-996c-ef58a77ad69a', 'quiet', 'The settlement was concluded in quiet negotiations conducted away from public scrutiny.', '和解是在避开公众视线的静默谈判中达成的。'),
  ('66afa7bf-25be-4860-813b-7164e9b28331-ex1', '66afa7bf-25be-4860-813b-7164e9b28331', 'dress', 'She wore a blue dress to the party.', '她穿着蓝色连衣裙去参加聚会。'),
  ('66afa7bf-25be-4860-813b-7164e9b28331-ex2', '66afa7bf-25be-4860-813b-7164e9b28331', 'dress', 'The code prescribes professional dress for all personnel appearing before the tribunal.', '规范要求所有出庭人员着职业正装。'),
  ('56f3d69b-6192-472f-be89-f0fe01586d28-ex1', '56f3d69b-6192-472f-be89-f0fe01586d28', 'promise', 'I promise to call you tonight.', '我保证今晚给你打电话。'),
  ('56f3d69b-6192-472f-be89-f0fe01586d28-ex2', '56f3d69b-6192-472f-be89-f0fe01586d28', 'promise', 'A promise unsupported by consideration is generally unenforceable at common law.', '按照普通法，无对价支持的允诺通常不具强制执行力。'),
  ('97587e4b-69b1-4ecd-a054-1110545e7a86-ex1', '97587e4b-69b1-4ecd-a054-1110545e7a86', 'aware', 'Are you aware of the new rules?', '你知道新规定吗？'),
  ('97587e4b-69b1-4ecd-a054-1110545e7a86-ex2', '97587e4b-69b1-4ecd-a054-1110545e7a86', 'aware', 'The directors were demonstrably aware of the risks they elected not to disclose.', '有证据表明，董事们明知这些风险却选择不予披露。'),
  ('ab90a372-4777-4168-b75a-2f4f2cde011a-ex1', 'ab90a372-4777-4168-b75a-2f4f2cde011a', 'neighbor', 'Our neighbor waters our plants when we travel.', '我们旅行时邻居帮我们浇花。'),
  ('ab90a372-4777-4168-b75a-2f4f2cde011a-ex2', 'ab90a372-4777-4168-b75a-2f4f2cde011a', 'neighbor', 'The doctrine obliges states to prevent transboundary harm to neighboring countries.', '该原则要求各国防止对邻国造成跨境损害。'),
  ('a13d960f-aa7b-44ab-9ae4-69c69530d3d9-ex1', 'a13d960f-aa7b-44ab-9ae4-69c69530d3d9', 'function', 'The elevator is not functioning today.', '电梯今天坏了。'),
  ('a13d960f-aa7b-44ab-9ae4-69c69530d3d9-ex2', 'a13d960f-aa7b-44ab-9ae4-69c69530d3d9', 'function', 'Independent courts perform an essential function in constraining majoritarian excess.', '独立法院在约束多数派越权方面发挥着不可或缺的作用。'),
  ('0142ffe6-2b93-41b2-86fc-b9ea4e14adbb-ex1', '0142ffe6-2b93-41b2-86fc-b9ea4e14adbb', 'bone', 'The dog buried a bone in the yard.', '狗在院子里埋了一根骨头。'),
  ('0142ffe6-2b93-41b2-86fc-b9ea4e14adbb-ex2', '0142ffe6-2b93-41b2-86fc-b9ea4e14adbb', 'bone', 'The excavated bones were dated to a period predating previously known settlement.', '出土的骨骼测定年代早于此前已知的聚居时期。'),
  ('f59158c6-e987-4437-9c4e-65ec8c8bcc5b-ex1', 'f59158c6-e987-4437-9c4e-65ec8c8bcc5b', 'active', 'My grandmother is still very active.', '我的祖母仍然非常活跃。'),
  ('f59158c6-e987-4437-9c4e-65ec8c8bcc5b-ex2', 'f59158c6-e987-4437-9c4e-65ec8c8bcc5b', 'active', 'The regulator maintains active surveillance of trading patterns across venues.', '监管机构对各交易场所的交易模式保持着主动监测。'),
  ('3071fd0c-ed79-4bbd-b87e-63a0d14cd90c-ex1', '3071fd0c-ed79-4bbd-b87e-63a0d14cd90c', 'extend', 'They decided to extend their vacation.', '他们决定延长假期。'),
  ('3071fd0c-ed79-4bbd-b87e-63a0d14cd90c-ex2', '3071fd0c-ed79-4bbd-b87e-63a0d14cd90c', 'extend', 'The court declined to extend the doctrine beyond its established boundaries.', '法院拒绝将该原则扩展到其既定边界之外。'),
  ('9f950b21-8132-4737-a3c9-aa4d2a101446-ex1', '9f950b21-8132-4737-a3c9-aa4d2a101446', 'chief', 'The fire chief spoke to the reporters.', '消防队长对记者发表了讲话。'),
  ('9f950b21-8132-4737-a3c9-aa4d2a101446-ex2', '9f950b21-8132-4737-a3c9-aa4d2a101446', 'chief', 'The chief obstacle to ratification remains the unresolved verification question.', '批准的主要障碍仍然是悬而未决的核查问题。'),
  ('cfce0a6d-91b9-4ffe-b7a0-22f9411ba72f-ex1', 'cfce0a6d-91b9-4ffe-b7a0-22f9411ba72f', 'combine', 'Combine the flour and eggs in a bowl.', '把面粉和鸡蛋在碗里混合。'),
  ('cfce0a6d-91b9-4ffe-b7a0-22f9411ba72f-ex2', 'cfce0a6d-91b9-4ffe-b7a0-22f9411ba72f', 'combine', 'The merged entity will combine complementary capabilities across the value chain.', '合并后的实体将整合价值链上互补的能力。'),
  ('bc4d027c-bc3b-4a83-a11b-42348c19104a-ex1', 'bc4d027c-bc3b-4a83-a11b-42348c19104a', 'wine', 'Would you like red or white wine?', '你想要红葡萄酒还是白葡萄酒？'),
  ('bc4d027c-bc3b-4a83-a11b-42348c19104a-ex2', 'bc4d027c-bc3b-4a83-a11b-42348c19104a', 'wine', 'The appellation rules strictly govern which vineyards may label their wine accordingly.', '原产地命名规则严格规定哪些葡萄园可以相应标注其葡萄酒。'),
  ('dafb17f2-5871-45f6-94e5-a5a30591f328-ex1', 'dafb17f2-5871-45f6-94e5-a5a30591f328', 'below', 'The temperature is below zero today.', '今天气温在零度以下。'),
  ('dafb17f2-5871-45f6-94e5-a5a30591f328-ex2', 'dafb17f2-5871-45f6-94e5-a5a30591f328', 'below', 'Institutions whose reserves fall below the prescribed minimum face immediate restrictions.', '储备低于规定下限的机构将立即受到限制。'),
  ('3416aaa5-435b-4758-8640-901a3808b63c-ex1', '3416aaa5-435b-4758-8640-901a3808b63c', 'cool', 'The evening air is nice and cool.', '傍晚的空气凉爽宜人。'),
  ('3416aaa5-435b-4758-8640-901a3808b63c-ex2', '3416aaa5-435b-4758-8640-901a3808b63c', 'cool', 'Investor enthusiasm began to cool as the structural weaknesses became apparent.', '随着结构性弱点显现，投资者的热情开始降温。'),
  ('cbe8a345-2899-4d4e-b913-2c27e42f5ea1-ex1', 'cbe8a345-2899-4d4e-b913-2c27e42f5ea1', 'voter', 'Every voter should know the candidates.', '每位选民都应该了解候选人。'),
  ('cbe8a345-2899-4d4e-b913-2c27e42f5ea1-ex2', 'cbe8a345-2899-4d4e-b913-2c27e42f5ea1', 'voter', 'The redistricting plan was challenged for diluting minority voter influence.', '这一选区重划方案因稀释少数族裔选民影响力而受到质疑。'),
  ('7873ca6f-e04d-4c33-9c1e-2af8cc07fc01-ex1', '7873ca6f-e04d-4c33-9c1e-2af8cc07fc01', 'learning', 'Learning a new skill takes time.', '学习一项新技能需要时间。'),
  ('7873ca6f-e04d-4c33-9c1e-2af8cc07fc01-ex2', '7873ca6f-e04d-4c33-9c1e-2af8cc07fc01', 'learning', 'The institute pioneered machine learning techniques for early diagnostic screening.', '该研究所率先将机器学习技术应用于早期诊断筛查。'),
  ('5df28756-4598-4847-8fc3-1bbda90c4a84-ex1', '5df28756-4598-4847-8fc3-1bbda90c4a84', 'bus', 'I take the bus to work every day.', '我每天坐公交车上班。'),
  ('5df28756-4598-4847-8fc3-1bbda90c4a84-ex2', '5df28756-4598-4847-8fc3-1bbda90c4a84', 'bus', 'The municipality electrified its entire bus fleet ahead of the statutory deadline.', '该市在法定期限之前完成了全部公交车队的电动化。'),
  ('c4826aca-6f8c-4d61-a130-142bf4860ece-ex1', 'c4826aca-6f8c-4d61-a130-142bf4860ece', 'hell', 'The traffic was hell this morning.', '今天早上的交通糟透了。'),
  ('c4826aca-6f8c-4d61-a130-142bf4860ece-ex2', 'c4826aca-6f8c-4d61-a130-142bf4860ece', 'hell', 'Survivors described the detention conditions as hell scarcely conveyed by official reports.', '幸存者形容拘留环境如同地狱，官方报告远不足以传达其惨状。'),
  ('32bc7029-58eb-413b-8660-44f1b2216322-ex1', '32bc7029-58eb-413b-8660-44f1b2216322', 'dangerous', 'It is dangerous to swim here.', '在这里游泳很危险。'),
  ('32bc7029-58eb-413b-8660-44f1b2216322-ex2', '32bc7029-58eb-413b-8660-44f1b2216322', 'dangerous', 'The precedent sets a dangerous course toward unchecked executive discretion.', '这一先例开启了通往不受制约的行政裁量权的危险道路。'),
  ('504cdae7-668c-43d4-94fe-325cd817169c-ex1', '504cdae7-668c-43d4-94fe-325cd817169c', 'remind', 'Remind me to buy milk tomorrow.', '提醒我明天买牛奶。'),
  ('504cdae7-668c-43d4-94fe-325cd817169c-ex2', '504cdae7-668c-43d4-94fe-325cd817169c', 'remind', 'The episode serves to remind regulators that voluntary codes rarely suffice.', '这一事件提醒监管者，自律准则很少能够奏效。'),
  ('f8389517-01b1-46d3-bec8-44943b3c27b7-ex1', 'f8389517-01b1-46d3-bec8-44943b3c27b7', 'moral', 'The story has a clear moral.', '这个故事有一个明确的寓意。'),
  ('f8389517-01b1-46d3-bec8-44943b3c27b7-ex2', 'f8389517-01b1-46d3-bec8-44943b3c27b7', 'moral', 'The tribunal distinguished legal obligation from purely moral responsibility.', '法庭区分了法律义务与纯粹的道德责任。'),
  ('26d4d837-f2d1-421c-8202-6eacae820c0a-ex1', '26d4d837-f2d1-421c-8202-6eacae820c0a', 'United', 'The team stayed united through hard times.', '这支队伍在困难时期保持团结。'),
  ('26d4d837-f2d1-421c-8202-6eacae820c0a-ex2', '26d4d837-f2d1-421c-8202-6eacae820c0a', 'United', 'The member states presented a united position throughout the multilateral negotiations.', '成员国在整个多边谈判中保持了一致立场。'),
  ('4b032f76-ace2-489c-a077-e464e48742c7-ex1', '4b032f76-ace2-489c-a077-e464e48742c7', 'category', 'Books are sorted by category in the library.', '图书馆的书按类别分类摆放。'),
  ('4b032f76-ace2-489c-a077-e464e48742c7-ex2', '4b032f76-ace2-489c-a077-e464e48742c7', 'category', 'The regulation creates a distinct category for systemically important intermediaries.', '该法规为具有系统重要性的中介机构设立了单独类别。'),
  ('4a761f7b-e893-4eb2-9201-4eeafc824c70-ex1', '4a761f7b-e893-4eb2-9201-4eeafc824c70', 'relatively', 'The test was relatively easy.', '这次考试相对容易。'),
  ('4a761f7b-e893-4eb2-9201-4eeafc824c70-ex2', '4a761f7b-e893-4eb2-9201-4eeafc824c70', 'relatively', 'The sector emerged relatively unscathed owing to its limited cross-border exposure.', '由于跨境敞口有限，该行业受到的冲击相对较小。'),
  ('a7892cc1-7f11-4c33-94be-180dff787765-ex1', 'a7892cc1-7f11-4c33-94be-180dff787765', 'victory', 'The team celebrated their victory.', '球队庆祝了胜利。'),
  ('a7892cc1-7f11-4c33-94be-180dff787765-ex2', 'a7892cc1-7f11-4c33-94be-180dff787765', 'victory', 'The ruling represents a landmark victory for advocates of digital privacy.', '这一裁决是数字隐私倡导者的里程碑式胜利。'),
  ('bedcf7e9-1f7f-49ac-bffd-34854721fb53-ex1', 'bedcf7e9-1f7f-49ac-bffd-34854721fb53', 'academic', 'She has excellent academic results.', '她的学习成绩非常优秀。'),
  ('bedcf7e9-1f7f-49ac-bffd-34854721fb53-ex2', 'bedcf7e9-1f7f-49ac-bffd-34854721fb53', 'academic', 'The committee safeguards academic freedom against administrative encroachment.', '该委员会保护学术自由免受行政干预。'),
  ('9551e50f-4149-4b6b-b666-3d13dc26655f-ex1', '9551e50f-4149-4b6b-b666-3d13dc26655f', 'Internet', 'The internet is down again.', '网络又断了。'),
  ('9551e50f-4149-4b6b-b666-3d13dc26655f-ex2', '9551e50f-4149-4b6b-b666-3d13dc26655f', 'Internet', 'The treaty addresses jurisdictional conflicts arising from cross-border internet commerce.', '该条约处理跨境互联网商务引发的管辖权冲突。'),
  ('2265b48a-80be-4ce3-b7d3-d995280501b9-ex1', '2265b48a-80be-4ce3-b7d3-d995280501b9', 'healthy', 'Eat healthy food and exercise often.', '吃健康的食物，经常锻炼。'),
  ('2265b48a-80be-4ce3-b7d3-d995280501b9-ex2', '2265b48a-80be-4ce3-b7d3-d995280501b9', 'healthy', 'A healthy banking sector is a precondition for sustained credit expansion.', '健康的银行业是信贷持续扩张的前提。'),
  ('2dfbda54-02c5-48a2-b5ff-cb18be7a4663-ex1', '2dfbda54-02c5-48a2-b5ff-cb18be7a4663', 'negative', 'The test result was negative.', '检测结果是阴性的。'),
  ('2dfbda54-02c5-48a2-b5ff-cb18be7a4663-ex2', '2dfbda54-02c5-48a2-b5ff-cb18be7a4663', 'negative', 'The assessment documented significant negative externalities borne by downstream communities.', '评估记录了由下游社区承担的重大负外部性。'),
  ('91405e80-b4a3-4998-88af-82f005cfbbcc-ex1', '91405e80-b4a3-4998-88af-82f005cfbbcc', 'following', 'Read the following paragraph carefully.', '仔细阅读下面这段文字。'),
  ('91405e80-b4a3-4998-88af-82f005cfbbcc-ex2', '91405e80-b4a3-4998-88af-82f005cfbbcc', 'following', 'Following the disclosures, the agency instituted sweeping procedural reforms.', '信息披露之后，该机构实施了全面的程序改革。'),
  ('d01082a4-e16b-4f21-b5cd-51e2c977a5f3-ex1', 'd01082a4-e16b-4f21-b5cd-51e2c977a5f3', 'historical', 'The museum has many historical objects.', '博物馆里有许多历史文物。'),
  ('d01082a4-e16b-4f21-b5cd-51e2c977a5f3-ex2', 'd01082a4-e16b-4f21-b5cd-51e2c977a5f3', 'historical', 'The commission examined the historical record to contextualize the disputed claims.', '委员会查考了历史记录，以厘清争议主张的来龙去脉。'),
  ('969dc594-071c-4aba-be27-309e3ffad055-ex1', '969dc594-071c-4aba-be27-309e3ffad055', 'medicine', 'Take this medicine twice a day.', '这种药一天服两次。'),
  ('969dc594-071c-4aba-be27-309e3ffad055-ex2', '969dc594-071c-4aba-be27-309e3ffad055', 'medicine', 'Regulatory science in medicine demands evidence drawn from controlled trials.', '医学监管科学要求以对照试验得出的证据为依据。'),
  ('51273e61-072b-4292-a9aa-f1d516673072-ex1', '51273e61-072b-4292-a9aa-f1d516673072', 'tour', 'We took a tour of the old city.', '我们游览了老城区。'),
  ('51273e61-072b-4292-a9aa-f1d516673072-ex2', '51273e61-072b-4292-a9aa-f1d516673072', 'tour', 'The inspection tour documented conditions at every facility under the consent decree.', '这次视察按照和解令记录了每处设施的状况。'),
  ('22dfc605-082c-4d0d-a21d-05ade299f7a6-ex1', '22dfc605-082c-4d0d-a21d-05ade299f7a6', 'depend', 'You can depend on me.', '你可以信赖我。'),
  ('22dfc605-082c-4d0d-a21d-05ade299f7a6-ex2', '22dfc605-082c-4d0d-a21d-05ade299f7a6', 'depend', 'Millions of livelihoods depend upon the uninterrupted functioning of the river system.', '数百万人的生计依赖于这条河流系统的正常运转。'),
  ('672ee335-696a-4506-96ec-5b59c0fb741f-ex1', '672ee335-696a-4506-96ec-5b59c0fb741f', 'photo', 'Let''s take a photo together!', '我们一起拍张照吧！'),
  ('672ee335-696a-4506-96ec-5b59c0fb741f-ex2', '672ee335-696a-4506-96ec-5b59c0fb741f', 'photo', 'The authenticated photos corroborated the witness testimony in material respects.', '经鉴定的照片在关键方面印证了证人证词。'),
  ('1be2f219-eae3-4d84-96fe-8c4c37dc49a8-ex1', '1be2f219-eae3-4d84-96fe-8c4c37dc49a8', 'finding', 'The doctor explained the findings to us.', '医生向我们解释了检查结果。'),
  ('1be2f219-eae3-4d84-96fe-8c4c37dc49a8-ex2', '1be2f219-eae3-4d84-96fe-8c4c37dc49a8', 'finding', 'The tribunal''s findings of fact are binding upon the parties absent manifest error.', '除非存在明显错误，法庭的事实认定对各方均有约束力。'),
  ('562bc311-636b-4eca-9326-def15cd88506-ex1', '562bc311-636b-4eca-9326-def15cd88506', 'grab', 'Grab your coat; we are leaving.', '拿上外套，我们要走了。'),
  ('562bc311-636b-4eca-9326-def15cd88506-ex2', '562bc311-636b-4eca-9326-def15cd88506', 'grab', 'The disclosures revealed a coordinated attempt to grab control of strategic assets.', '披露的信息揭示了一场夺取战略资产控制权的协同行动。'),
  ('0aaf832d-1661-4064-87eb-44d715937c80-ex1', '0aaf832d-1661-4064-87eb-44d715937c80', 'direct', 'Is there a direct flight to Tokyo?', '有直飞东京的航班吗？'),
  ('0aaf832d-1661-4064-87eb-44d715937c80-ex2', '0aaf832d-1661-4064-87eb-44d715937c80', 'direct', 'The regulation imposes direct obligations enforceable without national implementing measures.', '该条例规定的义务可直接执行，无需国内实施措施。'),
  ('65dfdf0b-d33b-4752-aedf-94e18a83418a-ex1', '65dfdf0b-d33b-4752-aedf-94e18a83418a', 'classroom', 'The classroom is on the second floor.', '教室在二楼。'),
  ('65dfdf0b-d33b-4752-aedf-94e18a83418a-ex2', '65dfdf0b-d33b-4752-aedf-94e18a83418a', 'classroom', 'The reforms reduce administrative burdens so teachers can remain in the classroom.', '这些改革减轻了行政负担，让教师能够专注于课堂。'),
  ('78b501c3-fede-462a-93d1-80c08053bf74-ex1', '78b501c3-fede-462a-93d1-80c08053bf74', 'contact', 'Stay in contact while you are abroad.', '你在国外时要保持联系。'),
  ('78b501c3-fede-462a-93d1-80c08053bf74-ex2', '78b501c3-fede-462a-93d1-80c08053bf74', 'contact', 'All contact between the parties was conducted through court-appointed intermediaries.', '双方的所有联系都通过法院指定的中间人进行。'),
  ('c5c4f16d-c19c-4244-92ba-9ab755264dbd-ex1', 'c5c4f16d-c19c-4244-92ba-9ab755264dbd', 'justice', 'The people demanded justice.', '人们要求伸张正义。'),
  ('c5c4f16d-c19c-4244-92ba-9ab755264dbd-ex2', 'c5c4f16d-c19c-4244-92ba-9ab755264dbd', 'justice', 'Transitional justice mechanisms must balance accountability against reconciliation.', '过渡时期司法机制必须在问责与和解之间取得平衡。'),
  ('26a3226c-00de-48d5-8f5d-1ec02b333638-ex1', '26a3226c-00de-48d5-8f5d-1ec02b333638', 'participate', 'All students can participate in the contest.', '所有学生都可以参加比赛。'),
  ('26a3226c-00de-48d5-8f5d-1ec02b333638-ex2', '26a3226c-00de-48d5-8f5d-1ec02b333638', 'participate', 'Affected residents were given no meaningful opportunity to participate in the proceedings.', '受影响的居民没有获得实质性参与相关程序的机会。'),
  ('6da49d43-51f0-46bf-af29-216bafc23269-ex1', '6da49d43-51f0-46bf-af29-216bafc23269', 'daily', 'Brush your teeth twice daily.', '每天刷两次牙。'),
  ('6da49d43-51f0-46bf-af29-216bafc23269-ex2', '6da49d43-51f0-46bf-af29-216bafc23269', 'daily', 'The facility undergoes daily monitoring under the terms of its operating license.', '根据运营许可条款，该设施每日接受监测。'),
  ('1063ea8b-52b5-4a81-b4b2-45b28d328160-ex1', '1063ea8b-52b5-4a81-b4b2-45b28d328160', 'fair', 'That is a fair price for the bike.', '这辆自行车的价格很公道。'),
  ('1063ea8b-52b5-4a81-b4b2-45b28d328160-ex2', '1063ea8b-52b5-4a81-b4b2-45b28d328160', 'fair', 'Every accused person is entitled to a fair hearing before an impartial tribunal.', '每个被告人都有权在公正的法庭获得公平审理。'),
  ('e9d1a376-9f58-4017-8722-acf0c6047b44-ex1', 'e9d1a376-9f58-4017-8722-acf0c6047b44', 'pair', 'I bought a new pair of shoes.', '我买了一双新鞋。'),
  ('e9d1a376-9f58-4017-8722-acf0c6047b44-ex2', 'e9d1a376-9f58-4017-8722-acf0c6047b44', 'pair', 'The studies pair longitudinal data with experimental validation to strengthen causal inference.', '这些研究将纵向数据与实验验证相结合，以加强因果推断。'),
  ('5008b386-214a-41e6-8f54-09c47f173062-ex1', '5008b386-214a-41e6-8f54-09c47f173062', 'famous', 'This city is famous for its food.', '这座城市以美食闻名。'),
  ('5008b386-214a-41e6-8f54-09c47f173062-ex2', '5008b386-214a-41e6-8f54-09c47f173062', 'famous', 'The case became famous as the precedent that redefined the boundaries of liability.', '该案作为重新界定责任边界的先例而闻名。'),
  ('1b8ac0af-f482-4d31-b6fc-4241d0b5d96e-ex1', '1b8ac0af-f482-4d31-b6fc-4241d0b5d96e', 'exercise', 'Morning exercise keeps me energetic.', '晨练让我精力充沛。'),
  ('1b8ac0af-f482-4d31-b6fc-4241d0b5d96e-ex2', '1b8ac0af-f482-4d31-b6fc-4241d0b5d96e', 'exercise', 'The veto''s exercise is constrained by conventions of constitutional restraint.', '否决权的行使受到宪制克制惯例的约束。'),
  ('9de0e620-7d82-4846-b67d-a8b5c861c442-ex1', '9de0e620-7d82-4846-b67d-a8b5c861c442', 'knee', 'He hurt his knee playing basketball.', '他打篮球伤了膝盖。'),
  ('9de0e620-7d82-4846-b67d-a8b5c861c442-ex2', '9de0e620-7d82-4846-b67d-a8b5c861c442', 'knee', 'The surgical registry tracks long-term outcomes for every knee replacement performed.', '手术登记系统追踪每例膝关节置换的长期疗效。'),
  ('dcb01e25-3d40-40fd-b8c3-088ab9beed07-ex1', 'dcb01e25-3d40-40fd-b8c3-088ab9beed07', 'flower', 'The flowers are blooming in the garden.', '花园里的花开了。'),
  ('dcb01e25-3d40-40fd-b8c3-088ab9beed07-ex2', 'dcb01e25-3d40-40fd-b8c3-088ab9beed07', 'flower', 'The export certification regime applies to every cut flower shipped abroad.', '出口认证制度适用于每一支运往海外的鲜切花。'),
  ('b9d2193d-6bdb-4006-b7f1-e03d6c7f5da4-ex1', 'b9d2193d-6bdb-4006-b7f1-e03d6c7f5da4', 'tape', 'Seal the box with tape.', '用胶带把箱子封好。'),
  ('b9d2193d-6bdb-4006-b7f1-e03d6c7f5da4-ex2', 'b9d2193d-6bdb-4006-b7f1-e03d6c7f5da4', 'tape', 'The subpoenaed tapes captured deliberations the participants believed confidential.', '被传调的录音带记录了与会者自以为保密的商议内容。'),
  ('3711ee4b-bb3d-42ce-acbd-e9369ebf5ce1-ex1', '3711ee4b-bb3d-42ce-acbd-e9369ebf5ce1', 'hire', 'The store will hire two new workers.', '这家店要招两名新员工。'),
  ('3711ee4b-bb3d-42ce-acbd-e9369ebf5ce1-ex2', '3711ee4b-bb3d-42ce-acbd-e9369ebf5ce1', 'hire', 'The ordinance forbids employers to hire on terms that circumvent collective agreements.', '该条例禁止雇主以规避集体协议的条件招聘。'),
  ('0e6a30f4-d85c-4a88-b925-4af18d8d3042-ex1', '0e6a30f4-d85c-4a88-b925-4af18d8d3042', 'familiar', 'Your face looks familiar to me.', '你看起来很面熟。'),
  ('0e6a30f4-d85c-4a88-b925-4af18d8d3042-ex2', '0e6a30f4-d85c-4a88-b925-4af18d8d3042', 'familiar', 'The pattern is depressingly familiar to investigators of institutional failure.', '对调查机构失灵的人员来说，这种模式令人沮丧地似曾相识。'),
  ('51ca85a6-8bf1-4d81-b69b-a8899f38e239-ex1', '51ca85a6-8bf1-4d81-b69b-a8899f38e239', 'appropriate', 'Wear appropriate clothes for the weather.', '穿适合天气的衣服。'),
  ('51ca85a6-8bf1-4d81-b69b-a8899f38e239-ex2', '51ca85a6-8bf1-4d81-b69b-a8899f38e239', 'appropriate', 'The committee may appropriate funds only for purposes enumerated in the charter.', '委员会只能为章程列明的用途拨款。'),
  ('a9446839-b0c8-46bf-9d3d-27f5ba34d469-ex1', 'a9446839-b0c8-46bf-9d3d-27f5ba34d469', 'supply', 'The town''s water supply is clean and safe.', '这个镇的供水干净安全。'),
  ('a9446839-b0c8-46bf-9d3d-27f5ba34d469-ex2', 'a9446839-b0c8-46bf-9d3d-27f5ba34d469', 'supply', 'Concentration in the supply chain leaves production vulnerable to single points of failure.', '供应链的高度集中使生产易受单点故障的冲击。'),
  ('6d2ac4dd-e47d-4cd4-9f86-3a2d3e93d124-ex1', '6d2ac4dd-e47d-4cd4-9f86-3a2d3e93d124', 'fully', 'I fully understand your concern.', '我完全理解你的担忧。'),
  ('6d2ac4dd-e47d-4cd4-9f86-3a2d3e93d124-ex2', '6d2ac4dd-e47d-4cd4-9f86-3a2d3e93d124', 'fully', 'The liabilities were never fully disclosed to the acquiring party.', '这些负债从未向收购方完全披露。'),
  ('6968f88b-1ee5-4409-b658-9740cc771802-ex1', '6968f88b-1ee5-4409-b658-9740cc771802', 'actor', 'He is a famous movie actor.', '他是一位著名的电影演员。'),
  ('6968f88b-1ee5-4409-b658-9740cc771802-ex2', '6968f88b-1ee5-4409-b658-9740cc771802', 'actor', 'Non-state actors increasingly shape outcomes once reserved to sovereign governments.', '非国家行为体日益影响着曾专属于主权政府的事务结果。'),
  ('c5648f0f-cda0-4bef-9c6c-587e0621ce63-ex1', 'c5648f0f-cda0-4bef-9c6c-587e0621ce63', 'birth', 'She gave birth to a healthy baby.', '她生了一个健康的宝宝。'),
  ('c5648f0f-cda0-4bef-9c6c-587e0621ce63-ex2', 'c5648f0f-cda0-4bef-9c6c-587e0621ce63', 'birth', 'The registry records every birth to guarantee access to citizenship rights.', '登记系统记录每例出生，以保障公民权利的获得。'),
  ('5a9b2259-b7bd-4bd4-ae47-125bbd9122d9-ex1', '5a9b2259-b7bd-4bd4-ae47-125bbd9122d9', 'search', 'I will search for my lost keys.', '我要找找丢失的钥匙。'),
  ('5a9b2259-b7bd-4bd4-ae47-125bbd9122d9-ex2', '5a9b2259-b7bd-4bd4-ae47-125bbd9122d9', 'search', 'The warrantless search was held to violate constitutional protections.', '这次无证搜查被裁定违反宪法保护条款。'),
  ('47e8ad7f-7b88-4a54-97ba-958348f6e08d-ex1', '47e8ad7f-7b88-4a54-97ba-958348f6e08d', 'tie', 'He wore a red tie to the meeting.', '他系着红色领带去开会。'),
  ('47e8ad7f-7b88-4a54-97ba-958348f6e08d-ex2', '47e8ad7f-7b88-4a54-97ba-958348f6e08d', 'tie', 'The disclosed ties between the auditor and the client compromised the engagement''s independence.', '审计师与客户之间被披露的关联损害了这项业务的独立性。'),
  ('1d1a210b-c951-47d0-83e7-74c9ce4589f7-ex1', '1d1a210b-c951-47d0-83e7-74c9ce4589f7', 'democracy', 'The country became a democracy in the 1990s.', '这个国家在二十世纪九十年代实现了民主化。'),
  ('1d1a210b-c951-47d0-83e7-74c9ce4589f7-ex2', '1d1a210b-c951-47d0-83e7-74c9ce4589f7', 'democracy', 'A resilient democracy requires institutions capable of withstanding concentrated power.', '有韧性的民主需要能够抵御权力集中的制度。'),
  ('d0606d85-4e67-4625-b3b7-bf25ce2566c6-ex1', 'd0606d85-4e67-4625-b3b7-bf25ce2566c6', 'eastern', 'The eastern part of the city is older.', '城市的东部更古老。'),
  ('d0606d85-4e67-4625-b3b7-bf25ce2566c6-ex2', 'd0606d85-4e67-4625-b3b7-bf25ce2566c6', 'eastern', 'Investment has surged across the eastern corridor following the trade liberalization.', '贸易自由化之后，东部走廊的投资激增。'),
  ('83517957-4c64-46f0-8fb2-64aefd1e983e-ex1', '83517957-4c64-46f0-8fb2-64aefd1e983e', 'primary', 'Safety is our primary concern.', '安全是我们最关心的问题。'),
  ('83517957-4c64-46f0-8fb2-64aefd1e983e-ex2', '83517957-4c64-46f0-8fb2-64aefd1e983e', 'primary', 'The primary obligation rests with the operator; the guarantor''s liability is secondary.', '主要义务由运营方承担，担保人的责任居于其次。'),
  ('cf1a3e4b-a2b5-46ed-a3f4-1acb5d895b7a-ex1', 'cf1a3e4b-a2b5-46ed-a3f4-1acb5d895b7a', 'yesterday', 'I saw her at the market yesterday.', '我昨天在市场看到她了。'),
  ('cf1a3e4b-a2b5-46ed-a3f4-1acb5d895b7a-ex2', 'cf1a3e4b-a2b5-46ed-a3f4-1acb5d895b7a', 'yesterday', 'The figures released yesterday compelled an immediate revision of growth forecasts.', '昨天公布的数据迫使增长预测立即作出修正。'),
  ('e569cf1d-d36a-4dda-8bf2-0067e1f8b68f-ex1', 'e569cf1d-d36a-4dda-8bf2-0067e1f8b68f', 'circle', 'Draw a circle on the paper.', '在纸上画一个圆。'),
  ('e569cf1d-d36a-4dda-8bf2-0067e1f8b68f-ex2', 'e569cf1d-d36a-4dda-8bf2-0067e1f8b68f', 'circle', 'Policy discussions long confined to expert circles have entered mainstream debate.', '长期局限于专家圈子的政策讨论已进入主流辩论。'),
  ('4beb6fb7-21ee-4a95-ba9c-404ae9a4a9ce-ex1', '4beb6fb7-21ee-4a95-ba9c-404ae9a4a9ce', 'device', 'This device measures air quality.', '这个设备可以测量空气质量。'),
  ('4beb6fb7-21ee-4a95-ba9c-404ae9a4a9ce-ex2', '4beb6fb7-21ee-4a95-ba9c-404ae9a4a9ce', 'device', 'Every connected device introduces a potential vector for network intrusion.', '每台联网设备都可能成为网络入侵的潜在途径。'),
  ('b2c1213e-4043-471d-bf92-d0cd8a1029c4-ex1', 'b2c1213e-4043-471d-bf92-d0cd8a1029c4', 'progress', 'You have made great progress in English.', '你的英语进步很大。'),
  ('b2c1213e-4043-471d-bf92-d0cd8a1029c4-ex2', 'b2c1213e-4043-471d-bf92-d0cd8a1029c4', 'progress', 'Progress toward the emission targets will be audited by an independent secretariat.', '减排目标的进展将由独立秘书处审计。'),
  ('229045cf-bc0c-4ffb-8e6a-b100c932cdb9-ex1', '229045cf-bc0c-4ffb-8e6a-b100c932cdb9', 'bottom', 'The keys were at the bottom of my bag.', '钥匙在我包的最底层。'),
  ('229045cf-bc0c-4ffb-8e6a-b100c932cdb9-ex2', '229045cf-bc0c-4ffb-8e6a-b100c932cdb9', 'bottom', 'The inquiry sought to get to the bottom of the systemic reporting failures.', '调查力图彻底查明系统性报告失误的根源。'),
  ('9e95b75f-1802-4e7a-9d83-d5ba26050053-ex1', '9e95b75f-1802-4e7a-9d83-d5ba26050053', 'island', 'We spent our vacation on a small island.', '我们在一个小岛上度假。'),
  ('9e95b75f-1802-4e7a-9d83-d5ba26050053-ex2', '9e95b75f-1802-4e7a-9d83-d5ba26050053', 'island', 'Low-lying island nations pressed for binding commitments on climate financing.', '低洼岛国敦促就气候融资作出有约束力的承诺。'),
  ('ea55d279-f324-438f-8345-079dbc4aa317-ex1', 'ea55d279-f324-438f-8345-079dbc4aa317', 'exchange', 'Can I exchange this shirt for a larger one?', '我能把这件衬衫换成大一号的吗？'),
  ('ea55d279-f324-438f-8345-079dbc4aa317-ex2', 'ea55d279-f324-438f-8345-079dbc4aa317', 'exchange', 'The exchange suspended trading amid unprecedented volatility in the listed securities.', '面对上市证券前所未有的波动，交易所暂停了交易。'),
  ('5adcbbd6-da09-476d-bbee-a02b57f81e79-ex1', '5adcbbd6-da09-476d-bbee-a02b57f81e79', 'clean', 'Please keep your room clean.', '请保持房间整洁。'),
  ('5adcbbd6-da09-476d-bbee-a02b57f81e79-ex2', '5adcbbd6-da09-476d-bbee-a02b57f81e79', 'clean', 'The audit pronounced the accounts clean, a conclusion later proved unwarranted.', '审计宣称账目无瑕疵，这一结论后来被证明站不住脚。'),
  ('62804216-cbd6-486e-9219-b7b2b8d64e06-ex1', '62804216-cbd6-486e-9219-b7b2b8d64e06', 'studio', 'She practices dance at the studio.', '她在舞蹈室练舞。'),
  ('62804216-cbd6-486e-9219-b7b2b8d64e06-ex2', '62804216-cbd6-486e-9219-b7b2b8d64e06', 'studio', 'The studio negotiated streaming rights that reshaped industry compensation norms.', '这家制片公司谈判达成的流媒体版权协议重塑了行业报酬规范。'),
  ('81eb5c4e-0e78-4e1f-ac43-88dec48c8212-ex1', '81eb5c4e-0e78-4e1f-ac43-88dec48c8212', 'train', 'The train arrives at nine.', '火车九点到站。'),
  ('81eb5c4e-0e78-4e1f-ac43-88dec48c8212-ex2', '81eb5c4e-0e78-4e1f-ac43-88dec48c8212', 'train', 'The academy was established to train magistrates in commercial adjudication.', '该学院的设立旨在培训商事审判方面的法官。'),
  ('53106d04-e6d4-4ab4-ad53-76eba1426125-ex1', '53106d04-e6d4-4ab4-ad53-76eba1426125', 'lady', 'A kind lady helped me find the way.', '一位好心的女士帮我指了路。'),
  ('53106d04-e6d4-4ab4-ad53-76eba1426125-ex2', '53106d04-e6d4-4ab4-ad53-76eba1426125', 'lady', 'The first lady''s foundation channels private philanthropy toward literacy programs.', '第一夫人的基金会将私人慈善资金引向扫盲项目。'),
  ('1a9d4f53-92c6-4e49-923e-00dfea5a3411-ex1', '1a9d4f53-92c6-4e49-923e-00dfea5a3411', 'colleague', 'I had lunch with my colleagues.', '我和同事们一起吃了午饭。'),
  ('1a9d4f53-92c6-4e49-923e-00dfea5a3411-ex2', '1a9d4f53-92c6-4e49-923e-00dfea5a3411', 'colleague', 'Her colleagues corroborated the account she provided to the investigating panel.', '她的同事们证实了她向调查组提供的陈述。'),
  ('bbfdadaa-a62e-4c01-aa17-1d5a07ae85ff-ex1', 'bbfdadaa-a62e-4c01-aa17-1d5a07ae85ff', 'application', 'My application was approved!', '我的申请通过了！'),
  ('bbfdadaa-a62e-4c01-aa17-1d5a07ae85ff-ex2', 'bbfdadaa-a62e-4c01-aa17-1d5a07ae85ff', 'application', 'The uniform application of the rules is essential to their perceived legitimacy.', '规则的统一适用对其公信力至关重要。'),
  ('73195383-faf5-4de7-92c2-60397ce99c02-ex1', '73195383-faf5-4de7-92c2-60397ce99c02', 'neck', 'My neck hurts from sitting too long.', '坐久了我的脖子疼。'),
  ('73195383-faf5-4de7-92c2-60397ce99c02-ex2', '73195383-faf5-4de7-92c2-60397ce99c02', 'neck', 'The two candidates remained neck and neck through the final week of polling.', '两位候选人在民调的最后一周仍不相上下。'),
  ('16749ca1-88c6-450a-bb4b-77635f584371-ex1', '16749ca1-88c6-450a-bb4b-77635f584371', 'lean', 'Don''t lean against the wet wall.', '别靠在湿墙上。'),
  ('16749ca1-88c6-450a-bb4b-77635f584371-ex2', '16749ca1-88c6-450a-bb4b-77635f584371', 'lean', 'The restructuring produced a leaner organization focused on core regulated activities.', '重组造就了一个聚焦核心受监管业务的精简组织。'),
  ('f4285dd2-ab4e-4845-a611-fd32ecc1c7d1-ex1', 'f4285dd2-ab4e-4845-a611-fd32ecc1c7d1', 'damage', 'The storm caused serious damage.', '暴风雨造成了严重的损失。'),
  ('f4285dd2-ab4e-4845-a611-fd32ecc1c7d1-ex2', 'f4285dd2-ab4e-4845-a611-fd32ecc1c7d1', 'damage', 'The claimants seek damages commensurate with the documented environmental harm.', '索赔人要求与记录在案的环境损害相称的赔偿。'),
  ('0243a424-7d53-4a5e-8909-a09b1092bc9c-ex1', '0243a424-7d53-4a5e-8909-a09b1092bc9c', 'plastic', 'Bring your own bag instead of using plastic.', '自带购物袋，少用塑料袋。'),
  ('0243a424-7d53-4a5e-8909-a09b1092bc9c-ex2', '0243a424-7d53-4a5e-8909-a09b1092bc9c', 'plastic', 'The directive phases out single-use plastic across all member jurisdictions.', '该指令在所有成员辖区逐步淘汰一次性塑料制品。'),
  ('3f6734f4-7798-4a71-b9f8-925c6cec37fb-ex1', '3f6734f4-7798-4a71-b9f8-925c6cec37fb', 'tall', 'My brother is very tall.', '我哥哥个子很高。'),
  ('3f6734f4-7798-4a71-b9f8-925c6cec37fb-ex2', '3f6734f4-7798-4a71-b9f8-925c6cec37fb', 'tall', 'The projections rest on assumptions that many economists consider a tall order.', '这些预测所依据的假设在许多经济学家看来难以实现。'),
  ('1b2c505a-e4b5-4e31-af63-6e4e328278d6-ex1', '1b2c505a-e4b5-4e31-af63-6e4e328278d6', 'plate', 'Put the cookies on a plate.', '把饼干放在盘子里。'),
  ('1b2c505a-e4b5-4e31-af63-6e4e328278d6-ex2', '1b2c505a-e4b5-4e31-af63-6e4e328278d6', 'plate', 'The agency has a full plate of pending rulemakings inherited from the prior administration.', '该机构手头堆满了上届政府遗留的待定规则制定事项。'),
  ('525d8696-3641-49f7-a31e-c3cbada036a4-ex1', '525d8696-3641-49f7-a31e-c3cbada036a4', 'hate', 'I hate getting up early.', '我讨厌早起。'),
  ('525d8696-3641-49f7-a31e-c3cbada036a4-ex2', '525d8696-3641-49f7-a31e-c3cbada036a4', 'hate', 'The statute criminalizes incitement to hatred while preserving protected expression.', '该法规将煽动仇恨定为犯罪，同时保留受保护的言论。'),
  ('b407db8e-7377-48d5-91c2-b84494c89664-ex1', 'b407db8e-7377-48d5-91c2-b84494c89664', 'otherwise', 'Hurry up; otherwise we will be late.', '快点，否则我们要迟到了。'),
  ('b407db8e-7377-48d5-91c2-b84494c89664-ex2', 'b407db8e-7377-48d5-91c2-b84494c89664', 'otherwise', 'Absent the waiver, the transaction would otherwise contravene the ownership restrictions.', '若无豁免，该交易本会违反所有权限制规定。'),
  ('539a3cc5-ad6f-4e09-9578-3e61e3a6977d-ex1', '539a3cc5-ad6f-4e09-9578-3e61e3a6977d', 'writing', 'Her writing is clear and beautiful.', '她的文笔清晰优美。'),
  ('539a3cc5-ad6f-4e09-9578-3e61e3a6977d-ex2', '539a3cc5-ad6f-4e09-9578-3e61e3a6977d', 'writing', 'All amendments must be evidenced in writing signed by authorized representatives.', '所有修订必须以经授权代表签署的书面形式为凭。'),
  ('677b0f36-da5b-4094-ab81-34ab2b584f4a-ex1', '677b0f36-da5b-4094-ab81-34ab2b584f4a', 'male', 'The male birds have brighter colors.', '雄鸟的羽毛颜色更鲜艳。'),
  ('677b0f36-da5b-4094-ab81-34ab2b584f4a-ex2', '677b0f36-da5b-4094-ab81-34ab2b584f4a', 'male', 'The study documents persistent disparities favoring male candidates in promotion decisions.', '该研究记录了晋升决定中长期存在的偏向男性候选人的差异。'),
  ('5745c902-702a-4a88-a921-589a96110f53-ex1', '5745c902-702a-4a88-a921-589a96110f53', 'alive', 'The fish is still alive.', '这条鱼还活着。'),
  ('5745c902-702a-4a88-a921-589a96110f53-ex2', '5745c902-702a-4a88-a921-589a96110f53', 'alive', 'The appellate ruling keeps alive claims that the trial court had dismissed.', '上诉裁决使初审法院驳回的诉求得以延续。'),
  ('2db462e8-4d69-419e-a23f-c91d0b2af85c-ex1', '2db462e8-4d69-419e-a23f-c91d0b2af85c', 'expression', 'She had a happy expression on her face.', '她脸上带着幸福的表情。'),
  ('2db462e8-4d69-419e-a23f-c91d0b2af85c-ex2', '2db462e8-4d69-419e-a23f-c91d0b2af85c', 'expression', 'The covenant protects freedom of expression subject only to narrowly drawn exceptions.', '该公约保护表达自由，仅受严格限定的例外约束。'),
  ('4e77e722-8bd3-4a61-82b4-8953d02b2bcb-ex1', '4e77e722-8bd3-4a61-82b4-8953d02b2bcb', 'football', 'We play football every weekend.', '我们每个周末踢足球。'),
  ('4e77e722-8bd3-4a61-82b4-8953d02b2bcb-ex2', '4e77e722-8bd3-4a61-82b4-8953d02b2bcb', 'football', 'The football federation imposed financial fair-play rules to curb unsustainable spending.', '足球协会实施了财政公平规则，以遏制不可持续的支出。'),
  ('5fd4fb5e-388d-4430-93ba-4b2e3f61880c-ex1', '5fd4fb5e-388d-4430-93ba-4b2e3f61880c', 'intend', 'I intend to finish this book tonight.', '我打算今晚读完这本书。'),
  ('5fd4fb5e-388d-4430-93ba-4b2e3f61880c-ex2', '5fd4fb5e-388d-4430-93ba-4b2e3f61880c', 'intend', 'The parties intend the agreement to supersede all prior understandings.', '双方意图以本协议取代此前的一切约定。'),
  ('39654d77-ed4d-4cfb-8855-ae71be94bc99-ex1', '39654d77-ed4d-4cfb-8855-ae71be94bc99', 'chicken', 'We had chicken and rice for dinner.', '我们晚饭吃了鸡肉和米饭。'),
  ('39654d77-ed4d-4cfb-8855-ae71be94bc99-ex2', '39654d77-ed4d-4cfb-8855-ae71be94bc99', 'chicken', 'The recall encompassed every chicken product processed at the affected facility.', '召回涵盖了受影响工厂加工的所有鸡肉制品。'),
  ('4d7ae5e2-3f27-448b-b74a-88d32e81f22f-ex1', '4d7ae5e2-3f27-448b-b74a-88d32e81f22f', 'army', 'He joined the army at eighteen.', '他十八岁参军。'),
  ('4d7ae5e2-3f27-448b-b74a-88d32e81f22f-ex2', '4d7ae5e2-3f27-448b-b74a-88d32e81f22f', 'army', 'The army remains subject to civilian command under the constitutional settlement.', '根据宪制安排，军队仍受文官指挥。'),
  ('feb3b500-e73d-49f6-a8f5-8edf0bbe8125-ex1', 'feb3b500-e73d-49f6-a8f5-8edf0bbe8125', 'abuse', 'Don''t abuse your eyes by reading in the dark.', '别在黑暗中看书伤眼睛。'),
  ('feb3b500-e73d-49f6-a8f5-8edf0bbe8125-ex2', 'feb3b500-e73d-49f6-a8f5-8edf0bbe8125', 'abuse', 'The inquiry documented systematic abuse of dominance in the platform markets.', '调查记录了平台市场中系统性滥用支配地位的行为。'),
  ('02aa4b52-2ca2-4404-a6ee-62e387eb3e82-ex1', '02aa4b52-2ca2-4404-a6ee-62e387eb3e82', 'theater', 'We saw a play at the theater.', '我们在剧院看了一场话剧。'),
  ('02aa4b52-2ca2-4404-a6ee-62e387eb3e82-ex2', '02aa4b52-2ca2-4404-a6ee-62e387eb3e82', 'theater', 'The restored theater anchors the city''s broader cultural regeneration strategy.', '修复后的剧院是该市整体文化复兴战略的支柱。'),
  ('7c161558-eb17-475e-acba-94970cb9c729-ex1', '7c161558-eb17-475e-acba-94970cb9c729', 'shut', 'Please shut the window; it is cold.', '请关上窗户，天冷了。'),
  ('7c161558-eb17-475e-acba-94970cb9c729-ex2', '7c161558-eb17-475e-acba-94970cb9c729', 'shut', 'The regulator moved to shut down operations conducted without requisite licensing.', '监管机构着手关停未取得必要许可的经营活动。'),
  ('03d3563d-9d67-47b0-8df7-abd0fc18cc73-ex1', '03d3563d-9d67-47b0-8df7-abd0fc18cc73', 'map', 'Can you find our hotel on the map?', '你能在地图上找到我们的酒店吗？'),
  ('03d3563d-9d67-47b0-8df7-abd0fc18cc73-ex2', '03d3563d-9d67-47b0-8df7-abd0fc18cc73', 'map', 'The genomic map enables researchers to localize variants associated with disease.', '基因组图谱使研究人员能够定位与疾病相关的变异。'),
  ('89f19cbf-74a9-46e3-9bab-60cb99dbaaa9-ex1', '89f19cbf-74a9-46e3-9bab-60cb99dbaaa9', 'extra', 'Can I have an extra blanket?', '能再给我一条毯子吗？'),
  ('89f19cbf-74a9-46e3-9bab-60cb99dbaaa9-ex2', '89f19cbf-74a9-46e3-9bab-60cb99dbaaa9', 'extra', 'The lenders demanded extra covenants as the borrower''s leverage increased.', '随着借款人杠杆率上升，贷款方要求增加额外契约条款。'),
  ('b9400aa9-c170-414b-b60a-4f2474a4c5e9-ex1', 'b9400aa9-c170-414b-b60a-4f2474a4c5e9', 'session', 'The morning session starts at nine.', '上午的会议九点开始。'),
  ('b9400aa9-c170-414b-b60a-4f2474a4c5e9-ex2', 'b9400aa9-c170-414b-b60a-4f2474a4c5e9', 'session', 'The legislature convened an extraordinary session to address the funding crisis.', '立法机构召开特别会议以应对资金危机。'),
  ('263d1ed4-354a-4bd7-b4dd-c03e6f55e335-ex1', '263d1ed4-354a-4bd7-b4dd-c03e6f55e335', 'danger', 'The sign warns of danger ahead.', '指示牌警告前方危险。'),
  ('263d1ed4-354a-4bd7-b4dd-c03e6f55e335-ex2', '263d1ed4-354a-4bd7-b4dd-c03e6f55e335', 'danger', 'The court weighed the danger of flight against the presumption of liberty.', '法院在潜逃风险与自由推定之间进行了权衡。'),
  ('e741858b-5af4-410d-8974-ad63aabf6cbb-ex1', 'e741858b-5af4-410d-8974-ad63aabf6cbb', 'welcome', 'Welcome to our home!', '欢迎来我们家！'),
  ('e741858b-5af4-410d-8974-ad63aabf6cbb-ex2', 'e741858b-5af4-410d-8974-ad63aabf6cbb', 'welcome', 'The delegation received a welcome calibrated to signal cautious diplomatic warming.', '代表团受到的接待经过精心安排，传递出谨慎的外交回暖信号。'),
  ('06e47e6f-529e-4ea6-bfc7-4e3cecbfc682-ex1', '06e47e6f-529e-4ea6-bfc7-4e3cecbfc682', 'domestic', 'She prefers domestic products.', '她更喜欢国产商品。'),
  ('06e47e6f-529e-4ea6-bfc7-4e3cecbfc682-ex2', '06e47e6f-529e-4ea6-bfc7-4e3cecbfc682', 'domestic', 'The carve-out shields domestic producers from the full force of the tariff reductions.', '这一例外条款使国内生产商免受关税削减的全面冲击。'),
  ('6251cfad-010e-4f1c-a290-df2a480d85f3-ex1', '6251cfad-010e-4f1c-a290-df2a480d85f3', 'lots', 'We have lots of time before the train leaves.', '离火车开车还有很多时间。'),
  ('6251cfad-010e-4f1c-a290-df2a480d85f3-ex2', '6251cfad-010e-4f1c-a290-df2a480d85f3', 'lots', 'The auction disposed of lots comprising assets seized under the forfeiture order.', '这次拍卖处置了依据没收令查扣资产组成的各批标的。'),
  ('17fb02d2-83ce-4ed0-b0a3-6e2c2e7b8f9a-ex1', '17fb02d2-83ce-4ed0-b0a3-6e2c2e7b8f9a', 'literature', 'She studies English literature.', '她学习英国文学。'),
  ('17fb02d2-83ce-4ed0-b0a3-6e2c2e7b8f9a-ex2', '17fb02d2-83ce-4ed0-b0a3-6e2c2e7b8f9a', 'literature', 'The peer-reviewed literature overwhelmingly supports the causal interpretation.', '同行评审文献压倒性地支持这一因果解释。'),
  ('7da1df5c-0c9a-4341-8c40-3ff97a79a000-ex1', '7da1df5c-0c9a-4341-8c40-3ff97a79a000', 'rain', 'The rain lasted all night.', '雨下了一整夜。'),
  ('7da1df5c-0c9a-4341-8c40-3ff97a79a000-ex2', '7da1df5c-0c9a-4341-8c40-3ff97a79a000', 'rain', 'Erratic seasonal rains have undermined the reliability of traditional cropping calendars.', '季节性降雨的反复无常削弱了传统农时安排的可靠性。'),
  ('d9ec8de3-0630-40ce-9131-ffb4927ff861-ex1', 'd9ec8de3-0630-40ce-9131-ffb4927ff861', 'desire', 'She has a strong desire to learn.', '她有强烈的求知欲。'),
  ('d9ec8de3-0630-40ce-9131-ffb4927ff861-ex2', 'd9ec8de3-0630-40ce-9131-ffb4927ff861', 'desire', 'The settlement reflects a mutual desire to avoid protracted and uncertain litigation.', '和解体现了双方避免旷日持久且结果难料的诉讼的共同意愿。'),
  ('6e889a80-759f-485c-9c8a-d0ae882844c2-ex1', '6e889a80-759f-485c-9c8a-d0ae882844c2', 'assessment', 'The teacher gave a fair assessment of my work.', '老师对我的作业给出了公正的评价。'),
  ('6e889a80-759f-485c-9c8a-d0ae882844c2-ex2', '6e889a80-759f-485c-9c8a-d0ae882844c2', 'assessment', 'The environmental assessment must precede any irreversible commitment of resources.', '环境评估必须先于任何不可逆转的资源投入。'),
  ('2731d67c-0b94-46b4-99f1-0b2ca1bd3499-ex1', '2731d67c-0b94-46b4-99f1-0b2ca1bd3499', 'injury', 'He suffered a minor injury in the game.', '他在比赛中受了轻伤。'),
  ('2731d67c-0b94-46b4-99f1-0b2ca1bd3499-ex2', '2731d67c-0b94-46b4-99f1-0b2ca1bd3499', 'injury', 'Compensation extends to psychological injury where causation is medically established.', '在因果关系获得医学证实的情况下，赔偿范围延及心理伤害。'),
  ('bb6698ea-65cc-4ac6-b765-52e669f09a5b-ex1', 'bb6698ea-65cc-4ac6-b765-52e669f09a5b', 'respect', 'Children should respect their elders.', '孩子应该尊敬长辈。'),
  ('bb6698ea-65cc-4ac6-b765-52e669f09a5b-ex2', 'bb6698ea-65cc-4ac6-b765-52e669f09a5b', 'respect', 'The judgment commands respect across jurisdictions for its meticulous reasoning.', '该判决以其缜密的说理赢得了各司法管辖区的尊重。')
INSERT INTO vocab_examples (id, vocabulary_id, word, sentence_en, sentence_zh) VALUES
  ('3c7cef15-bbb3-4b21-a426-180571126523-ex1', '3c7cef15-bbb3-4b21-a426-180571126523', 'northern', 'They live in the northern part of the city.', '他们住在城市的北部。'),
  ('3c7cef15-bbb3-4b21-a426-180571126523-ex2', '3c7cef15-bbb3-4b21-a426-180571126523', 'northern', 'The northern provinces secured fiscal transfers under the equalization framework.', '北部各省根据均衡化框架获得了财政转移支付。'),
  ('5058f571-45d5-4c8d-9c81-e0fab5680847-ex1', '5058f571-45d5-4c8d-9c81-e0fab5680847', 'nod', 'She gave me a friendly nod.', '她友好地向我点了点头。'),
  ('5058f571-45d5-4c8d-9c81-e0fab5680847-ex2', '5058f571-45d5-4c8d-9c81-e0fab5680847', 'nod', 'The committee gave its final nod to the merger subject to behavioral remedies.', '委员会附带行为性救济条件，对合并给予了最终批准。'),
  ('1e7b3492-d374-4300-b514-1a14d5318df9-ex1', '1e7b3492-d374-4300-b514-1a14d5318df9', 'paint', 'We will paint the bedroom blue.', '我们要把卧室刷成蓝色。'),
  ('1e7b3492-d374-4300-b514-1a14d5318df9-ex2', '1e7b3492-d374-4300-b514-1a14d5318df9', 'paint', 'The disclosures paint a damning portrait of sustained regulatory complacency.', '披露的信息勾勒出一幅监管长期自满的可悲图景。'),
  ('c0ae740e-f236-427b-ad5e-7191a4089ef4-ex1', 'c0ae740e-f236-427b-ad5e-7191a4089ef4', 'fuel', 'The car is running low on fuel.', '汽车快没油了。'),
