  ('6a5bef3b-2062-4a5f-8310-43a468f0c3ca-ex2', '6a5bef3b-2062-4a5f-8310-43a468f0c3ca', 'novel', 'The case presents novel questions concerning liability for autonomous systems.', '该案就自主系统的责任问题提出了前所未有的法律问题。'),
  ('ea19c60c-0b8e-46bc-afac-4dca1cdc4906-ex1', 'ea19c60c-0b8e-46bc-afac-4dca1cdc4906', 'code', 'Enter the code to open the door.', '输入密码开门。'),
