  ('dc37efca-1304-4d3d-8f8e-985cd436faf4-ex2', 'dc37efca-1304-4d3d-8f8e-985cd436faf4', 'jury', 'The jury was sequestered to insulate deliberations from media coverage.', '陪审团被隔离，以使评议不受媒体报道影响。'),
  ('ef62a977-5b82-473a-bf94-72cd70cdb085-ex1', 'ef62a977-5b82-473a-bf94-72cd70cdb085', 'breast', 'Breast milk is best for newborns.', '母乳对新生儿最好。'),
  ('ef62a977-5b82-473a-bf94-72cd70cdb085-ex2', 'ef62a977-5b82-473a-bf94-72cd70cdb085', 'breast', 'The screening program detects breast cancer at substantially earlier stages.', '该筛查项目能在更早阶段发现乳腺癌。'),
  ('b31b993d-5bcd-4100-a713-301ba1789886-ex1', 'b31b993d-5bcd-4100-a713-301ba1789886', 'Iraqi', 'He has an Iraqi friend from college.', '他有一位大学认识的伊拉克朋友。'),
  ('b31b993d-5bcd-4100-a713-301ba1789886-ex2', 'b31b993d-5bcd-4100-a713-301ba1789886', 'Iraqi', 'Iraqi negotiators pressed for the restitution of antiquities removed during the conflict.', '伊拉克谈判代表要求归还冲突期间流失的文物。'),
  ('0bb502ef-e85c-4f23-9986-760fd47170a2-ex1', '0bb502ef-e85c-4f23-9986-760fd47170a2', 'acknowledge', 'She acknowledged her mistake right away.', '她立刻承认了自己的错误。'),
  ('0bb502ef-e85c-4f23-9986-760fd47170a2-ex2', '0bb502ef-e85c-4f23-9986-760fd47170a2', 'acknowledge', 'The ministry declined to acknowledge receipt of the formal protest note.', '该部拒绝确认收到正式抗议照会。'),
  ('4205b6da-a54f-46bd-8d5d-a5210ef38a5c-ex1', '4205b6da-a54f-46bd-8d5d-a5210ef38a5c', 'theme', 'The party has an ocean theme.', '派对以海洋为主题。'),
  ('4205b6da-a54f-46bd-8d5d-a5210ef38a5c-ex2', '4205b6da-a54f-46bd-8d5d-a5210ef38a5c', 'theme', 'Accountability emerged as the unifying theme across the commission''s recommendations.', '问责成为贯穿委员会各项建议的共同主题。'),
