  ('8521b031-5844-4e8b-8e7b-c686df605c3a-ex1', '8521b031-5844-4e8b-8e7b-c686df605c3a', 'declare', 'Do you have anything to declare at customs?', '你有需要向海关申报的物品吗？'),
  ('8521b031-5844-4e8b-8e7b-c686df605c3a-ex2', '8521b031-5844-4e8b-8e7b-c686df605c3a', 'declare', 'The court may declare the provision void for inconsistency with the constitution.', '法院可以宣告该条款因抵触宪法而无效。'),
  ('cdba5224-4e49-4abd-b2cd-dd6ef652bb06-ex1', 'cdba5224-4e49-4abd-b2cd-dd6ef652bb06', 'appreciate', 'I really appreciate your help.', '我非常感谢你的帮助。'),
  ('cdba5224-4e49-4abd-b2cd-dd6ef652bb06-ex2', 'cdba5224-4e49-4abd-b2cd-dd6ef652bb06', 'appreciate', 'Few contemporaries appreciated the full significance of the institutional innovation.', '当时很少有人充分认识到这一制度创新的深远意义。'),
  ('138a5854-92d1-4c28-a116-d2c6d9ecb249-ex1', '138a5854-92d1-4c28-a116-d2c6d9ecb249', 'actual', 'The actual price was higher than advertised.', '实际价格比广告标价高。'),
  ('138a5854-92d1-4c28-a116-d2c6d9ecb249-ex2', '138a5854-92d1-4c28-a116-d2c6d9ecb249', 'actual', 'Damages are measured by actual loss rather than speculative projections.', '损害赔偿以实际损失为准，而非推测性预估。'),
  ('bf442bea-78fc-4a4f-805f-1ce3b190179c-ex1', 'bf442bea-78fc-4a4f-805f-1ce3b190179c', 'bottle', 'Bring a bottle of water for the hike.', '远足时带一瓶水。'),
  ('bf442bea-78fc-4a4f-805f-1ce3b190179c-ex2', 'bf442bea-78fc-4a4f-805f-1ce3b190179c', 'bottle', 'The deposit scheme applies to every beverage bottle sold within the jurisdiction.', '押金制度适用于辖区内销售的每一个饮料瓶。'),
  ('5b01b061-a634-4d1c-8ea5-ea6caaed6fb4-ex1', '5b01b061-a634-4d1c-8ea5-ea6caaed6fb4', 'hardly', 'I could hardly hear you on the phone.', '电话里我几乎听不清你说话。'),
  ('5b01b061-a634-4d1c-8ea5-ea6caaed6fb4-ex2', '5b01b061-a634-4d1c-8ea5-ea6caaed6fb4', 'hardly', 'The remedies hardly address the structural imbalances the inquiry identified.', '这些补救措施几乎没有触及调查所发现的结构性失衡。'),
  ('df0451ec-fd3c-4821-8142-19925133c7ea-ex1', 'df0451ec-fd3c-4821-8142-19925133c7ea', 'setting', 'The hotel is in a beautiful mountain setting.', '这家酒店坐落在美丽的山间。'),
  ('df0451ec-fd3c-4821-8142-19925133c7ea-ex2', 'df0451ec-fd3c-4821-8142-19925133c7ea', 'setting', 'Standard-setting in this domain has migrated from states to private consortia.', '该领域的标准制定已从国家转移到私营联盟手中。'),
  ('3101feb7-f19e-4bc5-b76e-24953c8b676e-ex1', '3101feb7-f19e-4bc5-b76e-24953c8b676e', 'launch', 'The company will launch a new phone next month.', '该公司下个月将发布新手机。'),
  ('3101feb7-f19e-4bc5-b76e-24953c8b676e-ex2', '3101feb7-f19e-4bc5-b76e-24953c8b676e', 'launch', 'The agency resolved to launch a formal investigation into the pricing practices.', '该机构决定对定价行为启动正式调查。'),
  ('bfa6924c-f382-4267-95ec-f133cd97e47a-ex1', 'bfa6924c-f382-4267-95ec-f133cd97e47a', 'file', 'Save the file before closing the program.', '关闭程序前先保存文件。'),
  ('bfa6924c-f382-4267-95ec-f133cd97e47a-ex2', 'bfa6924c-f382-4267-95ec-f133cd97e47a', 'file', 'The claimants must file their submissions within the period prescribed by the rules.', '索赔人必须在规则规定的期限内提交材料。'),
  ('c76b62dd-3fb4-40ce-95da-806eac3aa3e1-ex1', 'c76b62dd-3fb4-40ce-95da-806eac3aa3e1', 'sick', 'I stayed home because I was sick.', '我生病了所以待在家里。'),
  ('c76b62dd-3fb4-40ce-95da-806eac3aa3e1-ex2', 'c76b62dd-3fb4-40ce-95da-806eac3aa3e1', 'sick', 'The statute guarantees paid sick leave to all workers regardless of contract form.', '该法规保障所有劳动者无论合同形式均享有带薪病假。'),
  ('dc85a558-1c67-43ca-a8c4-8319d8f517d4-ex1', 'dc85a558-1c67-43ca-a8c4-8319d8f517d4', 'outcome', 'We are still waiting for the test outcome.', '我们还在等检查结果。'),
  ('dc85a558-1c67-43ca-a8c4-8319d8f517d4-ex2', 'dc85a558-1c67-43ca-a8c4-8319d8f517d4', 'outcome', 'The outcome of the arbitration will shape investor expectations for a generation.', '这场仲裁的结果将影响一代投资者的预期。'),
  ('4884766f-1ab4-4750-a83c-24d078e19e04-ex1', '4884766f-1ab4-4750-a83c-24d078e19e04', 'ad', 'I saw the job in a newspaper ad.', '我在报纸广告上看到这份工作。'),
  ('4884766f-1ab4-4750-a83c-24d078e19e04-ex2', '4884766f-1ab4-4750-a83c-24d078e19e04', 'ad', 'Political ads must disclose their sponsors under the transparency rules.', '根据透明度规则，政治广告必须披露其出资方。'),
  ('96fd4ed1-206e-4e78-bdda-a8abda2b5f18-ex1', '96fd4ed1-206e-4e78-bdda-a8abda2b5f18', 'defend', 'She defended her little brother.', '她保护了自己的弟弟。'),
  ('96fd4ed1-206e-4e78-bdda-a8abda2b5f18-ex2', '96fd4ed1-206e-4e78-bdda-a8abda2b5f18', 'defend', 'Counsel will defend the legality of the measure before the constitutional court.', '律师将在宪法法院为该措施的合法性辩护。'),
  ('7f4661b7-4bd1-49eb-8a9a-d02fccc7b23a-ex1', '7f4661b7-4bd1-49eb-8a9a-d02fccc7b23a', 'duty', 'It is my duty to take care of my family.', '照顾家人是我的责任。'),
  ('7f4661b7-4bd1-49eb-8a9a-d02fccc7b23a-ex2', '7f4661b7-4bd1-49eb-8a9a-d02fccc7b23a', 'duty', 'Directors owe a fiduciary duty that cannot be contracted away.', '董事负有不可通过约定免除的信义义务。'),
  ('cfc23f38-9ba9-4f9e-8bc0-b8bc70fb818b-ex1', 'cfc23f38-9ba9-4f9e-8bc0-b8bc70fb818b', 'sheet', 'Put clean sheets on the bed.', '给床铺上干净的床单。'),
  ('cfc23f38-9ba9-4f9e-8bc0-b8bc70fb818b-ex2', 'cfc23f38-9ba9-4f9e-8bc0-b8bc70fb818b', 'sheet', 'The balance sheet concealed liabilities routed through unconsolidated entities.', '资产负债表掩盖了通过未并表实体转移的负债。'),
  ('6fd45424-65d0-4b86-9bbb-9da3d195e45d-ex1', '6fd45424-65d0-4b86-9bbb-9da3d195e45d', 'ought', 'You ought to see a doctor.', '你应该去看医生。'),
  ('6fd45424-65d0-4b86-9bbb-9da3d195e45d-ex2', '6fd45424-65d0-4b86-9bbb-9da3d195e45d', 'ought', 'Institutions ought to disclose material risks before soliciting public investment.', '机构在向公众募资之前理应披露重大风险。'),
  ('97ac3ceb-4b6f-42a2-b27d-72459d5e3a15-ex1', '97ac3ceb-4b6f-42a2-b27d-72459d5e3a15', 'ensure', 'Please ensure the door is locked.', '请确保门已锁好。'),
  ('97ac3ceb-4b6f-42a2-b27d-72459d5e3a15-ex2', '97ac3ceb-4b6f-42a2-b27d-72459d5e3a15', 'ensure', 'Procedural safeguards ensure that no party is condemned unheard.', '程序保障确保任何一方都不会未经听审而被定责。'),
  ('1a7f9f67-e595-4491-827c-984aaf51ae51-ex1', '1a7f9f67-e595-4491-827c-984aaf51ae51', 'Catholic', 'She attends a Catholic school.', '她就读于一所天主教学校。'),
  ('1a7f9f67-e595-4491-827c-984aaf51ae51-ex2', '1a7f9f67-e595-4491-827c-984aaf51ae51', 'Catholic', 'The Catholic charities network administers relief programs across the region.', '天主教慈善网络在该地区开展救济项目。'),
  ('1656dcd4-2d1f-456c-86a5-3c96156e3fda-ex1', '1656dcd4-2d1f-456c-86a5-3c96156e3fda', 'extremely', 'The test was extremely difficult.', '这次考试极其困难。'),
  ('1656dcd4-2d1f-456c-86a5-3c96156e3fda-ex2', '1656dcd4-2d1f-456c-86a5-3c96156e3fda', 'extremely', 'The court deemed the conduct extremely serious, warranting exemplary sanctions.', '法院认定该行为情节极其严重，应予惩戒性处罚。'),
  ('151d0eee-11d3-404b-8e69-1f81e695f5b0-ex1', '151d0eee-11d3-404b-8e69-1f81e695f5b0', 'extent', 'I agree with you to some extent.', '在某种程度上我同意你的看法。'),
  ('151d0eee-11d3-404b-8e69-1f81e695f5b0-ex2', '151d0eee-11d3-404b-8e69-1f81e695f5b0', 'extent', 'The full extent of the contamination emerged only after independent sampling.', '污染的全部范围在独立采样之后才显现出来。'),
  ('95f0ee8e-a30c-4885-83b3-c56b8103ecbb-ex1', '95f0ee8e-a30c-4885-83b3-c56b8103ecbb', 'component', 'The machine has a broken component.', '这台机器有个零件坏了。'),
  ('95f0ee8e-a30c-4885-83b3-c56b8103ecbb-ex2', '95f0ee8e-a30c-4885-83b3-c56b8103ecbb', 'component', 'Transparency constitutes an indispensable component of credible governance.', '透明度是可信治理不可或缺的组成部分。'),
  ('fc1f498a-3686-4021-a14f-2d58f7c83a8f-ex1', 'fc1f498a-3686-4021-a14f-2d58f7c83a8f', 'mix', 'Mix the eggs and sugar together.', '把鸡蛋和糖混合在一起。'),
  ('fc1f498a-3686-4021-a14f-2d58f7c83a8f-ex2', 'fc1f498a-3686-4021-a14f-2d58f7c83a8f', 'mix', 'The portfolio''s asset mix was recalibrated toward inflation-protected instruments.', '投资组合的资产配置已向抗通胀工具倾斜。'),
  ('9550edec-4ed3-4f32-bae1-75ee5e52f006-ex1', '9550edec-4ed3-4f32-bae1-75ee5e52f006', 'long-term', 'Exercise has long-term health benefits.', '锻炼对健康有长期益处。'),
  ('9550edec-4ed3-4f32-bae1-75ee5e52f006-ex2', '9550edec-4ed3-4f32-bae1-75ee5e52f006', 'long-term', 'Short electoral cycles systematically disadvantage long-term infrastructure planning.', '短暂的选举周期系统性地不利于长期基础设施规划。'),
  ('69ce6988-612a-400d-a6d5-9e59abaecbf6-ex1', '69ce6988-612a-400d-a6d5-9e59abaecbf6', 'slow', 'The internet is slow tonight.', '今晚网速很慢。'),
  ('69ce6988-612a-400d-a6d5-9e59abaecbf6-ex2', '69ce6988-612a-400d-a6d5-9e59abaecbf6', 'slow', 'Implementation has been slow, hampered by fragmented administrative responsibility.', '实施进展缓慢，受制于行政职责的碎片化。'),
  ('af377b86-1dd3-45b8-94d2-14cbbc694b72-ex1', 'af377b86-1dd3-45b8-94d2-14cbbc694b72', 'contrast', 'The contrast between the two photos is clear.', '这两张照片的对比很明显。'),
  ('af377b86-1dd3-45b8-94d2-14cbbc694b72-ex2', 'af377b86-1dd3-45b8-94d2-14cbbc694b72', 'contrast', 'The audited figures stand in stark contrast to the projections circulated to investors.', '经审计的数字与发给投资者的预测形成鲜明对比。'),
  ('7dbc1bd5-a97a-468b-b04a-8575b82702b8-ex1', '7dbc1bd5-a97a-468b-b04a-8575b82702b8', 'zone', 'This is a no-parking zone.', '这里是禁止停车区。'),
  ('7dbc1bd5-a97a-468b-b04a-8575b82702b8-ex2', '7dbc1bd5-a97a-468b-b04a-8575b82702b8', 'zone', 'The exclusion zone remains in force pending completion of the decontamination.', '在去污工作完成之前，隔离区继续有效。'),
  ('522b28db-329e-41cc-89e5-205e06304c31-ex1', '522b28db-329e-41cc-89e5-205e06304c31', 'wake', 'I wake up at six every morning.', '我每天早上六点醒。'),
  ('522b28db-329e-41cc-89e5-205e06304c31-ex2', '522b28db-329e-41cc-89e5-205e06304c31', 'wake', 'Sweeping reforms followed in the wake of the institutional collapse.', '机构倒闭之后，全面改革接踵而至。'),
  ('f9e8535c-b06d-457a-8b93-c5cd423f72b2-ex1', 'f9e8535c-b06d-457a-8b93-c5cd423f72b2', 'airport', 'We arrived at the airport two hours early.', '我们提前两小时到达机场。'),
  ('f9e8535c-b06d-457a-8b93-c5cd423f72b2-ex2', 'f9e8535c-b06d-457a-8b93-c5cd423f72b2', 'airport', 'The airport expansion was conditioned on binding noise abatement commitments.', '机场扩建以具有约束力的降噪承诺为前提条件。'),
  ('1c6902f8-8a1b-47ea-94c6-aa8c8daf65d2-ex1', '1c6902f8-8a1b-47ea-94c6-aa8c8daf65d2', 'brown', 'She has beautiful brown eyes.', '她有一双美丽的棕色眼睛。'),
  ('1c6902f8-8a1b-47ea-94c6-aa8c8daf65d2-ex2', '1c6902f8-8a1b-47ea-94c6-aa8c8daf65d2', 'brown', 'The remediation plan converts brown industrial land to certified residential use.', '修复计划将工业棕地转为经认证的住宅用地。'),
  ('2be1441a-39dd-4fee-bd2f-50a1e005363b-ex1', '2be1441a-39dd-4fee-bd2f-50a1e005363b', 'shirt', 'He ironed his shirt before the interview.', '面试前他熨好了衬衫。'),
  ('2be1441a-39dd-4fee-bd2f-50a1e005363b-ex2', '2be1441a-39dd-4fee-bd2f-50a1e005363b', 'shirt', 'The investigation traced the counterfeit shirts to unlicensed offshore factories.', '调查将这些假冒衬衫追溯到未经许可的离岸工厂。'),
  ('a5411f40-f184-40ec-90ad-b236991e9b8a-ex1', 'a5411f40-f184-40ec-90ad-b236991e9b8a', 'pilot', 'The pilot landed the plane safely.', '飞行员让飞机安全着陆。'),
  ('a5411f40-f184-40ec-90ad-b236991e9b8a-ex2', 'a5411f40-f184-40ec-90ad-b236991e9b8a', 'pilot', 'The pilot program will inform the design of the nationwide rollout.', '试点项目将为全国推广方案的设计提供依据。'),
  ('00e1e658-bd82-42ad-9d94-bcb8053cd544-ex1', '00e1e658-bd82-42ad-9d94-bcb8053cd544', 'warn', 'I warned you about the icy road.', '我提醒过你路面结冰。'),
  ('00e1e658-bd82-42ad-9d94-bcb8053cd544-ex2', '00e1e658-bd82-42ad-9d94-bcb8053cd544', 'warn', 'Internal memoranda warned of precisely the failure that later materialized.', '内部备忘录所警告的恰恰就是后来发生的那种失灵。'),
  ('859c1130-e9ba-47e7-a43d-083226cc3e7b-ex1', '859c1130-e9ba-47e7-a43d-083226cc3e7b', 'ultimately', 'Ultimately, the choice is yours.', '最终，选择权在你。'),
  ('859c1130-e9ba-47e7-a43d-083226cc3e7b-ex2', '859c1130-e9ba-47e7-a43d-083226cc3e7b', 'ultimately', 'Ultimately, accountability rests with the board rather than delegated committees.', '归根结底，问责的主体是董事会，而非受托的各委员会。'),
  ('9972fe12-1ce4-408e-9c4a-8315bd384bf5-ex1', '9972fe12-1ce4-408e-9c4a-8315bd384bf5', 'cat', 'Our cat sleeps all day long.', '我们家的猫整天睡觉。'),
  ('9972fe12-1ce4-408e-9c4a-8315bd384bf5-ex2', '9972fe12-1ce4-408e-9c4a-8315bd384bf5', 'cat', 'The disclosure let the cat out of the bag regarding the impending restructuring.', '这次披露让即将进行的重组计划走漏了风声。'),
  ('5e755e5d-b19f-4fc7-b02d-96fe90c10940-ex1', '5e755e5d-b19f-4fc7-b02d-96fe90c10940', 'contribution', 'Thank you for your contribution to the team.', '感谢你对团队的贡献。'),
  ('5e755e5d-b19f-4fc7-b02d-96fe90c10940-ex2', '5e755e5d-b19f-4fc7-b02d-96fe90c10940', 'contribution', 'Campaign contributions exceeding the threshold trigger mandatory public disclosure.', '超过限额的竞选捐款必须强制公开披露。'),
  ('79378511-79e5-430b-b2a4-09b0210575c3-ex1', '79378511-79e5-430b-b2a4-09b0210575c3', 'capacity', 'The stadium has a capacity of fifty thousand.', '这座体育场可容纳五万人。'),
  ('79378511-79e5-430b-b2a4-09b0210575c3-ex2', '79378511-79e5-430b-b2a4-09b0210575c3', 'capacity', 'The agency lacks the institutional capacity to administer the expanded mandate.', '该机构缺乏履行扩大职权所需的机构能力。'),
  ('ce428b04-7b5e-4533-82f3-ff2d864e578d-ex1', 'ce428b04-7b5e-4533-82f3-ff2d864e578d', 'ourselves', 'We made the cake ourselves.', '蛋糕是我们自己做的。'),
  ('ce428b04-7b5e-4533-82f3-ff2d864e578d-ex2', 'ce428b04-7b5e-4533-82f3-ff2d864e578d', 'ourselves', 'We must satisfy ourselves that the safeguards operate as designed before certification.', '在认证之前，我们必须确信这些保障措施按设计运作。')
INSERT INTO vocab_examples (id, vocabulary_id, word, sentence_en, sentence_zh) VALUES
  ('af69184d-973c-459e-93d1-17e5288adf86-ex1', 'af69184d-973c-459e-93d1-17e5288adf86', 'estate', 'They live on a large country estate.', '他们住在乡间的一座大庄园里。'),
  ('af69184d-973c-459e-93d1-17e5288adf86-ex2', 'af69184d-973c-459e-93d1-17e5288adf86', 'estate', 'The estate passes under intestacy rules absent a validly executed will.', '如无有效订立的遗嘱，遗产将按无遗嘱继承规则分配。'),
  ('9be431a9-0d3f-4646-afca-c5ae1c753107-ex1', '9be431a9-0d3f-4646-afca-c5ae1c753107', 'guide', 'The guide showed us around the museum.', '导游带我们参观了博物馆。'),
  ('9be431a9-0d3f-4646-afca-c5ae1c753107-ex2', '9be431a9-0d3f-4646-afca-c5ae1c753107', 'guide', 'The sentencing guidelines guide but do not bind judicial discretion.', '量刑指南对法官裁量具有指导性，但不具约束力。'),
  ('a1b09ae8-f9e7-4d9f-af69-37b0aaea8b72-ex1', 'a1b09ae8-f9e7-4d9f-af69-37b0aaea8b72', 'circumstance', 'Under the circumstances, we did our best.', '在这种情况下，我们已经尽力了。'),
  ('a1b09ae8-f9e7-4d9f-af69-37b0aaea8b72-ex2', 'a1b09ae8-f9e7-4d9f-af69-37b0aaea8b72', 'circumstance', 'Mitigating circumstances justified departure from the presumptive sentence.', '减轻情节为偏离基准刑提供了正当理由。'),
  ('c64e8d9f-6395-49db-9941-a4d01d0527d5-ex1', 'c64e8d9f-6395-49db-9941-a4d01d0527d5', 'snow', 'The kids are playing in the snow.', '孩子们在雪地里玩耍。'),
  ('c64e8d9f-6395-49db-9941-a4d01d0527d5-ex2', 'c64e8d9f-6395-49db-9941-a4d01d0527d5', 'snow', 'Diminishing snow cover threatens the water security of downstream populations.', '积雪减少威胁着下游人口的水安全。'),
  ('07fac460-8c5a-4cbd-8476-372425d89b5e-ex1', '07fac460-8c5a-4cbd-8476-372425d89b5e', 'English', 'She speaks English very well.', '她英语说得很好。'),
  ('07fac460-8c5a-4cbd-8476-372425d89b5e-ex2', '07fac460-8c5a-4cbd-8476-372425d89b5e', 'English', 'English serves as the authentic language of the treaty in case of interpretive divergence.', '如出现解释分歧，英语文本为该条约的作准文本。'),
  ('32fa6102-6a32-4f33-805d-cd7360811144-ex1', '32fa6102-6a32-4f33-805d-cd7360811144', 'politician', 'The politician visited our school today.', '那位政界人士今天访问了我们学校。'),
