  ('e13ea333-86cd-4b92-84b1-f23a6a573837-ex1', 'e13ea333-86cd-4b92-84b1-f23a6a573837', 'typical', 'This is a typical autumn day.', '这是典型的秋日。'),
  ('e13ea333-86cd-4b92-84b1-f23a6a573837-ex2', 'e13ea333-86cd-4b92-84b1-f23a6a573837', 'typical', 'The case is typical of disputes arising from ambiguous allocation clauses.', '该案是因分配条款含糊而引发争议的典型。'),
  ('fea04dfc-58ac-4d3b-8938-aab8a5d0ad54-ex1', 'fea04dfc-58ac-4d3b-8938-aab8a5d0ad54', 'except', 'Everyone came except Tom.', '除了汤姆，大家都来了。'),
