  ('eafd398d-f753-4b73-823f-0a4abdd3e160-ex2', 'eafd398d-f753-4b73-823f-0a4abdd3e160', 'rare', 'The fund subsidizes therapies for rare diseases unprofitable to develop commercially.', '该基金资助商业开发无利可图的罕见病疗法。'),
  ('887d61db-6637-495d-98f9-e99c72151351-ex1', '887d61db-6637-495d-98f9-e99c72151351', 'tank', 'The fish tank needs cleaning.', '鱼缸该清洗了。'),
