  ('6aa9c5e3-18ae-458a-a0cb-3e483d330df3-ex1', '6aa9c5e3-18ae-458a-a0cb-3e483d330df3', 'limited', 'Seats are limited, so book early.', '座位有限，请尽早预订。'),
  ('6aa9c5e3-18ae-458a-a0cb-3e483d330df3-ex2', '6aa9c5e3-18ae-458a-a0cb-3e483d330df3', 'limited', 'Liability is limited to losses reasonably foreseeable at contract formation.', '责任范围限于订立合同时可合理预见的损失。'),
  ('55331552-36bc-4341-9eea-c58c0d132fa4-ex1', '55331552-36bc-4341-9eea-c58c0d132fa4', 'proud', 'I am proud of your progress.', '我为你的进步感到骄傲。'),
  ('55331552-36bc-4341-9eea-c58c0d132fa4-ex2', '55331552-36bc-4341-9eea-c58c0d132fa4', 'proud', 'The institution remains proud of a compliance record unmatched in the sector.', '该机构始终以业内无可匹敌的合规记录为荣。'),
  ('514af872-6926-4920-8be3-43a624ac2878-ex1', '514af872-6926-4920-8be3-43a624ac2878', 'flow', 'The river flows through the city.', '这条河流经城市。'),
  ('514af872-6926-4920-8be3-43a624ac2878-ex2', '514af872-6926-4920-8be3-43a624ac2878', 'flow', 'Cross-border data flows are conditioned on adequacy determinations.', '跨境数据流动以充分性认定为前提条件。'),
  ('a8ad4f15-dadc-4e91-b69d-d1e8d347a745-ex1', 'a8ad4f15-dadc-4e91-b69d-d1e8d347a745', 'faculty', 'The faculty meeting is on Friday.', '教师会议在周五举行。'),
  ('a8ad4f15-dadc-4e91-b69d-d1e8d347a745-ex2', 'a8ad4f15-dadc-4e91-b69d-d1e8d347a745', 'faculty', 'The faculty senate censured the administration for bypassing shared governance.', '教授评议会谴责校方绕过共同治理机制。'),
  ('21a42d3c-76b1-47c5-b366-f77f91360769-ex1', '21a42d3c-76b1-47c5-b366-f77f91360769', 'increased', 'There is increased interest in the course.', '这门课程受到越来越多的关注。'),
  ('21a42d3c-76b1-47c5-b366-f77f91360769-ex2', '21a42d3c-76b1-47c5-b366-f77f91360769', 'increased', 'Increased capital requirements apply to institutions exceeding the systemic threshold.', '超过系统性门槛的机构适用更高的资本要求。'),
  ('cd85ad3c-4320-4507-bac4-2715d2c38d0a-ex1', 'cd85ad3c-4320-4507-bac4-2715d2c38d0a', 'waste', 'Don''t waste food.', '不要浪费食物。'),
  ('cd85ad3c-4320-4507-bac4-2715d2c38d0a-ex2', 'cd85ad3c-4320-4507-bac4-2715d2c38d0a', 'waste', 'The directive regulates the transboundary shipment of hazardous waste.', '该指令规范危险废物的跨境转移。'),
  ('794a6ee1-b15b-47f4-bf82-04b83e5427c6-ex1', '794a6ee1-b15b-47f4-bf82-04b83e5427c6', 'merely', 'It was merely a suggestion.', '那只是个建议。'),
  ('794a6ee1-b15b-47f4-bf82-04b83e5427c6-ex2', '794a6ee1-b15b-47f4-bf82-04b83e5427c6', 'merely', 'The certification was merely formal, unsupported by substantive verification.', '这一认证仅具形式，缺乏实质性核查支持。'),
  ('733c8c10-4eaa-4a36-b70c-8cf4c6824785-ex1', '733c8c10-4eaa-4a36-b70c-8cf4c6824785', 'mass', 'The mass of the box is two kilograms.', '这个箱子的质量是两公斤。'),
  ('733c8c10-4eaa-4a36-b70c-8cf4c6824785-ex2', '733c8c10-4eaa-4a36-b70c-8cf4c6824785', 'mass', 'The statute restricts mass surveillance absent individualized judicial warrant.', '该法规限制未经个案司法令状的大规模监控。'),
  ('489e49a0-e91b-4d12-b472-005a615958fb-ex1', '489e49a0-e91b-4d12-b472-005a615958fb', 'emphasize', 'The teacher emphasized the main points.', '老师强调了要点。'),
  ('489e49a0-e91b-4d12-b472-005a615958fb-ex2', '489e49a0-e91b-4d12-b472-005a615958fb', 'emphasize', 'The guidelines emphasize proportionality in the exercise of enforcement discretion.', '该指南强调执法裁量权行使中的相称性。'),
  ('59fc4357-9712-4c9a-a169-fe8393ad5332-ex1', '59fc4357-9712-4c9a-a169-fe8393ad5332', 'experiment', 'We did a fun experiment in science class.', '我们在科学课上做了一个有趣的实验。'),
  ('59fc4357-9712-4c9a-a169-fe8393ad5332-ex2', '59fc4357-9712-4c9a-a169-fe8393ad5332', 'experiment', 'The natural experiment afforded by the policy divergence enabled causal identification.', '政策分化提供的自然实验使因果识别成为可能。'),
  ('88e6ea7f-6ea5-44ef-a075-61b079a9f7a7-ex1', '88e6ea7f-6ea5-44ef-a075-61b079a9f7a7', 'definitely', 'I will definitely come to your party.', '我一定会来参加你的聚会。'),
  ('88e6ea7f-6ea5-44ef-a075-61b079a9f7a7-ex2', '88e6ea7f-6ea5-44ef-a075-61b079a9f7a7', 'definitely', 'The records definitely establish contemporaneous knowledge of the defect.', '这些记录确凿地证明当时已知晓该缺陷。'),
  ('fd6fbe94-fab1-4913-86a8-bb6256bf5531-ex1', 'fd6fbe94-fab1-4913-86a8-bb6256bf5531', 'bomb', 'The old bomb was safely removed.', '那枚旧炸弹被安全拆除了。'),
  ('fd6fbe94-fab1-4913-86a8-bb6256bf5531-ex2', 'fd6fbe94-fab1-4913-86a8-bb6256bf5531', 'bomb', 'The disclosures landed like a bomb in the middle of the ratification debate.', '这些披露犹如一颗炸弹，在批准辩论中引发轩然大波。'),
  ('ea8e5d63-7d3a-4ccc-aab0-3749f7054447-ex1', 'ea8e5d63-7d3a-4ccc-aab0-3749f7054447', 'enormous', 'The elephant is an enormous animal.', '大象是一种巨大的动物。'),
  ('ea8e5d63-7d3a-4ccc-aab0-3749f7054447-ex2', 'ea8e5d63-7d3a-4ccc-aab0-3749f7054447', 'enormous', 'The settlement imposes enormous remediation obligations on the operator.', '和解协议给运营方施加了巨大的修复义务。'),
  ('0b6224bc-eadf-42a1-a273-e00caa6d5415-ex1', '0b6224bc-eadf-42a1-a273-e00caa6d5415', 'tone', 'I didn''t like his tone of voice.', '我不喜欢他说话的语气。'),
  ('0b6224bc-eadf-42a1-a273-e00caa6d5415-ex2', '0b6224bc-eadf-42a1-a273-e00caa6d5415', 'tone', 'The central bank''s communications set the tone for global risk appetite.', '央行的言论为全球风险偏好定下了基调。'),
  ('5f7df965-21de-4a0e-b5d9-9bca962f291e-ex1', '5f7df965-21de-4a0e-b5d9-9bca962f291e', 'liberal', 'She has liberal views on most issues.', '她在大多数问题上持开明观点。'),
  ('5f7df965-21de-4a0e-b5d9-9bca962f291e-ex2', '5f7df965-21de-4a0e-b5d9-9bca962f291e', 'liberal', 'The liberal trading order faces challenges from resurgent economic nationalism.', '自由贸易秩序正面临经济民族主义复兴的挑战。'),
  ('48a6cbd4-5354-4afd-bd2a-dbc2c1e5dd4c-ex1', '48a6cbd4-5354-4afd-bd2a-dbc2c1e5dd4c', 'massive', 'The new stadium is massive.', '新体育场非常宏伟。'),
  ('48a6cbd4-5354-4afd-bd2a-dbc2c1e5dd4c-ex2', '48a6cbd4-5354-4afd-bd2a-dbc2c1e5dd4c', 'massive', 'The breach triggered massive coordinated notification obligations across jurisdictions.', '这次泄露在各司法管辖区触发了大规模协同通报义务。'),
  ('de4af3f2-66e0-4910-8ab2-1bb67454b9d6-ex1', 'de4af3f2-66e0-4910-8ab2-1bb67454b9d6', 'engineer', 'My sister is a software engineer.', '我姐姐是软件工程师。'),
  ('de4af3f2-66e0-4910-8ab2-1bb67454b9d6-ex2', 'de4af3f2-66e0-4910-8ab2-1bb67454b9d6', 'engineer', 'The certifying engineer bears personal liability for the structural attestations.', '出具认证的工程师对结构鉴定承担个人责任。'),
  ('fff2d899-c42f-44a0-9d29-198ea257bc29-ex1', 'fff2d899-c42f-44a0-9d29-198ea257bc29', 'wheel', 'The front wheel of my bike is flat.', '我自行车的前轮没气了。'),
  ('fff2d899-c42f-44a0-9d29-198ea257bc29-ex2', 'fff2d899-c42f-44a0-9d29-198ea257bc29', 'wheel', 'Institutional reform turns like a heavy wheel, slowly yet with great momentum.', '机构改革如同沉重的巨轮，转动缓慢却势不可挡。'),
  ('70ec8a00-22c2-4079-9e54-086b3d3e69ac-ex1', '70ec8a00-22c2-4079-9e54-086b3d3e69ac', 'decline', 'Prices declined slightly this month.', '本月价格略有下降。'),
  ('70ec8a00-22c2-4079-9e54-086b3d3e69ac-ex2', '70ec8a00-22c2-4079-9e54-086b3d3e69ac', 'decline', 'The court may decline jurisdiction where a more appropriate forum exists.', '如存在更适宜的管辖法院，法院可拒绝行使管辖权。'),
  ('736c2dc5-99e0-4239-a65a-b993bc3a34d8-ex1', '736c2dc5-99e0-4239-a65a-b993bc3a34d8', 'invest', 'They invested their savings in a house.', '他们把积蓄投资买了房子。'),
  ('736c2dc5-99e0-4239-a65a-b993bc3a34d8-ex2', '736c2dc5-99e0-4239-a65a-b993bc3a34d8', 'invest', 'Fiduciaries may invest only in instruments authorized by the governing statute.', '受托人只能投资于准据法规授权的工具。'),
  ('b2cb9b58-ce69-4d07-bf94-d6aa5d571545-ex1', 'b2cb9b58-ce69-4d07-bf94-d6aa5d571545', 'cable', 'The TV cable is loose.', '电视线松了。'),
  ('b2cb9b58-ce69-4d07-bf94-d6aa5d571545-ex2', 'b2cb9b58-ce69-4d07-bf94-d6aa5d571545', 'cable', 'The undersea cable network constitutes critical infrastructure under the directive.', '根据该指令，海底电缆网络属于关键基础设施。'),
  ('96c37fab-c031-477d-ac83-ccbd11b38f0c-ex1', '96c37fab-c031-477d-ac83-ccbd11b38f0c', 'towards', 'She walked towards the station.', '她朝车站走去。'),
  ('96c37fab-c031-477d-ac83-ccbd11b38f0c-ex2', '96c37fab-c031-477d-ac83-ccbd11b38f0c', 'towards', 'The settlement marks a significant step towards comprehensive restitution.', '这一和解是迈向全面赔偿的重要一步。'),
  ('6167284a-25b1-437f-b31f-e50b340498d6-ex1', '6167284a-25b1-437f-b31f-e50b340498d6', 'expose', 'Don''t expose the film to light.', '不要让胶卷见光。'),
  ('6167284a-25b1-437f-b31f-e50b340498d6-ex2', '6167284a-25b1-437f-b31f-e50b340498d6', 'expose', 'The audit exposed liabilities concealed through off-balance-sheet structures.', '审计揭露了通过表外结构隐藏的负债。'),
  ('43626830-d543-4d7b-8cc8-58a7474686df-ex1', '43626830-d543-4d7b-8cc8-58a7474686df', 'rural', 'They moved to a rural area last year.', '他们去年搬到了乡村地区。'),
  ('43626830-d543-4d7b-8cc8-58a7474686df-ex2', '43626830-d543-4d7b-8cc8-58a7474686df', 'rural', 'The program channels concessional credit toward chronically underserved rural districts.', '该计划将优惠信贷引向长期服务不足的农村地区。'),
  ('e614c08c-7dff-4c93-896b-1da74f20fd4f-ex1', 'e614c08c-7dff-4c93-896b-1da74f20fd4f', 'AIDS', 'AIDS awareness campaigns save lives.', '艾滋病宣传活动拯救生命。'),
  ('e614c08c-7dff-4c93-896b-1da74f20fd4f-ex2', 'e614c08c-7dff-4c93-896b-1da74f20fd4f', 'AIDS', 'The global AIDS response demonstrated what coordinated financing can achieve.', '全球艾滋病防治行动证明了协同融资所能取得的成就。'),
  ('1783aace-8650-4d1a-a61b-40ca4873605f-ex1', '1783aace-8650-4d1a-a61b-40ca4873605f', 'Jew', 'He is a Jew who grew up in New York.', '他是在纽约长大的犹太人。'),
  ('1783aace-8650-4d1a-a61b-40ca4873605f-ex2', '1783aace-8650-4d1a-a61b-40ca4873605f', 'Jew', 'The memorial honors every Jew deported from the occupied territories.', '纪念碑悼念从被占领土被驱逐的每一位犹太人。'),
  ('fee7e118-f6ae-45df-b67e-b07acbe46697-ex1', 'fee7e118-f6ae-45df-b67e-b07acbe46697', 'narrow', 'The street is too narrow for trucks.', '这条街太窄，卡车过不去。'),
  ('fee7e118-f6ae-45df-b67e-b07acbe46697-ex2', 'fee7e118-f6ae-45df-b67e-b07acbe46697', 'narrow', 'The court adopted a narrow construction confining the precedent to its facts.', '法院采取狭义解释，将该先例限定于其特定事实。'),
  ('fbcfc03a-3964-4124-979b-41d3b49b9d97-ex1', 'fbcfc03a-3964-4124-979b-41d3b49b9d97', 'cream', 'Would you like cream in your coffee?', '你的咖啡要加奶油吗？'),
  ('fbcfc03a-3964-4124-979b-41d3b49b9d97-ex2', 'fbcfc03a-3964-4124-979b-41d3b49b9d97', 'cream', 'The labeling rules distinguish dairy cream from synthetic substitutes.', '标签规则区分乳制奶油与人工替代品。'),
  ('547b65fe-f9ea-4c95-beea-50c0c13726e8-ex1', '547b65fe-f9ea-4c95-beea-50c0c13726e8', 'secretary', 'The secretary scheduled the meeting.', '秘书安排了会议。'),
  ('547b65fe-f9ea-4c95-beea-50c0c13726e8-ex2', '547b65fe-f9ea-4c95-beea-50c0c13726e8', 'secretary', 'The secretary of state certified the election results despite partisan objections.', '尽管存在党派异议，州务卿仍认证了选举结果。'),
  ('daa80b8d-24c4-4e47-8f3b-2919d5d5228f-ex1', 'daa80b8d-24c4-4e47-8f3b-2919d5d5228f', 'gate', 'Close the gate behind you.', '随手关上大门。'),
  ('daa80b8d-24c4-4e47-8f3b-2919d5d5228f-ex2', 'daa80b8d-24c4-4e47-8f3b-2919d5d5228f', 'gate', 'The boarding gate assignments were reorganized under the new security protocol.', '根据新的安检规程，登机口分配进行了调整。')
INSERT INTO vocab_examples (id, vocabulary_id, word, sentence_en, sentence_zh) VALUES
  ('ad26029c-6b1f-4418-ba1a-c893b704776f-ex1', 'ad26029c-6b1f-4418-ba1a-c893b704776f', 'solid', 'The table is made of solid wood.', '这张桌子是实木做的。'),
  ('ad26029c-6b1f-4418-ba1a-c893b704776f-ex2', 'ad26029c-6b1f-4418-ba1a-c893b704776f', 'solid', 'The conviction rests on solid documentary evidence rather than testimony alone.', '该定罪建立在扎实的书面证据之上，而非仅凭证词。'),
  ('9772849c-55f6-49a3-9916-317162bd1139-ex1', '9772849c-55f6-49a3-9916-317162bd1139', 'hill', 'Our school is on a small hill.', '我们学校在一座小山上。'),
  ('9772849c-55f6-49a3-9916-317162bd1139-ex2', '9772849c-55f6-49a3-9916-317162bd1139', 'hill', 'The legislation faces an uphill battle on the hill amid entrenched opposition.', '面对根深蒂固的反对，该立法在国会山面临一场苦战。'),
  ('54cc8000-bf92-43ac-9cf8-e223fa51dbb9-ex1', '54cc8000-bf92-43ac-9cf8-e223fa51dbb9', 'typically', 'I typically wake up at six.', '我通常六点起床。'),
  ('54cc8000-bf92-43ac-9cf8-e223fa51dbb9-ex2', '54cc8000-bf92-43ac-9cf8-e223fa51dbb9', 'typically', 'Such disputes typically resolve through arbitration before reaching the courts.', '此类争端通常在诉至法院之前就通过仲裁解决。'),
  ('7f11c89d-a2fb-4de0-a1c8-9175ff75150f-ex1', '7f11c89d-a2fb-4de0-a1c8-9175ff75150f', 'noise', 'The noise outside kept me awake.', '外面的噪音让我睡不着。'),
  ('7f11c89d-a2fb-4de0-a1c8-9175ff75150f-ex2', '7f11c89d-a2fb-4de0-a1c8-9175ff75150f', 'noise', 'Analysts must distinguish meaningful signals from statistical noise.', '分析人士必须把有意义的信号与统计噪声区分开来。'),
  ('7957b6c5-0b88-4706-94a8-358ee157a73f-ex1', '7957b6c5-0b88-4706-94a8-358ee157a73f', 'grass', 'Don''t walk on the grass.', '请勿践踏草坪。'),
  ('7957b6c5-0b88-4706-94a8-358ee157a73f-ex2', '7957b6c5-0b88-4706-94a8-358ee157a73f', 'grass', 'The grass-roots campaign compelled the legislature to revisit the exemption.', '这场草根运动迫使立法机构重新审议该豁免条款。'),
  ('5c9b1589-a3c3-4f81-a697-8233883f234e-ex1', '5c9b1589-a3c3-4f81-a697-8233883f234e', 'unfortunately', 'Unfortunately, the tickets are sold out.', '很遗憾，票已售罄。'),
  ('5c9b1589-a3c3-4f81-a697-8233883f234e-ex2', '5c9b1589-a3c3-4f81-a697-8233883f234e', 'unfortunately', 'Unfortunately, the remedial measures arrived long after the damage had crystallized.', '遗憾的是，补救措施出台时损害早已成定局。'),
  ('d1c1139b-c2be-4517-a825-684205a4afa8-ex1', 'd1c1139b-c2be-4517-a825-684205a4afa8', 'hat', 'Wear a hat in the strong sun.', '太阳大要戴帽子。'),
  ('d1c1139b-c2be-4517-a825-684205a4afa8-ex2', 'd1c1139b-c2be-4517-a825-684205a4afa8', 'hat', 'The chairman wears two hats, a duality the governance code expressly discourages.', '董事长身兼两职，而治理准则明确不鼓励这种双重身份。'),
  ('2281a4fb-186c-4a31-87e6-54b6736b137c-ex1', '2281a4fb-186c-4a31-87e6-54b6736b137c', 'legislation', 'The new legislation protects workers.', '新立法保护劳动者。'),
  ('2281a4fb-186c-4a31-87e6-54b6736b137c-ex2', '2281a4fb-186c-4a31-87e6-54b6736b137c', 'legislation', 'Implementing legislation must be enacted before the treaty acquires domestic effect.', '必须先制定实施立法，条约才能在国内生效。'),
  ('0e9e4d07-cdc1-40d8-b8cd-ae861f491bc1-ex1', '0e9e4d07-cdc1-40d8-b8cd-ae861f491bc1', 'succeed', 'I believe you will succeed.', '我相信你会成功的。'),
  ('0e9e4d07-cdc1-40d8-b8cd-ae861f491bc1-ex2', '0e9e4d07-cdc1-40d8-b8cd-ae861f491bc1', 'succeed', 'Reforms rarely succeed without sustained commitment across electoral cycles.', '没有跨越选举周期的持续投入，改革很少能够成功。'),
  ('76c2216b-8921-4e02-9570-e5d2121bd23a-ex1', '76c2216b-8921-4e02-9570-e5d2121bd23a', 'celebrate', 'We celebrated her birthday with a cake.', '我们用蛋糕庆祝了她的生日。'),
  ('76c2216b-8921-4e02-9570-e5d2121bd23a-ex2', '76c2216b-8921-4e02-9570-e5d2121bd23a', 'celebrate', 'The assembly convened to celebrate the convention''s fiftieth anniversary.', '大会召开会议，纪念公约缔结五十周年。'),
  ('38d0a4cd-0a95-4b22-a911-cbc64fe9e846-ex1', '38d0a4cd-0a95-4b22-a911-cbc64fe9e846', 'achievement', 'Winning the prize was a great achievement.', '获奖是一项了不起的成就。'),
  ('38d0a4cd-0a95-4b22-a911-cbc64fe9e846-ex2', '38d0a4cd-0a95-4b22-a911-cbc64fe9e846', 'achievement', 'The accord stands as the signal achievement of a decade of multilateral diplomacy.', '该协定是十年多边外交最显著的成就。'),
  ('54ddca76-8ced-4587-bb16-a87a4b3e9a4d-ex1', '54ddca76-8ced-4587-bb16-a87a4b3e9a4d', 'fishing', 'We went fishing at the lake.', '我们去湖边钓鱼了。'),
