  ('53e6fca5-d933-4a7d-83db-396ecd4e2def-ex1', '53e6fca5-d933-4a7d-83db-396ecd4e2def', 'childhood', 'I spent my childhood in the countryside.', '我的童年是在乡村度过的。'),
